    # ─── Anxiety subtypes (10) ───
    {"id":"mh-x-01","domain":"Mental Health","lang":"en","topic":"Generalised Anxiety Disorder (GAD)",
     "source":"DSM-5 · NIMHANS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"GAD is excessive, hard-to-control worry across multiple life domains lasting 6+ months. Physical signs: muscle tension, fatigue, sleep disturbance, irritability, restlessness. First-line treatment: CBT + SSRI/SNRI. Self-help: structured worry time, sleep hygiene, reduced caffeine."},
    {"id":"mh-x-02","domain":"Mental Health","lang":"en","topic":"Panic Disorder",
     "source":"DSM-5 · APA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Recurrent unexpected panic attacks plus a month of worry about the next attack or behaviour changes to avoid them. Differs from a one-off panic attack. Treatment: CBT with interoceptive exposure, SSRIs. Avoid long-term benzodiazepines."},
    {"id":"mh-x-03","domain":"Mental Health","lang":"en","topic":"Agoraphobia",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Fear of situations where escape feels difficult — public transport, open/enclosed spaces, crowds, being outside home alone. Two or more such situations are actively avoided. Often follows panic disorder. Exposure therapy is the evidence-based path."},
    {"id":"mh-x-04","domain":"Mental Health","lang":"en","topic":"Specific phobias",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Marked fear of a specific object/situation (heights, blood, injection, animals, flying) that's persistent (6+ months) and out of proportion. Treatment: exposure therapy is highly effective; medication is rarely needed."},
    {"id":"mh-x-05","domain":"Mental Health","lang":"en","topic":"Post-Traumatic Stress Disorder (PTSD)",
     "source":"DSM-5 · NCMH guidelines","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"After exposure to actual/threatened death, injury, or sexual violence: intrusion (flashbacks, nightmares), avoidance, negative mood/cognition changes, hyperarousal — lasting 1+ month. Trauma-focused CBT and EMDR are first-line. SSRIs may help."},
    {"id":"mh-x-06","domain":"Mental Health","lang":"en","topic":"Complex PTSD (C-PTSD)",
     "source":"ICD-11 · ISTSS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"PTSD plus disturbances in self-organisation: emotion regulation difficulty, negative self-concept, interpersonal disturbance. Usually follows prolonged trauma (childhood abuse, captivity, trafficking). Phase-based treatment: stabilisation → trauma processing → integration."},
    {"id":"mh-x-07","domain":"Mental Health","lang":"en","topic":"Acute Stress Disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Trauma-response symptoms appearing 3 days to 1 month after a traumatic event. Becomes PTSD if it persists past a month. Early CBT can reduce risk of progression to PTSD."},
    {"id":"mh-x-08","domain":"Mental Health","lang":"en","topic":"Adjustment Disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Emotional/behavioural symptoms developing within 3 months of an identifiable life stressor (job loss, divorce, diagnosis). Resolves within 6 months once stressor ends. Short-term therapy + problem-solving usually sufficient."},
    {"id":"mh-x-09","domain":"Mental Health","lang":"en","topic":"Health anxiety / illness anxiety disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Persistent preoccupation with having or acquiring a serious illness despite minimal/no somatic symptoms. Excessive health-checking or avoidance of medical care. CBT focused on reassurance-seeking reduction is effective."},
    {"id":"mh-x-10","domain":"Mental Health","lang":"en","topic":"Separation anxiety in adults",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Not just childhood — adult separation anxiety affects ~7% of adults. Excessive fear about separation from attachment figures (partner, parent, child). Often comorbid with panic disorder. CBT + supportive partner involvement helps."},

    # ─── Mood disorders (12) ───
    {"id":"mh-x-11","domain":"Mental Health","lang":"en","topic":"Bipolar I disorder",
     "source":"DSM-5 · NIMHANS bipolar clinic protocols","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"At least one manic episode (1 week of elevated/irritable mood with grandiosity, decreased sleep need, racing thoughts, risky behaviour). Depressive episodes common but not required for diagnosis. Mood stabilisers (lithium, valproate) are first-line; psychotherapy improves adherence."},
    {"id":"mh-x-12","domain":"Mental Health","lang":"en","topic":"Bipolar II disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"At least one hypomanic episode (4+ days, less severe than mania, no psychosis/hospitalisation) plus one major depressive episode. Often misdiagnosed as unipolar depression — antidepressants alone can trigger hypomania. Mood stabilisers + cautious antidepressants."},
    {"id":"mh-x-13","domain":"Mental Health","lang":"en","topic":"Cyclothymia",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Chronic mood fluctuations (2+ years) with periods of hypomanic and depressive symptoms that don't meet full episode criteria. ~15-50% progress to bipolar I/II. Mood stabilisers and lifestyle regularity help."},
    {"id":"mh-x-14","domain":"Mental Health","lang":"en","topic":"Persistent depressive disorder (dysthymia)",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Chronic low mood for 2+ years (1 year in children/adolescents) with at least two associated symptoms. Less severe but longer than major depression. CBT + SSRI combination shows best outcomes."},
    {"id":"mh-x-15","domain":"Mental Health","lang":"en","topic":"Seasonal Affective Disorder (SAD)",
     "source":"DSM-5 specifier · NIH","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Major depressive episodes with seasonal pattern, usually winter onset. Light therapy (10,000 lux, 30 min morning) is first-line, often as effective as SSRIs. Vitamin D supplementation supports but doesn't replace treatment."},
    {"id":"mh-x-16","domain":"Mental Health","lang":"en","topic":"Premenstrual Dysphoric Disorder (PMDD)",
     "source":"DSM-5 · ACOG","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Severe mood, anxiety, and physical symptoms in the week before menses, resolving within days of onset. Distinct from regular PMS. SSRIs (continuous or luteal-phase only), CBT, and combined oral contraceptives are evidence-based options."},
    {"id":"mh-x-17","domain":"Mental Health","lang":"en","topic":"Treatment-resistant depression",
     "source":"APA · STAR*D trial","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Failure to respond to 2+ adequate trials of different antidepressants. Options: augmentation (lithium, atypical antipsychotic, thyroid), switching class, ECT, ketamine/esketamine, rTMS. NIMHANS and major Indian hospitals now offer rTMS."},
    {"id":"mh-x-18","domain":"Mental Health","lang":"en","topic":"Postpartum depression deep dive",
     "source":"DSM-5 peripartum specifier · ICMR","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Onset during pregnancy or within 4 weeks postpartum. Affects ~22% of Indian mothers. Risk factors: prior depression, low social support, traumatic birth, infant health issues. Screening: Edinburgh Postnatal Depression Scale (EPDS). Treatment safe in breastfeeding: sertraline, paroxetine."},
    {"id":"mh-x-19","domain":"Mental Health","lang":"en","topic":"Postpartum psychosis",
     "source":"RCOG · NICE","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Rare (1-2 per 1000 births) but a psychiatric emergency. Onset usually within 2 weeks postpartum: severe mood changes, confusion, hallucinations, delusions. Hospitalisation, antipsychotics, mood stabilisers. High recurrence risk in subsequent pregnancies."},
    {"id":"mh-x-20","domain":"Mental Health","lang":"en","topic":"Atypical depression",
     "source":"DSM-5 atypical features specifier","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Depression with mood reactivity (mood lifts to positive events) plus increased appetite, hypersomnia, leaden paralysis, rejection sensitivity. MAOIs historically work better than tricyclics; SSRIs are first-line now."},
    {"id":"mh-x-21","domain":"Mental Health","lang":"en","topic":"Melancholic depression",
     "source":"DSM-5 melancholic features specifier","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Severe depression with loss of pleasure in all activities, lack of mood reactivity, early morning waking, marked psychomotor slowing, weight loss. Responds well to tricyclics and ECT."},
    {"id":"mh-x-22","domain":"Mental Health","lang":"en","topic":"Disruptive Mood Dysregulation Disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Children/adolescents (6-18) with severe, recurrent temper outbursts (3+/week) plus persistent irritable mood between outbursts. Distinct from bipolar disorder. Parent training + CBT; medication adjunctive."},

    # ─── Eating disorders (8) ───
    {"id":"mh-x-23","domain":"Mental Health","lang":"en","topic":"Anorexia nervosa",
     "source":"DSM-5 · NIMHANS eating disorders clinic","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Restriction of energy intake leading to significantly low body weight, intense fear of weight gain, body image disturbance. Restricting subtype vs binge-eating/purging subtype. Medical complications (cardiac, bone) can be fatal. Family-Based Treatment (FBT) is first-line for adolescents."},
    {"id":"mh-x-24","domain":"Mental Health","lang":"en","topic":"Bulimia nervosa",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Recurrent binge eating + compensatory behaviours (purging, fasting, excessive exercise) occurring 1+ times/week for 3+ months, with self-evaluation overly tied to body shape/weight. CBT-E is gold standard; fluoxetine 60 mg has evidence."},
    {"id":"mh-x-25","domain":"Mental Health","lang":"en","topic":"Binge eating disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Recurrent binge eating without compensatory behaviours, occurring weekly for 3+ months. Marked distress about bingeing. Most common eating disorder. CBT, IPT, and topiramate are evidence-based; lisdexamfetamine FDA-approved."},
    {"id":"mh-x-26","domain":"Mental Health","lang":"en","topic":"Avoidant/Restrictive Food Intake Disorder (ARFID)",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Disturbance in eating manifested as significant weight loss, nutritional deficiency, dependence on supplements, or psychosocial interference — without body image concerns. Often sensory-based or trauma-related (choking incident). Treatment: CBT-AR, family approach for children."},
    {"id":"mh-x-27","domain":"Mental Health","lang":"en","topic":"Body Dysmorphic Disorder",
     "source":"DSM-5 (OCD-related disorders)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Preoccupation with one or more perceived defects in appearance not observable to others. Repetitive behaviours (mirror checking, comparing). Often seeks cosmetic procedures unsuccessfully. ERP-based CBT + SSRIs (often high-dose)."},
    {"id":"mh-x-28","domain":"Mental Health","lang":"en","topic":"Orthorexia",
     "source":"Not in DSM-5 · clinical literature","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Obsessive focus on 'healthy' or 'clean' eating, often progressing to malnutrition and social isolation. Not a formal DSM-5 diagnosis but increasingly recognised. Treatment overlaps with anorexia/OCD approaches."},
    {"id":"mh-x-29","domain":"Mental Health","lang":"en","topic":"Pica",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Persistent eating of non-nutritive, non-food substances (clay, hair, paper, paint chips) for 1+ month. Common during pregnancy and in children with developmental disability. Rule out iron/zinc deficiency. Behavioural intervention; treat any nutritional deficits."},
    {"id":"mh-x-30","domain":"Mental Health","lang":"en","topic":"Rumination disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Repeated regurgitation of food (re-chewed, re-swallowed, or spit out) over 1+ month, not due to GI condition. Diaphragmatic breathing exercises are first-line in adolescents and adults."},

    # ─── Personality disorders (10) ───
    {"id":"mh-x-31","domain":"Mental Health","lang":"en","topic":"Borderline Personality Disorder (BPD)",
     "source":"DSM-5 Cluster B","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pattern of unstable relationships, self-image, and affects, with marked impulsivity. Frantic efforts to avoid abandonment, self-harm/suicidal behaviour, chronic emptiness. DBT is gold-standard; MBT and TFP also evidence-based. Medications adjunctive only."},
    {"id":"mh-x-32","domain":"Mental Health","lang":"en","topic":"Narcissistic Personality Disorder",
     "source":"DSM-5 Cluster B","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Grandiosity, need for admiration, lack of empathy. Two subtypes: grandiose (overt) and vulnerable (covert, more depressive/anxious). Engagement in treatment is the main challenge. Schema therapy and TFP have some evidence."},
    {"id":"mh-x-33","domain":"Mental Health","lang":"en","topic":"Antisocial Personality Disorder",
     "source":"DSM-5 Cluster B","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pervasive disregard for and violation of others' rights since age 15 (with conduct disorder evidence before). Deceit, impulsivity, aggression, irresponsibility, lack of remorse. Often comorbid with substance use. No established psychiatric medication."},
    {"id":"mh-x-34","domain":"Mental Health","lang":"en","topic":"Paranoid Personality Disorder",
     "source":"DSM-5 Cluster A","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pervasive distrust and suspiciousness of others, interpreting motives as malevolent. Holds grudges, perceives attacks on character. Distinct from psychotic disorders. Builds slowly via trust-based CBT."},
    {"id":"mh-x-35","domain":"Mental Health","lang":"en","topic":"Schizoid Personality Disorder",
     "source":"DSM-5 Cluster A","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Detachment from social relationships, restricted range of emotional expression. Prefers solitary activities, indifferent to praise/criticism. Distinct from autism spectrum (no social communication deficit core). Often doesn't seek treatment."},
    {"id":"mh-x-36","domain":"Mental Health","lang":"en","topic":"Schizotypal Personality Disorder",
     "source":"DSM-5 Cluster A","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Acute discomfort with close relationships, cognitive/perceptual distortions, eccentric behaviour. Magical thinking, odd speech, paranoid ideation. Considered on the schizophrenia spectrum. Low-dose antipsychotics may help."},
    {"id":"mh-x-37","domain":"Mental Health","lang":"en","topic":"Histrionic Personality Disorder",
     "source":"DSM-5 Cluster B","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Excessive emotionality and attention-seeking. Uncomfortable when not centre of attention, theatrical, easily influenced, considers relationships more intimate than they are. Limited high-quality treatment evidence; psychodynamic therapy explored."},
    {"id":"mh-x-38","domain":"Mental Health","lang":"en","topic":"Avoidant Personality Disorder",
     "source":"DSM-5 Cluster C","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Social inhibition, feelings of inadequacy, hypersensitivity to negative evaluation. Distinct from social anxiety in pervasiveness across all relationships. CBT, schema therapy, SSRIs all have evidence."},
    {"id":"mh-x-39","domain":"Mental Health","lang":"en","topic":"Dependent Personality Disorder",
     "source":"DSM-5 Cluster C","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pervasive need to be taken care of, leading to submissive/clinging behaviour and fears of separation. Difficulty making everyday decisions, going to lengths to obtain nurturance. CBT focused on assertiveness and tolerance of being alone."},
    {"id":"mh-x-40","domain":"Mental Health","lang":"en","topic":"Obsessive-Compulsive Personality Disorder (OCPD)",
     "source":"DSM-5 Cluster C","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Preoccupation with orderliness, perfectionism, and control — at expense of flexibility and efficiency. Distinct from OCD (no true obsessions/compulsions; ego-syntonic vs ego-dystonic). CBT works once insight develops."},

    # ─── Psychotic & related (5) ───
    {"id":"mh-x-41","domain":"Mental Health","lang":"en","topic":"Schizophrenia",
     "source":"DSM-5 · NIMHANS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Two or more of: delusions, hallucinations, disorganised speech, grossly disorganised behaviour, negative symptoms — for 1+ month with continuous signs 6+ months. Antipsychotics + family psychoeducation + supported employment. India's lifetime prevalence ~0.3%."},
    {"id":"mh-x-42","domain":"Mental Health","lang":"en","topic":"Schizoaffective disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Major mood episode concurrent with schizophrenia symptoms, plus 2+ weeks of psychotic symptoms without mood episode. Bipolar or depressive subtypes. Treatment combines antipsychotics + mood stabilisers/antidepressants."},
    {"id":"mh-x-43","domain":"Mental Health","lang":"en","topic":"Brief psychotic disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Sudden onset of psychotic symptoms lasting 1+ day but less than 1 month, with full return to premorbid functioning. May be triggered by major stressor or postpartum. Short antipsychotic course often sufficient."},
    {"id":"mh-x-44","domain":"Mental Health","lang":"en","topic":"Delusional disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Presence of 1+ delusions for 1+ month without other prominent psychotic symptoms. Function may be otherwise preserved. Subtypes: erotomanic, grandiose, jealous, persecutory, somatic. Antipsychotics + supportive therapy; insight often limited."},
    {"id":"mh-x-45","domain":"Mental Health","lang":"en","topic":"Substance-induced psychotic disorder",
     "source":"DSM-5","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Hallucinations/delusions during or shortly after substance use/withdrawal — common with cannabis (especially high-potency), stimulants, hallucinogens, alcohol withdrawal. Resolves with abstinence but may unmask underlying primary psychotic disorder."},

    # ─── Trauma & abuse (12) ───
    {"id":"mh-x-46","domain":"Mental Health","lang":"en","topic":"Childhood sexual abuse — adult survivors",
     "source":"RAINN · NIMHANS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Long-term effects: PTSD, depression, substance use, relationship/trust difficulties, sexual difficulties. Recovery is possible at any age. Specialised trauma therapy (TF-CBT, EMDR, somatic) helps. India: iCall, Arpan Foundation, Tulir provide trauma-informed support."},
    {"id":"mh-x-47","domain":"Mental Health","lang":"en","topic":"Adult sexual assault aftermath",
     "source":"RAINN · WHO","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"After an assault: medical exam within 72 hours if possible (forensic + STI/pregnancy prophylaxis). Reactions vary widely — numbness, shock, anger, fear, self-blame. Not your fault. Support: NCW 7827170170, One Stop Centres (181), iCall, RAINN-style trauma centres in metros."},
    {"id":"mh-x-48","domain":"Mental Health","lang":"en","topic":"Domestic violence — psychological impact",
     "source":"WHO · NIMH","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Beyond physical injury: PTSD (60%+ of survivors), depression, anxiety, substance use, learned helplessness. Coercive control causes lasting cognitive harm even without physical violence. Trauma-informed therapy + practical safety planning are intertwined."},
    {"id":"mh-x-49","domain":"Mental Health","lang":"en","topic":"Workplace trauma & moral injury",
     "source":"BMJ · APA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Healthcare workers, soldiers, first responders, social workers — exposure to others' suffering produces vicarious trauma. Moral injury (acting against one's values under institutional pressure) is distinct from PTSD. Peer support, supervision, structured debriefing."},
    {"id":"mh-x-50","domain":"Mental Health","lang":"en","topic":"Refugee & displacement trauma",
     "source":"UNHCR · WHO","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Multiple traumas: pre-flight violence, dangerous journey, loss of community, resettlement stress. Higher PTSD/depression rates. Community-based and culturally-adapted interventions outperform individual Western therapy in displaced populations."},
    {"id":"mh-x-51","domain":"Mental Health","lang":"en","topic":"Medical trauma",
     "source":"AAFP","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"ICU stays, cancer diagnosis/treatment, traumatic birth, paediatric illness — can cause PTSD in patients and family caregivers. ICU diary, post-ICU clinics, psychological screening at discharge reduce long-term distress."},
    {"id":"mh-x-52","domain":"Mental Health","lang":"en","topic":"Complicated grief / Prolonged Grief Disorder",
     "source":"ICD-11 · APA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Persistent grief beyond 6-12 months that severely impairs functioning. Yearning, identity disruption, avoidance of reminders, emotional numbness. Distinct from depression. Complicated Grief Therapy (Shear) is the evidence-based intervention."},
    {"id":"mh-x-53","domain":"Mental Health","lang":"en","topic":"Vicarious / secondary trauma",
     "source":"ProQOL","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Professionals exposed to trauma stories (therapists, journalists, lawyers, social workers) develop trauma-like symptoms. Self-care practices, caseload limits, peer consultation, formal supervision are protective. ProQOL is a self-screen tool."},
    {"id":"mh-x-54","domain":"Mental Health","lang":"en","topic":"Religious / spiritual abuse",
     "source":"Clinical literature","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Coercive control via religious authority — shaming, shunning, threats of damnation, forced practices. Recovery often requires both psychological and spiritual/identity work. Therapists familiar with religious trauma syndrome can help."},
    {"id":"mh-x-55","domain":"Mental Health","lang":"en","topic":"Racial trauma & microaggressions",
     "source":"APA · Carter racial trauma model","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Cumulative exposure to discrimination produces trauma-like symptoms. Microaggressions (subtle slights) compound macro-events. Race-conscious therapy, community connection, advocacy engagement support recovery. In India: caste-based trauma is the parallel and equally serious."},
    {"id":"mh-x-56","domain":"Mental Health","lang":"en","topic":"Caste-based discrimination & mental health",
     "source":"Round Table India · NIMHANS dalit MH research","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Dalit, Adivasi, and OBC students/workers face elevated depression, anxiety, suicide risk linked to discrimination, microaggressions, and institutional exclusion. Insti-fi suicides in IITs/IIMs have been correlated with this. Specialised counselling at Equal Opportunity Cells; ASHA workers in rural areas."},
    {"id":"mh-x-57","domain":"Mental Health","lang":"en","topic":"Disaster mental health response",
     "source":"WHO · IASC","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"After earthquakes, floods, cyclones: Psychological First Aid (PFA) in acute phase, screening for delayed PTSD/depression months later, community-based interventions outperform individual therapy. NDMA + state DMHPs activate during major disasters."},

    # ─── Therapy modalities (15) ───
    {"id":"mh-x-58","domain":"Mental Health","lang":"en","topic":"Cognitive Behavioural Therapy (CBT)",
     "source":"Beck Institute · APA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Structured, time-limited (typically 12-20 sessions) therapy targeting thoughts-feelings-behaviours connections. Strongest evidence base of any psychotherapy. Effective for depression, anxiety, OCD, PTSD, eating disorders, insomnia. Skills-based with homework between sessions."},
    {"id":"mh-x-59","domain":"Mental Health","lang":"en","topic":"Dialectical Behavior Therapy (DBT)",
     "source":"Linehan · DBT-Linehan Board","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Developed for BPD, now used for chronic suicidality, self-harm, emotion dysregulation. Four modules: mindfulness, distress tolerance, emotion regulation, interpersonal effectiveness. Full programme = individual therapy + skills group + phone coaching + consultation team."},
    {"id":"mh-x-60","domain":"Mental Health","lang":"en","topic":"Acceptance and Commitment Therapy (ACT)",
     "source":"ACBS · Hayes","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Builds psychological flexibility through six processes: acceptance, defusion, present-moment awareness, self-as-context, values, committed action. Goal is values-driven living despite uncomfortable internal experiences. Evidence for chronic pain, depression, anxiety, addiction."},
    {"id":"mh-x-61","domain":"Mental Health","lang":"en","topic":"Eye Movement Desensitisation and Reprocessing (EMDR)",
     "source":"EMDRIA · WHO PTSD guidelines","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Trauma-focused therapy using bilateral stimulation (eye movements/tapping/sound) while recalling traumatic memories. WHO-recommended for PTSD. 8-phase protocol. Requires specific training; not all therapists qualified. Effective in fewer sessions than trauma-focused CBT for some."},
    {"id":"mh-x-62","domain":"Mental Health","lang":"en","topic":"Internal Family Systems (IFS)",
     "source":"Schwartz · IFS Institute","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Model conceptualising the mind as multiple 'parts' (managers, exiles, firefighters) led by a core Self. Therapy involves befriending and unburdening parts. Growing evidence base, especially for trauma and complex presentations."},
    {"id":"mh-x-63","domain":"Mental Health","lang":"en","topic":"Psychodynamic psychotherapy",
     "source":"APA · Shedler 2010 review","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Insight-oriented therapy exploring unconscious patterns, defences, and relationship dynamics — often via the therapeutic relationship itself. Shorter-term (16-30 sessions) versions have evidence comparable to CBT for depression. Open-ended versions for personality work."},
    {"id":"mh-x-64","domain":"Mental Health","lang":"en","topic":"Schema Therapy",
     "source":"Young · ISST","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Integrates CBT, attachment, and Gestalt to address Early Maladaptive Schemas formed in childhood. Effective for personality disorders (especially BPD) and chronic depression. Uses imagery rescripting, chair work, limited reparenting."},
    {"id":"mh-x-65","domain":"Mental Health","lang":"en","topic":"Somatic Experiencing",
     "source":"Levine · SE International","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Body-based trauma therapy focused on completing the autonomic response cycle through pendulation, titration, resourcing. Evidence base growing; particularly useful where talk therapy reactivates trauma. Sensorimotor Psychotherapy is a related modality."},
    {"id":"mh-x-66","domain":"Mental Health","lang":"en","topic":"Mindfulness-Based Stress Reduction (MBSR)",
     "source":"Kabat-Zinn · UMass Medical","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"8-week structured programme combining meditation, body scan, gentle yoga. Originally for chronic pain, now used for stress, anxiety, depression. Strong evidence for reducing relapse in recurrent depression (MBCT is the depression-specific variant)."},
    {"id":"mh-x-67","domain":"Mental Health","lang":"en","topic":"Mindfulness-Based Cognitive Therapy (MBCT)",
     "source":"Segal, Williams, Teasdale","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"NICE-recommended to prevent depressive relapse after 3+ episodes. Combines MBSR with CBT elements. 8 weekly group sessions plus home practice. Reduces relapse by ~30% over 1 year vs treatment as usual."},
    {"id":"mh-x-68","domain":"Mental Health","lang":"en","topic":"Interpersonal Psychotherapy (IPT)",
     "source":"Klerman, Weissman","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Brief (12-16 sessions) therapy linking mood symptoms to one of four problem areas: grief, role transitions, role disputes, interpersonal deficits. WHO-recommended for depression. Adapted versions for adolescents (IPT-A) and group settings."},
    {"id":"mh-x-69","domain":"Mental Health","lang":"en","topic":"Behavioural Activation",
     "source":"Jacobson · NICE","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Stand-alone evidence-based depression treatment focused on scheduling activities linked to positive reinforcement, breaking avoidance cycles. Simpler than CBT, equally effective for many patients, more accessible in low-resource settings."},
    {"id":"mh-x-70","domain":"Mental Health","lang":"en","topic":"Group therapy",
     "source":"AGPA · NIMHANS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Therapeutic factors include universality, altruism, instillation of hope, interpersonal learning. As effective as individual therapy for many conditions (depression, anxiety, addiction). More cost-effective. Specific structured groups: DBT skills, MBCT, support groups."},
    {"id":"mh-x-71","domain":"Mental Health","lang":"en","topic":"Family therapy & systems approaches",
     "source":"AAMFT","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Treats the family system, not just the 'identified patient'. Particularly evidence-based for adolescent eating disorders (FBT), psychosis (Open Dialogue), addiction. Cultural adaptation important in Indian joint-family contexts."},
    {"id":"mh-x-72","domain":"Mental Health","lang":"en","topic":"Couples therapy modalities",
     "source":"Johnson · Gottman","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Emotionally Focused Therapy (EFT, Johnson) targets attachment cycles. Gottman Method works on physiological calm, repair attempts, friendship system. Both have strong outcome data. IBCT integrates acceptance and change."},

    # ─── Medications (10) ───
    {"id":"mh-x-73","domain":"Mental Health","lang":"en","topic":"SSRIs (Selective Serotonin Reuptake Inhibitors)",
     "source":"NIMH · Indian Psychiatric Society","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"First-line for depression and anxiety: fluoxetine, sertraline, escitalopram, paroxetine, fluvoxamine. 4-6 weeks for full effect. Common side effects: nausea, sexual dysfunction, weight changes, sleep disturbance. Slow taper to discontinue."},
    {"id":"mh-x-74","domain":"Mental Health","lang":"en","topic":"SNRIs (Serotonin-Norepinephrine Reuptake Inhibitors)",
     "source":"FDA · IPS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Venlafaxine, duloxetine, desvenlafaxine, milnacipran. Used for depression, anxiety, fibromyalgia/chronic pain. Risk of hypertension at high doses; discontinuation syndrome can be sharp. Useful when SSRIs partially work."},
    {"id":"mh-x-75","domain":"Mental Health","lang":"en","topic":"Benzodiazepines — short-term anxiety",
     "source":"NICE · WHO","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Diazepam, alprazolam, clonazepam, lorazepam. Effective fast but tolerance and dependence develop in 2-4 weeks. NICE and most guidelines limit use to 2-4 weeks for acute crises. Not first-line for chronic anxiety; SSRIs preferred."},
    {"id":"mh-x-76","domain":"Mental Health","lang":"en","topic":"Mood stabilisers",
     "source":"BAP · IPS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Lithium remains gold standard for bipolar, also reduces suicide risk. Valproate (avoid in women of reproductive age — teratogenic), lamotrigine (bipolar depression), carbamazepine. Regular bloodwork required (levels, thyroid, kidney)."},
    {"id":"mh-x-77","domain":"Mental Health","lang":"en","topic":"Antipsychotics — typical vs atypical",
     "source":"APA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Typicals (haloperidol, chlorpromazine) — effective for positive symptoms, more extrapyramidal side effects. Atypicals (olanzapine, risperidone, quetiapine, aripiprazole, clozapine) — broader spectrum, metabolic side effects. Clozapine for treatment-resistant schizophrenia (requires WBC monitoring)."},
    {"id":"mh-x-78","domain":"Mental Health","lang":"en","topic":"Tricyclic antidepressants (TCAs)",
     "source":"NICE","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Amitriptyline, imipramine, nortriptyline. Older but still useful for treatment-resistant depression, neuropathic pain, migraine prophylaxis. Anticholinergic side effects + cardiac risk in overdose make them second-line."},
    {"id":"mh-x-79","domain":"Mental Health","lang":"en","topic":"Stimulants for adult ADHD",
     "source":"FDA · NICE","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Methylphenidate and amphetamines — strong evidence for adult ADHD. India: methylphenidate available with psychiatric prescription. Atomoxetine (non-stimulant) is an alternative. Treatment improves driving safety, occupational, and academic outcomes."},
    {"id":"mh-x-80","domain":"Mental Health","lang":"en","topic":"Ketamine and esketamine for depression",
     "source":"FDA · NIMH","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Rapid antidepressant effect (hours, not weeks) for treatment-resistant depression. Esketamine nasal spray (Spravato) FDA-approved 2019. Effect lasts days; requires repeat dosing. Available at select Indian centres under monitoring."},
    {"id":"mh-x-81","domain":"Mental Health","lang":"en","topic":"ECT (Electroconvulsive Therapy)",
     "source":"APA · NIMHANS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Highly effective for severe depression, treatment-resistant depression, catatonia, severe mania, psychotic depression. Modern ECT is brief, with anaesthesia + muscle relaxant. Side effects: short-term memory loss. Lifesaving when fast response needed."},
    {"id":"mh-x-82","domain":"Mental Health","lang":"en","topic":"rTMS (Repetitive Transcranial Magnetic Stimulation)",
     "source":"FDA · NIMHANS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Non-invasive brain stimulation for depression (FDA-approved), OCD, smoking cessation. ~30 sessions over 6 weeks. No anaesthesia. Available at NIMHANS, AIIMS, and several private hospitals in India. Particularly useful when medications poorly tolerated."},

    # ─── India-specific MH (15) ───
    {"id":"mh-x-83","domain":"Mental Health","lang":"en","topic":"Mental Healthcare Act 2017 (India)",
     "source":"Mental Healthcare Act 2017","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Decriminalised suicide attempts (Sec 115), guaranteed right to mental healthcare, advance directives, nominated representatives. Mandates insurance coverage for mental illness equivalent to physical illness. State and Central Mental Health Authorities oversee implementation."},
    {"id":"mh-x-84","domain":"Mental Health","lang":"en","topic":"Tele-MANAS national tele-mental-health programme",
     "source":"MoHFW · NIMHANS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"24×7 toll-free national helpline 14416 (or 1800-891-4416). Launched 2022, now in 36 states/UTs with 50+ regional centres. Offers triage, counselling, psychiatric consultation in 20+ Indian languages. Backed by NIMHANS and IIIT-Bangalore."},
    {"id":"mh-x-85","domain":"Mental Health","lang":"en","topic":"District Mental Health Programme (DMHP)",
     "source":"National Mental Health Programme","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Available in 700+ districts. Provides outpatient psychiatry, medication, training for primary-care doctors, IEC activities. Patients can walk in to district hospital psychiatry clinics (usually 1-2 days/week). Free medications under the programme."},
    {"id":"mh-x-86","domain":"Mental Health","lang":"en","topic":"Mental health insurance under Indian regulations",
     "source":"IRDAI · MHA 2017","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Section 21(4) of Mental Healthcare Act 2017 mandates insurance parity for mental and physical illness. IRDAI 2018 circular requires all insurers to cover mental illness. In practice, coverage caps and exclusions still vary; complaint mechanism via Insurance Ombudsman."},
    {"id":"mh-x-87","domain":"Mental Health","lang":"en","topic":"NIMHANS Bengaluru services",
     "source":"NIMHANS.ac.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"India's premier mental-health institute. OPD consultation: walk-in registration (small fee), long waitlists. Specialised clinics: dementia, deaddiction, women's MH, child & adolescent, neurology, telemedicine. Many services free or subsidised."},
    {"id":"mh-x-88","domain":"Mental Health","lang":"en","topic":"iCall psychosocial helpline",
     "source":"TISS · icallhelpline.org","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free phone (+91 9152987821) and email/chat counselling Mon-Sat 8am-10pm. Run by Tata Institute of Social Sciences. Counsellors trained in active listening, crisis intervention, brief therapeutic conversations. Confidential."},
    {"id":"mh-x-89","domain":"Mental Health","lang":"en","topic":"Vandrevala Foundation helpline",
     "source":"vandrevalafoundation.com","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"24×7 free helpline 1860-2662-345 / 9999666555. Phone + WhatsApp + email counselling. Trained counsellors and clinical psychologists, with psychiatric escalation when needed. Founded by industrialist Cyrus Vandrevala."},
    {"id":"mh-x-90","domain":"Mental Health","lang":"en","topic":"AASRA suicide prevention helpline",
     "source":"aasra.info","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"24×7 helpline +91-9820466726. Mumbai-based but pan-India phone access. Volunteer-staffed crisis intervention. Confidential. Important for callers in active suicidal crisis."},
    {"id":"mh-x-91","domain":"Mental Health","lang":"en","topic":"Sangath Goa community MH model",
     "source":"sangath.in · Lancet 2010","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pioneered task-shifting: lay health counsellors deliver evidence-based brief interventions for depression and harmful drinking under psychiatrist supervision. Healthy Activity Programme (HAP) for depression — efficacy demonstrated in Lancet RCT. Model scaled in MP, Goa, Madhya Pradesh."},
    {"id":"mh-x-92","domain":"Mental Health","lang":"en","topic":"Live Love Laugh Foundation (LLLF)",
     "source":"thelivelovelaughfoundation.org","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Deepika Padukone's foundation focused on awareness, anti-stigma campaigns, rural school programmes (You Are Not Alone), and Together Against Depression. Maintains a list of credentialed therapists across India."},
    {"id":"mh-x-93","domain":"Mental Health","lang":"en","topic":"Mpower mental health support",
     "source":"mpowerminds.com","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Birla family initiative — Mpower 1on1 helpline 1800-120-820050 (24×7). Clinics in Mumbai, Pune, Bengaluru, Kolkata. Also runs community programmes, school mental-health curriculum."},
    {"id":"mh-x-94","domain":"Mental Health","lang":"en","topic":"NIMHANS Centre for Well Being (Bengaluru)",
     "source":"nimhans.ac.in/cwb","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Dedicated wellness-focused unit at NIMHANS for non-acute concerns — stress, anxiety, family issues, work-life. Lower-cost psychotherapy sessions, structured wellness programmes, yoga, mindfulness. Self-referral OK."},
    {"id":"mh-x-95","domain":"Mental Health","lang":"en","topic":"Sneha Suicide Prevention India Chennai",
     "source":"snehaindia.org","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"24×7 multilingual helpline 044-24640050, email help@snehaindia.org. Trained volunteers (Befrienders International member). Active in suicide-prevention training and survivor support across South India."},
    {"id":"mh-x-96","domain":"Mental Health","lang":"en","topic":"Sumaitri Delhi suicide prevention",
     "source":"sumaitri.net","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Delhi-based emotional support befrienders +91-11-23389090. Mon-Fri 2pm-10pm, weekends till 7pm. Walk-in service also available. Befrienders International affiliate."},
    {"id":"mh-x-97","domain":"Mental Health","lang":"en","topic":"Connecting Trust Pune (suicide & emotional crisis)",
     "source":"connectingngo.org","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"+91-9922001122. Active befrienders helpline founded in 2005. Also runs suicide-prevention training for educational institutions and corporates."},

    # ─── Sleep & adjacent (8) ───
    {"id":"mh-x-98","domain":"Mental Health","lang":"en","topic":"Chronic insomnia disorder",
     "source":"DSM-5 · AASM","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Difficulty initiating/maintaining sleep 3+ nights/week for 3+ months despite adequate opportunity, with daytime impairment. CBT-I is first-line (more effective long-term than hypnotics). Components: sleep restriction, stimulus control, cognitive therapy, relaxation."},
    {"id":"mh-x-99","domain":"Mental Health","lang":"en","topic":"Obstructive sleep apnoea",
     "source":"AASM","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Snoring, witnessed apnoeas, morning headaches, daytime sleepiness. Major cardiovascular risk factor and contributor to depression/cognitive symptoms. Confirmed by polysomnography. CPAP first-line; oral appliances/surgery for selected cases."},
    {"id":"mh-x-100","domain":"Mental Health","lang":"en","topic":"Restless Legs Syndrome",
     "source":"IRLSSG","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Urge to move legs, worse at rest, relieved by movement, evening predominance. Check iron status (target ferritin >75). Avoid SSRIs, antihistamines, dopamine antagonists if possible. Gabapentinoids and dopamine agonists are first-line pharmacotherapy."},
    {"id":"mh-x-101","domain":"Mental Health","lang":"en","topic":"Narcolepsy",
     "source":"AASM","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Excessive daytime sleepiness with sleep attacks. Type 1 includes cataplexy (sudden muscle weakness with emotion). Diagnosis: Multiple Sleep Latency Test (MSLT). Treatment: stimulants (modafinil, methylphenidate), sodium oxybate for cataplexy."},
    {"id":"mh-x-102","domain":"Mental Health","lang":"en","topic":"Parasomnias",
     "source":"ICSD-3","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Sleepwalking, sleep terrors, REM sleep behaviour disorder (acting out dreams), nightmare disorder. Children: usually outgrow. Adults with new-onset RBD warrant neurology evaluation (Parkinson's risk). Safety measures + targeted CBT/medication."},
    {"id":"mh-x-103","domain":"Mental Health","lang":"en","topic":"Circadian rhythm sleep disorders",
     "source":"AASM","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Delayed sleep phase (night owls who can't sleep until 2-3am), advanced phase, shift work, jet lag. Light therapy at strategic times + melatonin shift rhythm. Light at wake time advances phase; evening light delays it."},
    {"id":"mh-x-104","domain":"Mental Health","lang":"en","topic":"Sleep paralysis",
     "source":"AASM","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Temporary inability to move/speak at sleep onset or waking, often with vivid hallucinations. Common (up to 40% experience it once). Reduce by improving sleep regularity, reducing alcohol/caffeine, avoiding supine sleep position."},
    {"id":"mh-x-105","domain":"Mental Health","lang":"en","topic":"Insomnia in pregnancy & postpartum",
     "source":"ACOG","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Common but consequential — increases depression and gestational complication risk. CBT-I safe in pregnancy. Limited medication options; doxylamine and short-term diphenhydramine are pregnancy-acceptable; avoid benzodiazepines."},

    # ─── Substance use specifics (8) ───
    {"id":"mh-x-106","domain":"Mental Health","lang":"en","topic":"Alcohol use disorder",
     "source":"DSM-5 · NIAAA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"AUDIT-C is a quick screen. Withdrawal can be fatal — medically supervised detox for daily heavy drinkers. Pharmacotherapy: naltrexone, acamprosate, disulfiram (deterrent). MET + CBT + 12-step facilitation all evidence-based."},
    {"id":"mh-x-107","domain":"Mental Health","lang":"en","topic":"Tobacco / nicotine dependence",
     "source":"WHO · NHS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Strongest single preventable cause of disease. Quitlines + behavioural counselling + NRT (gum, patch, lozenge) double quit rates over willpower alone. Varenicline most effective pharmacotherapy. India: National Tobacco Quitline 1800-11-2356."},
    {"id":"mh-x-108","domain":"Mental Health","lang":"en","topic":"Cannabis use disorder",
     "source":"DSM-5 · NIDA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Higher-potency cannabis (THC>15%) raises risk of dependence, psychosis (especially in adolescents). Withdrawal: irritability, sleep difficulty, decreased appetite. CBT + motivational interviewing; no FDA-approved medication."},
    {"id":"mh-x-109","domain":"Mental Health","lang":"en","topic":"Opioid use disorder",
     "source":"DSM-5 · WHO","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Medication-assisted treatment (buprenorphine, methadone) outperforms abstinence-only by 2-3x. Naloxone reverses overdose; carry/family-train if any opioid exposure. India: opioid substitution available via NIMHANS, AIIMS, NDDTC, accredited centres."},
    {"id":"mh-x-110","domain":"Mental Health","lang":"en","topic":"Benzodiazepine dependence and tapering",
     "source":"Ashton Manual","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Long-term users develop tolerance + dependence. Abrupt stop can cause seizures. Standard taper: switch to long-acting diazepam, reduce by ~10% every 2-4 weeks. Process can take months — pace to patient comfort. Ashton Manual is the canonical resource."},
    {"id":"mh-x-111","domain":"Mental Health","lang":"en","topic":"Behavioural addictions — gambling, gaming, porn",
     "source":"DSM-5 · ICD-11","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Gambling Disorder is the only formal behavioural addiction in DSM-5; gaming disorder in ICD-11. Same neuropsychology as substance addictions (dopaminergic). CBT effective; SHUT clinic at NIMHANS for tech-related addictions."},
    {"id":"mh-x-112","domain":"Mental Health","lang":"en","topic":"Naloxone — opioid overdose reversal",
     "source":"WHO · NIDA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Reverses opioid overdose within 2-5 min. Available as IM injection (0.4mg) and nasal spray. Family of any opioid user should carry. Call 102/108 immediately; naloxone wears off in 30-90 min, opioids in body longer — can re-overdose."},
    {"id":"mh-x-113","domain":"Mental Health","lang":"en","topic":"Alcoholics Anonymous India",
     "source":"aaindia.org · aagsoindia.org","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free 12-step peer support groups in most Indian metros and tier-2 cities. In-person and online meetings daily. AA literature available in English, Hindi, regional languages. Al-Anon supports family members. No professional therapy substitute, but strong adjunct."},

    # ─── ADHD, autism, neurodivergence (8) ───
    {"id":"mh-x-114","domain":"Mental Health","lang":"en","topic":"Adult ADHD",
     "source":"DSM-5 · CHADD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Diagnosis requires symptoms before age 12 and current symptoms in 2+ settings. Inattention, hyperactivity/impulsivity. Often missed in girls/women presenting as anxiety. Treatment: stimulants/atomoxetine + behavioural strategies + accommodations."},
    {"id":"mh-x-115","domain":"Mental Health","lang":"en","topic":"Autism spectrum diagnosis in adults",
     "source":"DSM-5 · NICE","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Many autistic adults are undiagnosed, especially women and those without intellectual disability. Diagnosis requires lifelong social communication differences + restricted/repetitive patterns. Diagnosis can clarify identity, unlock accommodations, reduce self-blame for masking exhaustion."},
    {"id":"mh-x-116","domain":"Mental Health","lang":"en","topic":"Autistic burnout",
     "source":"AANE","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pervasive long-term exhaustion, loss of function, reduced tolerance to stimulus — from cumulative masking and unmet sensory/social needs. Recovery: reduce demands, sensory accommodation, unmasking with safe people. Distinct from depression though they often co-occur."},
    {"id":"mh-x-117","domain":"Mental Health","lang":"en","topic":"Sensory processing differences",
     "source":"AOTA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Hyper- or hypo-sensitivity to sound, light, touch, taste, proprioception. Common in autism, ADHD, anxiety, post-trauma. Sensory profile assessment + environmental modifications (noise-cancelling headphones, lighting, clothing texture) often more useful than therapy."},
    {"id":"mh-x-118","domain":"Mental Health","lang":"en","topic":"Demand avoidance / PDA profile",
     "source":"PDA Society","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pathological/Persistent Demand Avoidance — extreme need for autonomy and threat response to perceived demands. Considered an autism profile by some clinicians. Standard behavioural approaches counterproductive; collaborative, low-demand approaches work better."},
    {"id":"mh-x-119","domain":"Mental Health","lang":"en","topic":"Dyslexia, dyspraxia, dyscalculia",
     "source":"BDA · IDA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Specific learning disorders affecting reading, motor coordination, math respectively. Independent of intelligence. Accommodations under Indian RPwD Act 2016 include extra time, scribe, assistive tech. Adult diagnosis still useful for self-understanding."},
    {"id":"mh-x-120","domain":"Mental Health","lang":"en","topic":"Tourette syndrome and tic disorders",
     "source":"DSM-5 · TAA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Multiple motor and at least one vocal tic for 1+ year. Usually onset childhood; often improves into adulthood. Comprehensive Behavioural Intervention for Tics (CBIT) is first-line; medication for severe cases."},
    {"id":"mh-x-121","domain":"Mental Health","lang":"en","topic":"FOMO, comparison, social media impact",
     "source":"Royal Society · CDC","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Heavy social media use correlates with depression, anxiety, loneliness — especially in adolescent girls. Mechanisms: upward social comparison, FOMO, displacement of sleep/exercise. Practical interventions: app limits, notification mute, intentional viewing windows."},

    # ─── LGBTQ+ MH (4) ───
    {"id":"mh-x-122","domain":"Mental Health","lang":"en","topic":"Minority stress in LGBTQ+ individuals",
     "source":"Meyer · APA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Chronic stigma, discrimination, expectations of rejection, internalised stigma — causes elevated depression, anxiety, suicidality. Affirming therapy, community connection, advocacy involvement are protective. India: Saksham (NIMHANS), Sahodaran, Naz Foundation provide affirming services."},
    {"id":"mh-x-123","domain":"Mental Health","lang":"en","topic":"Gender dysphoria & affirming care",
     "source":"WPATH SOC 8","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Distress arising from incongruence between experienced gender and assigned sex. Affirming pathways include social transition, hormones, surgery — with mental-health support throughout. WPATH SOC 8 is the international standard. India: Trans community advocacy groups + select endocrinologists/surgeons."},
    {"id":"mh-x-124","domain":"Mental Health","lang":"en","topic":"Coming-out related stress",
     "source":"GLMA · APA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"No 'right' time or order. Family safety, financial dependence, cultural context matter. Therapist with affirming training can help process anticipated reactions and develop scripts. India: many Indian families adjust over time even when initial reaction is hostile."},
    {"id":"mh-x-125","domain":"Mental Health","lang":"en","topic":"Conversion therapy ban",
     "source":"Madras HC 2021 · NMC","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Conversion therapy is harmful and ineffective — strongly opposed by WHO, APA, Indian Psychiatric Society, NMC. Madras High Court 2021 banned it in Tamil Nadu and directed NMC to discipline practitioners. Reporting unethical practice: state medical council + NMC."},

    # ─── Hindi MH content (10) ───
    {"id":"mh-x-126","domain":"Mental Health","lang":"hi","topic":"चिंता क्या है (Hindi) — anxiety basics",
     "source":"NIMHANS · iCall","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"चिंता तनाव के प्रति शरीर की स्वाभाविक प्रतिक्रिया है, लेकिन जब यह दैनिक जीवन में बाधा डाले तो उपचार ज़रूरी है। लक्षण: दौड़ते विचार, बेचैनी, मांसपेशियों में तनाव, नींद की समस्या, तेज़ धड़कन। मदद: iCall 9152987821, Vandrevala 1860-2662-345, Tele-MANAS 14416।"},
    {"id":"mh-x-127","domain":"Mental Health","lang":"hi","topic":"डिप्रेशन के लक्षण (Hindi) — depression signs",
     "source":"NIMHANS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"2 हफ़्ते से ज़्यादा उदास मन, रुचि में कमी, थकान, नींद-भूख में बदलाव, खुद को बेकार समझना। इलाज: मनोचिकित्सक से सलाह, CBT थेरेपी, ज़रूरत पड़ने पर दवा। आत्महत्या के विचार आएँ तो तुरंत iCall या AASRA 9820466726 पर कॉल करें।"},
    {"id":"mh-x-128","domain":"Mental Health","lang":"hi","topic":"नींद की समस्या (Hindi) — sleep issues",
     "source":"AASM · NHS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"रोज़ एक ही समय उठें, सोने से 1 घंटा पहले स्क्रीन बंद करें, कमरा ठंडा-अंधेरा रखें, दोपहर 2 बजे के बाद कैफ़ीन से बचें। 3 हफ़्ते से ज़्यादा अनिद्रा रहे तो CBT-I (नींद की संज्ञानात्मक व्यवहार थेरेपी) सबसे असरदार है।"},
    {"id":"mh-x-129","domain":"Mental Health","lang":"hi","topic":"पैनिक अटैक में क्या करें (Hindi)",
     "source":"NHS · ADAA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"डर का अचानक आना खतरनाक नहीं है — 5-10 मिनट में अपने आप शांत होता है। बॉक्स ब्रीदिंग (4-4-4-4) करें, 5-4-3-2-1 तकनीक से इंद्रियों पर ध्यान दें। बार-बार अटैक आएँ तो मनोचिकित्सक से मिलें।"},
    {"id":"mh-x-130","domain":"Mental Health","lang":"hi","topic":"छात्रों का मानसिक तनाव (Hindi)",
     "source":"UGC · iCall","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"परीक्षा, करियर, अकेलापन, पैसा — कॉलेज जीवन में आम तनाव। दिनचर्या बनाएँ, छोटे लक्ष्य रखें, दोस्तों से बात करें। आत्महत्या के विचार आएँ तो iCall (9152987821) या कॉलेज counsellor से तुरंत मिलें।"},
    {"id":"mh-x-131","domain":"Mental Health","lang":"hi","topic":"पारिवारिक झगड़े और तनाव (Hindi)",
     "source":"NIMHANS family clinic","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"जॉइंट फ़ैमिली, ससुराल, बच्चों की परवरिश — पारिवारिक टकराव आम है। बात करने का सही समय चुनें, दूसरे को समझने की कोशिश करें, ज़रूरी हो तो family counsellor से मदद लें। हिंसा हो तो NCW 7827170170।"},
    {"id":"mh-x-132","domain":"Mental Health","lang":"hi","topic":"शराब की लत छोड़ने में मदद (Hindi)",
     "source":"NIMHANS NDDTC · AA India","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"लत छोड़ने का सबसे सुरक्षित तरीका डॉक्टर की देखरेख में detox है — अचानक छोड़ने से दौरे पड़ सकते हैं। दवाएँ (naltrexone, acamprosate) मदद करती हैं। AA India की मीटिंग्स मुफ़्त हैं, हर शहर में हैं।"},
    {"id":"mh-x-133","domain":"Mental Health","lang":"hi","topic":"बुज़ुर्गों की मानसिक सेहत (Hindi)",
     "source":"HelpAge India · NIMHANS geriatric MH","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"अकेलापन, याददाश्त में कमी, उदासी, चिंता — बुज़ुर्गों में आम लेकिन इलाज योग्य। डिमेंशिया के लक्षणों को पहचानें: रोज़मर्रा की चीज़ें भूलना, समय-स्थान का confusion। Elderline 14567 पर मदद मिलती है।"},
    {"id":"mh-x-134","domain":"Mental Health","lang":"hi","topic":"प्रसव के बाद का तनाव — postpartum (Hindi)",
     "source":"ICMR · ACOG","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"बच्चे के जन्म के बाद उदासी, चिंता, बच्चे से लगाव न होना — postpartum depression के लक्षण। 22% भारतीय माँओं को होता है। डॉक्टर से मिलें — sertraline जैसी दवाएँ स्तनपान में सुरक्षित हैं। iCall पर बात भी कर सकती हैं।"},
    {"id":"mh-x-135","domain":"Mental Health","lang":"hi","topic":"आत्महत्या के विचार आने पर (Hindi)",
     "source":"AASRA · iCall","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"अगर खुद को नुकसान पहुँचाने का विचार आ रहा है तो अभी कॉल करें: AASRA 9820466726, iCall 9152987821, Vandrevala 1860-2662-345, Tele-MANAS 14416। आप अकेले नहीं हैं — मदद उपलब्ध है। नज़दीकी अस्पताल जाएँ।"},

    # ─── German MH content (8) ───
    {"id":"mh-x-136","domain":"Mental Health","lang":"de","topic":"Depression — Symptome und Hilfe (German)",
     "source":"Stiftung Deutsche Depressionshilfe","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Anhaltende Niedergeschlagenheit, Antriebslosigkeit, Schlafstörungen über 2+ Wochen. Hausarzt oder Psychotherapeut ist erste Anlaufstelle. Hilfetelefon: Telefonseelsorge 0800 111 0 111 (kostenlos, 24/7). Bei akuter Suizidalität 112 oder nächste Klinik."},
    {"id":"mh-x-137","domain":"Mental Health","lang":"de","topic":"Panikattacke — was tun (German)",
     "source":"DGPPN","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Panik kommt plötzlich, klingt nach 5-10 Min von selbst ab. Atemtechnik: 4 Sek einatmen, 4 Sek halten, 4 Sek ausatmen. Erinnern: Es ist nicht gefährlich. Bei wiederholten Anfällen Psychotherapie (KVT) suchen."},
    {"id":"mh-x-138","domain":"Mental Health","lang":"de","topic":"Burnout — Erste Schritte (German)",
     "source":"Techniker Krankenkasse","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Anhaltende emotionale Erschöpfung, Zynismus, Leistungsabfall. Erste Schritte: Hausarzt aufsuchen (Krankschreibung), Stressquellen identifizieren, Reha über Krankenkasse beantragen. Psychotherapie und ggf. Wechsel des Arbeitsumfelds."},
    {"id":"mh-x-139","domain":"Mental Health","lang":"de","topic":"Psychotherapeutensuche in Deutschland (German)",
     "source":"Bundespsychotherapeutenkammer","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Termin-Servicestelle der KV (116 117) vermittelt Sprechstunden binnen 4 Wochen. Krankenkasse übernimmt KVT, tiefenpsychologische und analytische Therapie. Therapeut.de und Psych-Info.de für freie Suche. Wartezeiten 3-6 Monate sind normal."},
    {"id":"mh-x-140","domain":"Mental Health","lang":"de","topic":"Suizidgedanken — Hilfe (German)",
     "source":"Telefonseelsorge","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Telefonseelsorge 0800 111 0 111 oder 0800 111 0 222 — kostenlos, 24/7, anonym. Auch per Chat über telefonseelsorge.de. Bei akuter Gefahr 112 oder direkt in die nächste psychiatrische Klinik. Sie sind nicht allein."},
    {"id":"mh-x-141","domain":"Mental Health","lang":"de","topic":"Essstörungen — Anlaufstellen (German)",
     "source":"BZgA · ANAD e.V.","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"BZgA-Beratungstelefon Essstörungen 0221 892031 (Mo-Do 10-22, Fr-So 10-18). ANAD e.V. bietet ambulante und stationäre Hilfe. Frühe Behandlung verbessert Prognose deutlich — Anorexie hat höchste Sterblichkeit aller psychischen Erkrankungen."},
    {"id":"mh-x-142","domain":"Mental Health","lang":"de","topic":"Suchterkrankungen — Anlaufstellen (German)",
     "source":"Sucht und Drogen Hotline","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Sucht und Drogen Hotline 01806 313 031 (rund um die Uhr). Anonyme Alkoholiker und Nikotinanonyme deutschlandweit. Drogenberatungsstellen in jeder Großstadt — kostenlos und anonym. Bei Opiatabhängigkeit Substitutionstherapie über spezialisierten Arzt."},
    {"id":"mh-x-143","domain":"Mental Health","lang":"de","topic":"Häusliche Gewalt — Hilfe (German)",
     "source":"Hilfetelefon Gewalt gegen Frauen","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Hilfetelefon Gewalt gegen Frauen 08000 116 016 (kostenlos, 24/7, 17 Sprachen + Gebärdensprache). Frauenhäuser bundesweit (frauenhauskoordinierung.de). Polizei 110. Bei medizinischen Spuren Gewaltschutzambulanzen ohne Anzeigepflicht."},

    # ─── Caregiver/family support (5) ───
    {"id":"mh-x-144","domain":"Mental Health","lang":"en","topic":"Caregiver burnout — dementia, chronic illness",
     "source":"HelpAge India · Family Caregiver Alliance","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Caring for someone with dementia/serious illness causes chronic stress, depression, immune suppression. Respite care, peer support groups, scheduled self-care non-negotiable. ARDSI (Alzheimer's & Related Disorders Society of India) runs caregiver groups."},
    {"id":"mh-x-145","domain":"Mental Health","lang":"en","topic":"Supporting a partner with depression",
     "source":"NAMI","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Listen without trying to fix. Don't take symptoms personally — withdrawal isn't rejection. Encourage treatment without coercion. Look after your own mental health. Couples therapy can help reset dynamics depression has distorted."},
    {"id":"mh-x-146","domain":"Mental Health","lang":"en","topic":"When a family member won't seek help",
     "source":"NAMI","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Lead with empathy, not arguments. Avoid power struggles. Educate yourself, attend family support groups (NAMI, AFSP). For severe risk: Mental Healthcare Act 2017 provides involuntary admission pathways via Magistrate / mental-health review board."},
    {"id":"mh-x-147","domain":"Mental Health","lang":"en","topic":"Parenting children with mental illness",
     "source":"NAMI · NIMHANS Child & Adolescent Centre","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Early intervention matters most. School involvement (under RPwD Act accommodations), parent training, family therapy. Siblings often overlooked — make space for their feelings. NIMHANS C&AP, AIIMS CAP units offer specialised care."},
    {"id":"mh-x-148","domain":"Mental Health","lang":"en","topic":"Bereavement after suicide",
     "source":"AFSP · SOLOS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Grief after suicide is uniquely complex — guilt, anger, public stigma, intrusive imagery. Survivor support groups (SOLOS, AFSP) reduce isolation and complicated-grief risk. Children need age-appropriate honest explanation. Professional help recommended."},

    # ─── Mind-body adjuncts (2) ───
    {"id":"mh-x-149","domain":"Mental Health","lang":"en","topic":"Yoga and meditation — mental health evidence",
     "source":"AIIMS Integrative Medicine · Cochrane","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Hatha and pranayama practices show moderate evidence for depression, anxiety, insomnia. MBSR/MBCT formalise this within secular protocols. Best as adjunct, not replacement, for moderate-severe illness. AIIMS Integrative Medicine offers structured programmes."},
    {"id":"mh-x-150","domain":"Mental Health","lang":"en","topic":"Exercise as antidepressant",
     "source":"BMJ 2023 meta-analysis","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"~150 min/week moderate exercise has antidepressant effect ~30-50% as strong as SSRIs for mild-moderate depression. Strength training, running, and yoga showed largest effects. Combination with usual treatment outperforms either alone."},

    # ═════════════════════════════════════════════════════════════════════
    # LEGAL — ~250 chunks
    # ═════════════════════════════════════════════════════════════════════

    # ─── Criminal procedure (BNSS / former CrPC) (20) ───
    {"id":"lg-x-01","domain":"Legal","lang":"en","topic":"BNSS Section 173 — FIR registration (replaces CrPC §154)",
     "source":"Bharatiya Nagarik Suraksha Sanhita 2023 · §173","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Police must record information about cognizable offences in writing, read it back, get it signed. Free copy is your right. Refusal: complaint in writing to Superintendent of Police (§173(4)), then magistrate under §175(3) BNSS (formerly §156(3) CrPC)."},
    {"id":"lg-x-02","domain":"Legal","lang":"en","topic":"BNSS Section 35 — arrest without warrant",
     "source":"BNSS 2023 §35","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Police can arrest without warrant for cognizable offences but must record reasons. Arnesh Kumar v State of Bihar (2014) safeguards still apply for offences punishable < 7 years: notice u/s 41A (now BNSS §35) before arrest is mandatory."},
    {"id":"lg-x-03","domain":"Legal","lang":"en","topic":"BNSS Section 47 — rights of arrested person",
     "source":"BNSS 2023 §47 · D K Basu guidelines","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Right to know grounds of arrest, right to lawyer, right to inform a relative/friend, right to medical examination, right to be produced before magistrate within 24 hours. D K Basu v West Bengal mandated arrest memo signed by witness."},
    {"id":"lg-x-04","domain":"Legal","lang":"en","topic":"BNSS Section 187 — judicial custody and remand",
     "source":"BNSS 2023 §187 (replaces CrPC §167)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Maximum police custody now 15 days (extendable up to 40 or 60 days within the first 40/60 of investigation under BNSS). Default bail right under §187(3) if chargesheet not filed within 60/90 days (depending on max sentence)."},
    {"id":"lg-x-05","domain":"Legal","lang":"en","topic":"Bail — bailable vs non-bailable offences",
     "source":"BNSS 2023 · First Schedule","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Bailable: bail is a matter of right (theft under specified value, simple hurt). Non-bailable: court's discretion (murder, rape, dacoity). Anticipatory bail under §482 BNSS (formerly §438 CrPC) for fear of arrest in non-bailable cases."},
    {"id":"lg-x-06","domain":"Legal","lang":"en","topic":"Anticipatory bail",
     "source":"BNSS 2023 §482","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Apply to Sessions Court or High Court if you fear arrest in non-bailable case. Court considers: nature of accusation, applicant's antecedents, possibility of fleeing. Can attach conditions. Sushila Aggarwal (2020 SC) clarified anticipatory bail need not be time-limited."},
    {"id":"lg-x-07","domain":"Legal","lang":"en","topic":"Plea bargaining",
     "source":"BNSS 2023 Ch XXIII","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Available for offences punishable up to 7 years (excluding socio-economic offences affecting society, offences against women/children). Voluntary, with court approval. Reduces sentence by 1/4 if accepted."},
    {"id":"lg-x-08","domain":"Legal","lang":"en","topic":"Compounding of offences",
     "source":"BNSS 2023 §359","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Some offences (specified list — like simple hurt, theft of low value, criminal breach of trust under ₹250) can be compromised with the victim, with or without court permission. Effect: acquittal."},
    {"id":"lg-x-09","domain":"Legal","lang":"en","topic":"Magistrate's powers — taking cognizance",
     "source":"BNSS 2023 §210 (replaces CrPC §190)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Magistrate can take cognizance on (a) police report, (b) private complaint, (c) information from any person. Private complaint route useful if police refuse to register FIR — magistrate orders investigation u/s §175 BNSS."},
    {"id":"lg-x-10","domain":"Legal","lang":"en","topic":"Quashing of FIR — Section 528 BNSS / 482 CrPC",
     "source":"BNSS 2023 §528","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"High Court's inherent power to quash criminal proceedings to prevent abuse of process. State of Haryana v Bhajan Lal (1992) laid down 7 categories where quashing is appropriate. Petition under §528 BNSS / §482 CrPC."},
    {"id":"lg-x-11","domain":"Legal","lang":"en","topic":"Witness protection scheme",
     "source":"Witness Protection Scheme 2018","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Three categories of protection (Category A — life threat extending to family, B — safety threat during trial, C — moderate). Application to Witness Protection Cell of state DGP. Identity concealment, residence change, transport security."},
    {"id":"lg-x-12","domain":"Legal","lang":"en","topic":"Victim compensation under §396 BNSS / §357A CrPC",
     "source":"BNSS 2023 §396","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Victim Compensation Scheme funded by state. NALSA Compensation Scheme for Women Victims/Survivors of Sexual Assault 2018 prescribes amounts: ₹4-7 lakh for rape, ₹3-7 lakh for acid attack, etc. Apply via DLSA."},
    {"id":"lg-x-13","domain":"Legal","lang":"en","topic":"Section 144 BNSS — public order",
     "source":"BNSS 2023 §163 (replaces CrPC §144)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Magistrate can prohibit assembly, weapon-carrying, or other actions if urgent public-order need. Maximum 2 months, extendable to 6 with state government approval. Anuradha Bhasin v UoI (2020) limited blanket curfew use."},
    {"id":"lg-x-14","domain":"Legal","lang":"en","topic":"Charge sheet vs final report",
     "source":"BNSS 2023 §193","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"After investigation, police file chargesheet (sufficient evidence) or final report / closure report (insufficient). Magistrate isn't bound by closure report — can disagree and order further investigation or take cognizance."},
    {"id":"lg-x-15","domain":"Legal","lang":"en","topic":"Habeas corpus petition",
     "source":"Constitution Art 32 / 226","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Writ to produce a person allegedly illegally detained. Filed in Supreme Court (Art 32) or High Court (Art 226). Can be filed by any person on behalf of detainee — letter to court suffices. Court hears on priority."},
    {"id":"lg-x-16","domain":"Legal","lang":"en","topic":"Right to default bail",
     "source":"BNSS 2023 §187(3)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"If chargesheet not filed within 60 days (offence ≤ 10 yr) or 90 days (offence > 10 yr or capital), accused has indefeasible right to bail. Must be applied for and granted on the same day — courts have held this right is enforceable on the 61st/91st day."},
    {"id":"lg-x-17","domain":"Legal","lang":"en","topic":"Lok Adalat",
     "source":"Legal Services Authorities Act 1987","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Alternative dispute resolution under DLSA/SLSA. Free, summary, no court fee. Awards have status of civil court decree, non-appealable. Useful for: motor accident claims, cheque bounce, family disputes, compoundable criminal cases."},
    {"id":"lg-x-18","domain":"Legal","lang":"en","topic":"Mediation under Mediation Act 2023",
     "source":"Mediation Act 2023","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pre-litigation mediation mandatory in commercial disputes (Commercial Courts Act). Mediation Act 2023 institutionalised the process — Mediation Council of India, registered mediators, time-bound process (120 days extendable). Mediated settlements enforceable as decrees."},
    {"id":"lg-x-19","domain":"Legal","lang":"en","topic":"Arbitration & Conciliation Act 1996",
     "source":"Arbitration & Conciliation Act 1996","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Private dispute-resolution alternative to courts. Domestic and international commercial arbitration. Awards enforceable like court decrees. Limited grounds for setting aside (§34). Indian seat or foreign seat affects court intervention."},
    {"id":"lg-x-20","domain":"Legal","lang":"en","topic":"Specific Relief Act 1963 — specific performance",
     "source":"Specific Relief Act 1963 (amended 2018)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pre-2018: specific performance was an exception. 2018 amendment made it a rule for contracts unless damages adequate. Useful for property sale agreements, IP licences. Mandatory injunctions to compel acts also under this Act."},

    # ─── Criminal law (BNS / former IPC) (25) ───
    {"id":"lg-x-21","domain":"Legal","lang":"en","topic":"BNS Section 64 — rape (replaces IPC §375)",
     "source":"Bharatiya Nyaya Sanhita 2023 §63-72","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Definition expanded under BNS retains 7 circumstances. Punishment minimum 10 years, extendable to life (§64). Aggravated forms (gang rape, custodial, of a minor) carry life or death. Section 65: rape on a woman under 16. Section 66: causing death/persistent vegetative state."},
    {"id":"lg-x-22","domain":"Legal","lang":"en","topic":"BNS Section 75 — sexual harassment (replaces IPC §354A)",
     "source":"BNS 2023 §75","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Unwelcome physical contact, demand for sexual favours, sexually coloured remarks, showing pornography — punishable up to 3 years and/or fine. Cognizable, bailable. Adds to remedies under POSH Act 2013 (civil) — both can be invoked."},
    {"id":"lg-x-23","domain":"Legal","lang":"en","topic":"BNS Section 78 — stalking",
     "source":"BNS 2023 §78 (replaces IPC §354D)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Following a woman or contacting/attempting to contact despite her disinterest, or monitoring her electronic communication. First conviction up to 3 years + fine; second up to 5 years. Cognizable, bailable on first offence."},
    {"id":"lg-x-24","domain":"Legal","lang":"en","topic":"BNS Section 77 — voyeurism",
     "source":"BNS 2023 §77 (replaces IPC §354C)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Watching/capturing image of woman engaged in private act where she'd expect not to be observed. 1-3 years first offence, 3-7 years repeat. Disseminating images without consent compounds offence (also IT Act §66E)."},
    {"id":"lg-x-25","domain":"Legal","lang":"en","topic":"BNS Section 79 — outraging modesty",
     "source":"BNS 2023 §79 (replaces IPC §509)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Word, gesture, or act intended to insult modesty of a woman. Up to 3 years. Often used in workplace harassment, public spaces, online harassment. Note overlap with §75 (sexual harassment) and IT Act provisions."},
    {"id":"lg-x-26","domain":"Legal","lang":"en","topic":"BNS Section 103 — murder (replaces IPC §302)",
     "source":"BNS 2023 §103","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Causing death with intention or knowledge that act is likely to cause death. Punishment: death or life imprisonment + fine. Distinguished from §105 culpable homicide not amounting to murder (lower mens rea, lesser punishment up to life)."},
    {"id":"lg-x-27","domain":"Legal","lang":"en","topic":"BNS Section 80 — dowry death (replaces IPC §304B)",
     "source":"BNS 2023 §80","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Death of woman within 7 years of marriage by burns, injury, or otherwise abnormal circumstances + harassment for dowry shortly before death. Presumption against husband/in-laws under §118 Bharatiya Sakshya Adhiniyam. 7 years to life imprisonment."},
    {"id":"lg-x-28","domain":"Legal","lang":"en","topic":"BNS Section 85-86 — cruelty by husband/in-laws (replaces IPC §498A)",
     "source":"BNS 2023 §85-86","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Wilful conduct likely to drive woman to suicide or cause grave injury, or harassment for unlawful demand of property. Up to 3 years + fine. Cognizable, non-bailable. Lalita Kumari (2014 SC) — FIR mandatory. Misuse concerns led to Rajesh Sharma (2017) Family Welfare Committee filter."},
    {"id":"lg-x-29","domain":"Legal","lang":"en","topic":"BNS Section 108 — abetment of suicide (replaces IPC §306)",
     "source":"BNS 2023 §108","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Up to 10 years + fine. Mere harassment insufficient — must be direct or indirect act of incitement with mens rea (SC in Ramesh Kumar 2001). Recent rulings emphasise causal link between accused's conduct and suicide."},
    {"id":"lg-x-30","domain":"Legal","lang":"en","topic":"BNS Section 122 — voluntarily causing hurt by dangerous weapons",
     "source":"BNS 2023 §122 (replaces IPC §324)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Hurt caused by instrument of shooting/stabbing/cutting, fire, poison, explosive — up to 3 years + fine. Non-compoundable after 2013 amendment to former CrPC §320 (now BNSS §359). Cognizable, bailable."},
    {"id":"lg-x-31","domain":"Legal","lang":"en","topic":"BNS Section 116 — grievous hurt (replaces IPC §320)",
     "source":"BNS 2023 §116","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"8 categories: emasculation, permanent loss of vision/hearing, loss of limb/joint, permanent disfigurement of head/face, fracture/dislocation, hurt endangering life, hurt confining person 20+ days. Causing grievous hurt: up to 7 yrs (BNS §117)."},
    {"id":"lg-x-32","domain":"Legal","lang":"en","topic":"BNS Section 137 — kidnapping (replaces IPC §363)",
     "source":"BNS 2023 §137","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"From lawful guardianship of person under 18 (or 21 for male in some contexts) without consent of guardian. Up to 7 years + fine. Aggravated forms (for ransom, slavery, marriage) under §138-§140."},
    {"id":"lg-x-33","domain":"Legal","lang":"en","topic":"BNS Section 351 — criminal intimidation (replaces IPC §503)",
     "source":"BNS 2023 §351","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Threatening injury to person, property, or reputation to compel act or cause alarm. Up to 2 years + fine. By anonymous communication (§353): additional punishment. Common in domestic disputes, neighbour conflicts, online harassment."},
    {"id":"lg-x-34","domain":"Legal","lang":"en","topic":"BNS Section 318 — cheating (replaces IPC §420)",
     "source":"BNS 2023 §318","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Deception causing wrongful gain to one or wrongful loss to another. Up to 7 years + fine. Cheating by personation (§319 / former §416-IPC). Mens rea (dishonest intention at the outset) is essential — pure breach of contract is not cheating."},
    {"id":"lg-x-35","domain":"Legal","lang":"en","topic":"BNS Section 316 — criminal breach of trust",
     "source":"BNS 2023 §316 (replaces IPC §405)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Dishonest misappropriation of property entrusted. Up to 5 years. By public servant (§316(5)) or clerk/banker — life imprisonment possible. Distinct from cheating (no entrustment) and theft (no consent in receiving property)."},
    {"id":"lg-x-36","domain":"Legal","lang":"en","topic":"BNS Section 303 — theft (replaces IPC §378)",
     "source":"BNS 2023 §303","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Dishonest taking of movable property without consent of owner. Up to 3 years + fine; up to 7 years if from dwelling/transport (§305). Aggravated by force = robbery (§309), violence = dacoity (§310, five or more persons)."},
    {"id":"lg-x-37","domain":"Legal","lang":"en","topic":"BNS Section 356 — defamation",
     "source":"BNS 2023 §356 (replaces IPC §499-500)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Imputation harming reputation. 10 exceptions including truth published for public good, fair comment on public conduct. Up to 2 years + fine. Civil defamation (separate, no statutory cap on damages) is parallel remedy."},
    {"id":"lg-x-38","domain":"Legal","lang":"en","topic":"BNS Section 113 — terrorist act",
     "source":"BNS 2023 §113","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"New BNS provision criminalising terrorist acts (previously only UAPA). Death/life imprisonment if death caused, 5 years to life otherwise. Concerns raised about overlap with UAPA and broad definition."},
    {"id":"lg-x-39","domain":"Legal","lang":"en","topic":"BNS Section 152 — endangering sovereignty (replaces IPC §124A sedition)",
     "source":"BNS 2023 §152","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Sedition (IPC §124A) is repealed; §152 BNS replaces with offence of acts endangering sovereignty, unity, integrity. Critics flag risk of similar misuse; SC's Kedar Nath narrow reading is the safeguard. Up to life imprisonment."},
    {"id":"lg-x-40","domain":"Legal","lang":"en","topic":"BNS Section 304 — snatching (new offence)",
     "source":"BNS 2023 §304","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"New offence — sudden, quick, or forcible seizure of movable property. Distinct from theft (no force) and robbery (more aggravated force). Up to 3 years + fine. Particularly relevant to chain/phone-snatching in urban areas."},
    {"id":"lg-x-41","domain":"Legal","lang":"en","topic":"BNS Section 69 — false promise to marry",
     "source":"BNS 2023 §69","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"New BNS provision: deceitful sexual intercourse including false promise to marry. Up to 10 years + fine. Codifies SC jurisprudence (Pramod Suryabhan Pawar 2019). Critics flag risk of misuse in consensual relationships gone sour."},
    {"id":"lg-x-42","domain":"Legal","lang":"en","topic":"BNS Section 197 — promoting enmity (replaces IPC §153A)",
     "source":"BNS 2023 §197","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Words, signs, visible representations promoting enmity between groups on religion/race/caste/community grounds. Up to 5 years + fine; 7 years if in place of worship. Frequently invoked against social-media hate speech."},
    {"id":"lg-x-43","domain":"Legal","lang":"en","topic":"BNS Section 209-211 — obscenity and obscene acts",
     "source":"BNS 2023 §209-211","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Sale/distribution of obscene matter (§210): 2 yr first offence, 5 yr second. To minors (§211): higher punishment. Obscene acts in public (§212): 3 months. Internet obscenity also under IT Act §67."},
    {"id":"lg-x-44","domain":"Legal","lang":"en","topic":"BNS Section 274 — adulteration of food/drugs",
     "source":"BNS 2023 §274 (replaces IPC §272)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Adulterating food/drink intended for sale. Up to 6 months + ₹5000 fine. Stronger remedies under Food Safety and Standards Act 2006 + Drugs and Cosmetics Act 1940. State food safety officers enforce."},
    {"id":"lg-x-45","domain":"Legal","lang":"en","topic":"BNS Section 81 — selling minor for prostitution",
     "source":"BNS 2023 §81 (replaces IPC §372)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Selling, letting, or otherwise disposing of person under 18 for prostitution. Up to 10 years + fine. Read with Immoral Traffic (Prevention) Act 1956 and Juvenile Justice Act 2015 for child protection."},

    # ─── Family law (20) ───
    {"id":"lg-x-46","domain":"Legal","lang":"en","topic":"Hindu Marriage Act §13(1) — fault grounds for divorce",
     "source":"HMA 1955 §13(1)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Cruelty (mental + physical), desertion 2+ years, conversion, mental disorder, communicable disease, renunciation, presumption of death (7+ years missing). Each ground has specific evidentiary requirements. Mediation often attempted first."},
    {"id":"lg-x-47","domain":"Legal","lang":"en","topic":"Hindu Marriage Act §13B — mutual consent divorce",
     "source":"HMA 1955 §13B","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Both spouses agree, separated 1+ year. Two motions, 6-month cooling period between. SC (Amardeep Singh 2017) allowed waiver where reconciliation impossible. Total: 6-18 months. Cheapest and least adversarial route."},
    {"id":"lg-x-48","domain":"Legal","lang":"en","topic":"Hindu Marriage Act §24-25 — maintenance",
     "source":"HMA 1955 §24-25","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"§24: interim maintenance + litigation expenses during pendency. §25: permanent alimony at decree. Court considers parties' income, conduct, lifestyle. Not gender-specific in 2024 reading though usually claimed by wife."},
    {"id":"lg-x-49","domain":"Legal","lang":"en","topic":"Section 125 CrPC / §144 BNSS — maintenance for wife/children/parents",
     "source":"BNSS 2023 §144","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Secular, religion-neutral, fast-track maintenance for wife (including divorced), children (legitimate + illegitimate, including major if unable to maintain), and parents. Magistrate's court. Quantum: capped at ₹500/month earlier — removed by 2001 amendment."},
    {"id":"lg-x-50","domain":"Legal","lang":"en","topic":"Special Marriage Act 1954 — civil marriage",
     "source":"Special Marriage Act 1954","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Inter-faith and civil marriages. 30-day notice, public objections, then marriage. Used widely for inter-religious marriages — controversial 30-day window has led to harassment of couples. Divorce on similar grounds as HMA."},
    {"id":"lg-x-51","domain":"Legal","lang":"en","topic":"Indian Divorce Act 1869 — Christians",
     "source":"Indian Divorce Act 1869 (amended 2001)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pre-2001 had higher burden on women. Now: cruelty, adultery, desertion, conversion, mental disorder, communicable disease, presumption of death, mutual consent. District court jurisdiction."},
    {"id":"lg-x-52","domain":"Legal","lang":"en","topic":"Muslim Personal Law — talaq forms",
     "source":"Muslim Personal Law · Triple Talaq Act 2019","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Talaq-e-Ahsan (single pronouncement, iddat waiting period), Talaq-e-Hasan (three monthly pronouncements). Triple talaq (talaq-e-biddat) invalidated by SC Shayara Bano 2017, criminalised by Muslim Women (Protection of Rights on Marriage) Act 2019."},
    {"id":"lg-x-53","domain":"Legal","lang":"en","topic":"Muslim women — divorce options",
     "source":"Dissolution of Muslim Marriages Act 1939","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Khula (wife seeks divorce, returns mahr), faskh (judicial dissolution under DMMA 1939 — grounds: cruelty, desertion 4+ years, non-maintenance 2 years, impotence, insanity, leprosy). Sec 125 CrPC maintenance also available."},
    {"id":"lg-x-54","domain":"Legal","lang":"en","topic":"Mahr — Muslim marriage dower",
     "source":"Muslim Personal Law","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Obligatory payment from husband to wife at marriage (prompt or deferred). Wife's absolute property. Recoverable as a debt in civil court. Court-determined if quantum disputed. Distinct from dowry (gifts from bride's family, prohibited)."},
    {"id":"lg-x-55","domain":"Legal","lang":"en","topic":"Dowry Prohibition Act 1961",
     "source":"Dowry Prohibition Act 1961","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Giving, taking, demanding dowry punishable up to 5 years + ₹15,000 fine or value of dowry. Read with BNS §80 (dowry death) and §85 (cruelty). Dowry Prohibition Officers in each district can register complaints."},
    {"id":"lg-x-56","domain":"Legal","lang":"en","topic":"PWDVA 2005 — types of abuse covered",
     "source":"Protection of Women from Domestic Violence Act 2005 §3","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Physical, sexual, verbal, emotional, economic abuse. Covers women in domestic relationship (marriage, live-in, family). Reliefs: protection order (§18), residence order (§19), monetary relief (§20), custody (§21), compensation (§22)."},
    {"id":"lg-x-57","domain":"Legal","lang":"en","topic":"PWDVA — right to reside in shared household",
     "source":"PWDVA §17","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Aggrieved woman has right to reside in shared household regardless of title. SC Satish Chander Ahuja v Sneha Ahuja (2020) clarified definition. Cannot be evicted except by court process. Magistrate can order alternative accommodation paid by respondent."},
    {"id":"lg-x-58","domain":"Legal","lang":"en","topic":"Hindu Succession Act 2005 amendment — daughter's coparcenary",
     "source":"HSA 1956 §6 (amended 2005)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Daughter becomes coparcener in joint Hindu family property by birth — same rights as son. Applies retrospectively per Vineeta Sharma v Rakesh Sharma (2020 SC), regardless of father's status on 9 Sep 2005."},
    {"id":"lg-x-59","domain":"Legal","lang":"en","topic":"Hindu Succession — intestate succession (§8 HSA)",
     "source":"HSA 1956 §8","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Property of Hindu male dying intestate devolves: Class I heirs (widow, sons, daughters, mother) first; absent that, Class II heirs (father, siblings, etc.); then agnates; cognates. Class I heirs share equally."},
    {"id":"lg-x-60","domain":"Legal","lang":"en","topic":"Muslim succession — Sharia distribution",
     "source":"Muslim Personal Law (Shariat) Application Act 1937","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Sunni and Shia distinct. Fixed shares for spouse, parents, children (sons take twice daughters' share in most cases — controversial). Will (wasiyyat) can dispose only 1/3 of estate. Disputed share distribution often litigated."},
    {"id":"lg-x-61","domain":"Legal","lang":"en","topic":"Indian Succession Act 1925 — Christians, Parsis, intestate",
     "source":"Indian Succession Act 1925","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Default for Christians and Parsis. Spouse + children share equally typically. Probate of will required in major cities (Calcutta, Bombay, Madras). Letters of administration for intestate succession."},
    {"id":"lg-x-62","domain":"Legal","lang":"en","topic":"Hindu Adoption and Maintenance Act 1956",
     "source":"HAMA 1956","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Hindu can adopt with spouse consent (unless single/widowed). Adoptive parent at least 21 years older than adoptee of opposite sex. Adopted child gets succession rights. CARA registration also required for inter-country/agency adoption."},
    {"id":"lg-x-63","domain":"Legal","lang":"en","topic":"CARA — adoption for non-Hindus",
     "source":"Central Adoption Resource Authority","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Statutory body under Juvenile Justice Act 2015. Registration at cara.nic.in for adoption from Specialised Adoption Agencies. Eligibility: 25-50 (single woman), couples ≤ 90 years combined for child under 4. Waiting time 1-3 years."},
    {"id":"lg-x-64","domain":"Legal","lang":"en","topic":"Guardianship — Hindu Minority and Guardianship Act 1956",
     "source":"HMGA 1956","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Father is natural guardian; mother after him — Gita Hariharan (1999 SC) read 'after' as not necessarily after death. Mother is natural guardian of illegitimate child. For children under 5, custody usually with mother (children's welfare paramount)."},
    {"id":"lg-x-65","domain":"Legal","lang":"en","topic":"Same-sex marriage — current Indian position",
     "source":"Supriyo @ Supriya Chakraborty v UoI (2023 SC)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Supreme Court (2023) declined to grant legal recognition to same-sex marriage, leaving it to Parliament. Court noted urgency of administrative protections (joint bank accounts, hospital visitation). Section 377 IPC decriminalised consensual same-sex relations by Navtej Singh Johar (2018)."},

    # ─── Civil procedure & contract (15) ───
    {"id":"lg-x-66","domain":"Legal","lang":"en","topic":"CPC Order 7 — plaint",
     "source":"Code of Civil Procedure 1908","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Plaint (suit's statement of claim) must include parties, jurisdiction facts, cause of action, value for jurisdiction, relief sought. Order 7 Rule 11 — court can reject for non-disclosure of cause of action, undervaluation, time bar, etc."},
    {"id":"lg-x-67","domain":"Legal","lang":"en","topic":"CPC Order 37 — summary suits",
     "source":"CPC Order 37","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Faster procedure for bills of exchange, promissory notes, money recovery on written contract. Defendant must apply for leave to defend within 10 days — courts strict on conditional leave if defence weak."},
    {"id":"lg-x-68","domain":"Legal","lang":"en","topic":"CPC §80 — notice to government before suit",
     "source":"CPC 1908 §80","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"2-month notice to government/public officer before filing suit (with exceptions for urgent injunction). Notice must specify cause of action, relief, name/address of plaintiff. Curable defect — courts increasingly permissive."},
    {"id":"lg-x-69","domain":"Legal","lang":"en","topic":"Indian Contract Act §11 — capacity to contract",
     "source":"Indian Contract Act 1872 §11","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Major (18+), sound mind, not disqualified by law. Minor's agreement is void ab initio (Mohori Bibee 1903). Minor's necessary purchases enforceable under §68. Mental incapacity assessed at moment of contracting."},
    {"id":"lg-x-70","domain":"Legal","lang":"en","topic":"Indian Contract Act §14 — free consent",
     "source":"ICA 1872 §14-22","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Consent not free if caused by coercion (§15), undue influence (§16), fraud (§17), misrepresentation (§18), or mistake (§20-22). Contract voidable at option of aggrieved party (except fundamental mistake — void)."},
    {"id":"lg-x-71","domain":"Legal","lang":"en","topic":"Indian Contract Act §23 — lawful consideration and object",
     "source":"ICA 1872 §23","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Agreement void if consideration/object: forbidden by law, defeats law, fraudulent, injures person/property, immoral, opposed to public policy. Modern wagering/cryptocurrency contracts test these limits."},
    {"id":"lg-x-72","domain":"Legal","lang":"en","topic":"Indian Contract Act §73-74 — damages on breach",
     "source":"ICA 1872 §73-74","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"§73: compensation for loss naturally arising from breach. §74: reasonable compensation where pre-agreed (liquidated damages clause) — court can reduce if not genuine pre-estimate. Mitigation duty on aggrieved party."},
    {"id":"lg-x-73","domain":"Legal","lang":"en","topic":"Indian Contract Act §27 — restraint of trade",
     "source":"ICA 1872 §27","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Agreements restraining lawful profession/trade are void, except sale of goodwill (limited time/area). Non-compete clauses in Indian employment contracts during employment OK; post-employment generally unenforceable."},
    {"id":"lg-x-74","domain":"Legal","lang":"en","topic":"Sale of Goods Act 1930",
     "source":"Sale of Goods Act 1930","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Implied conditions: title (§14), description (§15), quality/fitness (§16), sample (§17). Remedies: rejection, damages, specific performance. Distinct from Consumer Protection Act 2019 (which adds consumer-specific remedies)."},
    {"id":"lg-x-75","domain":"Legal","lang":"en","topic":"Limitation Act 1963 — common periods",
     "source":"Limitation Act 1963","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"3 years: most money suits, breach of contract. 1 year: defamation, accounts. 12 years: possession of immovable property. 30 years: mortgage redemption. Acknowledgment of debt (§18) restarts clock. Disability under §6 extends."},
    {"id":"lg-x-76","domain":"Legal","lang":"en","topic":"Court fees and stamp duty",
     "source":"Court Fees Act 1870 + state acts","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Ad valorem (percentage of claim value) for money suits, fixed for declaratory/injunction suits. State-specific rates. Insufficient stamp = plaint rejected unless made good. Indian Stamp Act for instruments (deeds, agreements)."},
    {"id":"lg-x-77","domain":"Legal","lang":"en","topic":"Civil suit — typical stages",
     "source":"CPC 1908","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Plaint → summons → written statement (30 days, extendable 90) → framing of issues → evidence (affidavit + cross-examination) → arguments → judgment → decree. Appeals to district court → high court → SC. Total time: often 5-10 years."},
    {"id":"lg-x-78","domain":"Legal","lang":"en","topic":"Negotiable Instruments Act §138 — cheque bounce defence",
     "source":"NI Act 1881 §139","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"§139 presumes cheque issued for discharge of debt — drawer must rebut. Common defences: no debt existed, cheque misused, signature forged, cheque time-barred when presented. Mediation/settlement frequently resolves without trial."},
    {"id":"lg-x-79","domain":"Legal","lang":"en","topic":"Specific Relief Act §38 — perpetual injunctions",
     "source":"SRA 1963 §38-39","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Court can grant perpetual injunction to prevent breach of obligation where damages would be inadequate. Mandatory injunction (§39) to compel act required by trust/contract. Property disputes, IP infringement common applications."},
    {"id":"lg-x-80","domain":"Legal","lang":"en","topic":"Easements Act 1882 — right of way",
     "source":"Indian Easements Act 1882","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Easement: right over another's land for one's own land's beneficial use. Created by grant, necessity, or prescription (20 years' open peaceful enjoyment). Common: right of way, light, air, water. Suit to declare/enforce in civil court."},

    # ─── Labour & employment (15) ───
    {"id":"lg-x-81","domain":"Legal","lang":"en","topic":"Code on Wages 2019 — overview",
     "source":"Code on Wages 2019","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Consolidates Payment of Wages Act, Minimum Wages Act, Payment of Bonus Act, Equal Remuneration Act. Statutory floor wage. Minimum wage notified state-wise + central sphere. Equal pay for equal work codified. Yet to be fully notified across states."},
    {"id":"lg-x-82","domain":"Legal","lang":"en","topic":"Industrial Disputes Act 1947 — retrenchment",
     "source":"IDA 1947 §25F-25N","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Retrenchment requires: 1 month notice + retrenchment compensation (15 days' wages × completed years). For establishments with 100+ workers, government permission required (§25N) — usually a high bar. Industrial Relations Code 2020 will replace once notified."},
    {"id":"lg-x-83","domain":"Legal","lang":"en","topic":"EPF — withdrawal rules",
     "source":"EPF Act 1952","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Full withdrawal after 2 months of leaving employment. Partial: marriage, education, housing, medical, illness, post-58 retirement. Online via Member Portal. Aadhaar + bank + PAN must be KYC-verified. Tax-free if 5+ years' service."},
    {"id":"lg-x-84","domain":"Legal","lang":"en","topic":"Gratuity — eligibility and calculation",
     "source":"Payment of Gratuity Act 1972","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Eligible after 5 years' continuous service (lower in some cases — death/disability). Formula: (15 × last drawn wage × completed years) ÷ 26. Tax-exempt up to ₹20 lakh. Employer's failure to pay = penalty + interest."},
    {"id":"lg-x-85","domain":"Legal","lang":"en","topic":"Maternity Benefit (Amendment) Act 2017",
     "source":"Maternity Benefit Act 1961 (amended 2017)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"26 weeks paid leave for first two children (12 for third+). 12 weeks for adoptive/commissioning mothers. Mandatory crèche for establishments with 50+ employees. Work-from-home option negotiable post-leave."},
    {"id":"lg-x-86","domain":"Legal","lang":"en","topic":"POSH Act — Internal Complaints Committee composition",
     "source":"POSH Act 2013 §4","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Presiding officer must be a senior woman employee. Two members from employees committed to women's issues. One external member from NGO familiar with sexual harassment. At least half women. 3-year term."},
    {"id":"lg-x-87","domain":"Legal","lang":"en","topic":"POSH — Local Complaints Committee",
     "source":"POSH Act §6","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"For workplaces with <10 employees or where employer is respondent. District officer constitutes LCC. Chairperson is socially-connected woman; one from rural area/grassroots; 2/3 women. Files complaints from domestic workers, informal sector."},
    {"id":"lg-x-88","domain":"Legal","lang":"en","topic":"POSH — complaint timeline and remedy",
     "source":"POSH Act §9","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Written complaint within 3 months (extendable by ICC for valid reason). ICC inquiry within 90 days. Action on findings within 60 days of report. Penalties: written apology, warning, transfer, suspension, dismissal, deduction from salary. False complaint = action against complainant."},
    {"id":"lg-x-89","domain":"Legal","lang":"en","topic":"She-Box — online POSH complaint portal",
     "source":"Ministry of Women & Child Development","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"shebox.wcd.gov.in — central government portal. Complaints forwarded to concerned authority. Provides time-bound tracking. Available to government, private, organised, unorganised sector employees."},
    {"id":"lg-x-90","domain":"Legal","lang":"en","topic":"ESI — eligibility and benefits",
     "source":"ESI Act 1948","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Employees earning ≤ ₹21,000/month (₹25,000 disabled). Covers: medical, sickness, maternity, disablement, dependent benefit, funeral. ESI hospitals + empanelled private hospitals. Contribution: 0.75% employee + 3.25% employer."},
    {"id":"lg-x-91","domain":"Legal","lang":"en","topic":"Trade Union recognition",
     "source":"Trade Unions Act 1926 / Industrial Relations Code 2020","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Registration: 10% or 100 workers (whichever less). Recognition: state varies but typically union with >51% membership. New IR Code (yet to be notified) introduces 'sole negotiating union' with >51% membership."},
    {"id":"lg-x-92","domain":"Legal","lang":"en","topic":"Sexual harassment — civil vs criminal remedies",
     "source":"POSH 2013 + BNS §75","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"POSH provides civil/administrative remedy through ICC. BNS §75 provides criminal remedy through FIR/court. Both can be invoked simultaneously — they don't bar each other. Choice depends on victim's preference for outcome (workplace action vs prosecution)."},
    {"id":"lg-x-93","domain":"Legal","lang":"en","topic":"Whistleblower Protection Act 2014",
     "source":"Whistle Blowers Protection Act 2014","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Limited Act — only for public servants reporting corruption/abuse to Vigilance Commission. Anonymous disclosure permitted; identity protected. Private-sector whistleblowers rely on SEBI/Companies Act/labour law remedies. Reform pending."},
    {"id":"lg-x-94","domain":"Legal","lang":"en","topic":"Contract labour — CLRA Act 1970",
     "source":"Contract Labour (Regulation & Abolition) Act 1970","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Establishments with 20+ contract workers need registration. Principal employer liable for wages if contractor defaults. Abolition possible in 'core' work (Steel Authority of India 2001 SC). New Occupational Safety Code 2020 consolidates."},
    {"id":"lg-x-95","domain":"Legal","lang":"en","topic":"Gig and platform workers — Social Security Code 2020",
     "source":"Code on Social Security 2020","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Recognises gig and platform workers (Ola, Uber, Swiggy drivers). Aggregators must contribute 1-2% of turnover or 5% of payouts (whichever lower). Schemes for life, disability, accident insurance. Implementation rules still being framed."},

    # ─── Tax law (10) ───
    {"id":"lg-x-96","domain":"Legal","lang":"en","topic":"Income Tax — old vs new regime",
     "source":"Income Tax Act 1961 §115BAC","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"New regime (default since FY 2023-24): lower slab rates but limited deductions (only standard ₹50,000, NPS 80CCD(2)). Old regime: higher rates but 80C, 80D, HRA, LTA, home loan deductions. Choose annually for non-business income."},
    {"id":"lg-x-97","domain":"Legal","lang":"en","topic":"Section 80C — common deductions",
     "source":"Income Tax Act 1961 §80C","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1.5 lakh cap. PF/PPF, ELSS mutual funds, life insurance premium, home loan principal, tuition fees for children, NSC, Sukanya Samriddhi, tax-saving FD (5 yr). Available under old regime only."},
    {"id":"lg-x-98","domain":"Legal","lang":"en","topic":"GST — slab rates",
     "source":"CGST Act 2017","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Five rates: 0% (essential food), 5%, 12%, 18%, 28%. Cess on luxury/sin items. Composition scheme (small businesses up to ₹1.5 cr): 1% (traders) / 6% (services). Threshold for registration: ₹40 lakh (₹20 lakh services)."},
    {"id":"lg-x-99","domain":"Legal","lang":"en","topic":"GST input tax credit",
     "source":"CGST Act §16-18","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Credit for GST paid on inputs used for taxable supplies. Conditions: invoice, receipt of goods/services, supplier filed GSTR-1, recipient files GSTR-3B. Time limit: by November of next FY. Blocked credits: motor vehicles (with exceptions), food, beauty services."},
    {"id":"lg-x-100","domain":"Legal","lang":"en","topic":"TDS — common rates",
     "source":"Income Tax Act 1961 Ch XVII","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Salary (§192) — slab rate. Professional fees (§194J) — 10%. Contractor (§194C) — 1%/2%. Rent (§194I) — 10% land/building, 2% machinery. Interest other than securities (§194A) — 10%. PAN missing = 20%. Quarterly returns + Form 16/16A."},
    {"id":"lg-x-101","domain":"Legal","lang":"en","topic":"Tax appeals — Income Tax",
     "source":"IT Act §246A onwards","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Assessment order → CIT(A) appeal (30 days, no stay automatic) → ITAT (60 days, second-level fact finding) → High Court (substantial question of law) → Supreme Court. Faceless appeal scheme operational since 2020."},
    {"id":"lg-x-102","domain":"Legal","lang":"en","topic":"Property tax basics",
     "source":"Municipal Acts (state-specific)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Annual tax to municipal corporation/panchayat. Basis: Annual Rateable Value or Capital Value (state-specific). Pay online via municipal portal. Late payment attracts interest. Self-occupied vs let-out, residential vs commercial differ."},
    {"id":"lg-x-103","domain":"Legal","lang":"en","topic":"Stamp duty on property sale",
     "source":"Indian Stamp Act 1899 + state amendments","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"State-specific (5-7% common). Some states give women buyers concession (1-2% lower). Registration fee separate (~1%). Buyer typically pays both. Pay online via state e-stamping system (Stock Holding Corporation)."},
    {"id":"lg-x-104","domain":"Legal","lang":"en","topic":"Capital gains — short vs long term",
     "source":"IT Act §2(42A), §111A, §112A","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Listed equity: STCG (held ≤12 months) = 15%; LTCG = 10% over ₹1.25 lakh. Real estate: STCG (≤24 months) = slab; LTCG = 20% with indexation OR 12.5% without (post-Budget 2024). Exemptions: §54 (new house), §54EC (capital gain bonds)."},
    {"id":"lg-x-105","domain":"Legal","lang":"en","topic":"Form 26AS / AIS / TIS",
     "source":"Income Tax Portal","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"26AS: TDS, advance tax, refunds. AIS (Annual Information Statement): comprehensive — includes SFT (specified financial transactions), GST turnover, foreign remittances. TIS (Taxpayer Information Summary): processed AIS for reconciliation. Check before ITR filing."},

    # ─── Property & real estate (10) ───
    {"id":"lg-x-106","domain":"Legal","lang":"en","topic":"RERA — Real Estate Regulatory Authority",
     "source":"Real Estate (Regulation and Development) Act 2016","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"All projects 500+ sqm or 8+ apartments need registration with state RERA. Mandates: 70% buyer funds in escrow, possession dates, carpet area disclosure, no advertising without registration. Complaints to RERA tribunal — fast-track."},
    {"id":"lg-x-107","domain":"Legal","lang":"en","topic":"Property title verification",
     "source":"Standard practice","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"30-year title chain check, encumbrance certificate (15-30 yr), khata/property tax receipts, RERA registration, building plan approval, occupancy certificate, NOC from lender if mortgaged. Always engage independent advocate, not seller's lawyer."},
    {"id":"lg-x-108","domain":"Legal","lang":"en","topic":"Power of Attorney sale — limited validity",
     "source":"Suraj Lamp v Haryana (2011 SC)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"SC banned use of GPA, agreement to sell, and unregistered will combo to transfer title. Only registered sale deed conveys title. POA + agreement valid only for executing eventual sale deed. Several states still see informal POA transactions — risky."},
    {"id":"lg-x-109","domain":"Legal","lang":"en","topic":"Apartment ownership — RWA and bye-laws",
     "source":"State Apartment Ownership Acts","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Apartment owner has rights in own unit + undivided share in common areas. Society/RWA management under state society registration acts + apartment ownership acts. Disputes go to Cooperative Court or Civil Court (depending on registration)."},
    {"id":"lg-x-110","domain":"Legal","lang":"en","topic":"Tenant — landlord rent recovery",
     "source":"State Rent Control Acts","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Most states have rent control acts (Delhi, Maharashtra, Tamil Nadu, etc.) — protections against eviction, capped rent escalation. Model Tenancy Act 2021 aims to balance interests but state adoption slow. Lease registration mandatory >1 year."},
    {"id":"lg-x-111","domain":"Legal","lang":"en","topic":"Section 106 TPA — notice to quit",
     "source":"Transfer of Property Act 1882 §106","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Monthly tenancy: 15 days notice ending with tenancy month. Yearly tenancy: 6 months notice. Written notice required. Self-help eviction = criminal trespass under IPC §441 — civil suit only legal route."},
    {"id":"lg-x-112","domain":"Legal","lang":"en","topic":"Adverse possession",
     "source":"Limitation Act §27 + Schedule","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"12 years' continuous, open, hostile possession of immovable property bars original owner's title (30 years for government property). Possession must be 'as owner' not as tenant. Suit for possession by original owner barred after limitation."},
    {"id":"lg-x-113","domain":"Legal","lang":"en","topic":"Partition of joint family property",
     "source":"HSA + general partition law","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Coparcener can demand partition any time. Methods: oral partition (less reliable), partition deed (registered, definitive), partition suit (court). Each coparcener gets share proportional to coparcenary right (equal for sons + daughters post-2005)."},
    {"id":"lg-x-114","domain":"Legal","lang":"en","topic":"Mortgage — types under TPA",
     "source":"TPA §58-104","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Simple, conditional sale, usufructuary, English, equitable (by deposit of title deeds). Most home loans = equitable mortgage. SARFAESI Act 2002 lets banks enforce without court. Borrower's right of redemption — pay off and recover."},
    {"id":"lg-x-115","domain":"Legal","lang":"en","topic":"Will — drafting essentials",
     "source":"Indian Succession Act 1925 §57-74","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Capable testator (18+, sound mind), signed in presence of 2 witnesses (who needn't know contents). No stamp duty; registration optional but recommended. Probate mandatory in Mumbai, Kolkata, Chennai presidency. Can be revoked or modified anytime."},

    # ─── Constitutional & administrative (15) ───
    {"id":"lg-x-116","domain":"Legal","lang":"en","topic":"Article 14 — equality before law",
     "source":"Constitution of India Art 14","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Equality before law + equal protection. Permits reasonable classification (intelligible differentia + rational nexus). Recent: Indra Sawhney (caste reservation), Navtej Singh Johar (LGBT decriminalisation) read Article 14 expansively."},
    {"id":"lg-x-117","domain":"Legal","lang":"en","topic":"Article 19 — six freedoms",
     "source":"Constitution Art 19","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Speech & expression, assembly, association, movement, residence, profession. Reasonable restrictions (19(2)-(6)): sovereignty, security, public order, decency, friendly relations with foreign states, defamation, incitement. Shreya Singhal (2015): struck IT Act §66A."},
    {"id":"lg-x-118","domain":"Legal","lang":"en","topic":"Article 21 — right to life and liberty",
     "source":"Constitution Art 21","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"'Procedure established by law' — Maneka Gandhi (1978) read as 'just, fair, reasonable'. Expanded to include privacy (Puttaswamy 2017), dignity, health, education, livelihood, environment, sleep, food. Most-litigated FR."},
    {"id":"lg-x-119","domain":"Legal","lang":"en","topic":"Article 21A — right to education",
     "source":"Constitution Art 21A (2002)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Right to free and compulsory education for children 6-14. Implemented by RTE Act 2009: 25% reservation in private unaided schools for EWS/disadvantaged, no detention till class 8, no capitation fee. Enforced through state authorities."},
    {"id":"lg-x-120","domain":"Legal","lang":"en","topic":"Article 25-28 — religious freedom",
     "source":"Constitution Art 25-28","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Art 25: freedom of conscience, free profession, practice, propagation of religion (subject to public order, morality, health). Art 26: right to manage religious affairs. Essential religious practices doctrine: courts decide what's 'essential' to a religion."},
    {"id":"lg-x-121","domain":"Legal","lang":"en","topic":"Article 32 — Supreme Court writs",
     "source":"Constitution Art 32","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Right to constitutional remedies — Ambedkar called it 'heart and soul'. Direct access to SC for FR enforcement. Five writs: habeas corpus, mandamus, certiorari, prohibition, quo warranto. Letter petitions accepted as PIL."},
    {"id":"lg-x-122","domain":"Legal","lang":"en","topic":"Article 226 — High Court writs",
     "source":"Constitution Art 226","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Wider than Art 32 — for FR + 'any other purpose' (any legal right). State-territorial jurisdiction. Service matters, education admission, land disputes vs state, common writ subjects. PIL doctrine expanded standing rules."},
    {"id":"lg-x-123","domain":"Legal","lang":"en","topic":"PIL — Public Interest Litigation",
     "source":"SP Gupta v UoI (1981) and successors","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Liberalised standing for matters affecting public interest. Started with prison reforms, environmental cases, bonded labour. Letter to court can be treated as petition. Caveat: rules in recent decades (Balwant Singh Chaufal 2010) check 'publicity-interest' litigation."},
    {"id":"lg-x-124","domain":"Legal","lang":"en","topic":"Article 14-16 — reservation framework",
     "source":"Constitution Art 14-16, 46, 335","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Indra Sawhney (1992): 50% reservation ceiling, creamy layer for OBC, no reservation in promotions (later modified). EWS 10% reservation (Janhit Abhiyan 2022 SC upheld). State must classify backward classes based on data, not just public perception."},
    {"id":"lg-x-125","domain":"Legal","lang":"en","topic":"Article 300A — right to property",
     "source":"Constitution Art 300A (44th Amendment)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Property no longer a fundamental right after 44th Amendment 1978 — now a constitutional/legal right under Art 300A. State can deprive property by authority of law. Compensation only if statute requires. Land acquisition acts govern process."},
    {"id":"lg-x-126","domain":"Legal","lang":"en","topic":"Land Acquisition Act 2013 — fair compensation",
     "source":"Right to Fair Compensation and Transparency in Land Acquisition Act 2013","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Replaces 1894 Act. Compensation: 2x market value urban, up to 4x rural. Social impact assessment, consent (70-80% for PPP/private). Rehabilitation and resettlement entitlements. Several states diluted via state amendments — controversial."},
    {"id":"lg-x-127","domain":"Legal","lang":"en","topic":"Election Commission of India",
     "source":"Constitution Art 324","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Three-member body (CEC + 2 ECs). Conducts Lok Sabha, Rajya Sabha, state legislature, President, VP elections. Model Code of Conduct binding post-announcement. Recent: CEC appointment process under SC scrutiny (Anoop Baranwal 2023)."},
    {"id":"lg-x-128","domain":"Legal","lang":"en","topic":"Election candidate disclosure",
     "source":"Representation of People Act 1951 · ADR judgments","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Candidate must disclose: criminal cases (Union of India v ADR 2002), assets, liabilities, educational qualifications. Conviction of 2+ years disqualifies (RP Act §8) — Lily Thomas (2013) struck down protection for sitting legislators."},
    {"id":"lg-x-129","domain":"Legal","lang":"en","topic":"Anti-defection law",
     "source":"Constitution Tenth Schedule","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Disqualifies legislators who voluntarily give up party membership or vote against whip. Earlier 1/3rd split exception removed (91st Amendment). Speaker decides — but Speaker's decision subject to judicial review (Kihoto Hollohan 1992)."},
    {"id":"lg-x-130","domain":"Legal","lang":"en","topic":"NHRC, SHRC — human rights mechanisms",
     "source":"Protection of Human Rights Act 1993","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"National Human Rights Commission (Delhi) + State HRCs investigate violations by public servants. Recommendations to government — not binding but typically followed for institutional issues. Online complaint at nhrc.nic.in. 1-year limitation."},

    # ─── Cyber & data protection (10) ───
    {"id":"lg-x-131","domain":"Legal","lang":"en","topic":"IT Act §66 — hacking",
     "source":"IT Act 2000 §66","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Unauthorised access, downloading, virus introduction etc. Up to 3 years + ₹5 lakh fine. Cognizable, bailable. Report to cybercrime.gov.in or jurisdictional police. State Cyber Cells handle investigation."},
    {"id":"lg-x-132","domain":"Legal","lang":"en","topic":"IT Act §66C — identity theft",
     "source":"IT Act 2000 §66C","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Dishonestly using another person's electronic signature, password, or unique identification. Up to 3 years + ₹1 lakh fine. Often co-charged with §66D (cheating by personation by computer)."},
    {"id":"lg-x-133","domain":"Legal","lang":"en","topic":"IT Act §66E — capturing private images",
     "source":"IT Act 2000 §66E","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Intentionally capturing, transmitting image of private area without consent. Up to 3 years + ₹2 lakh fine. Strong remedy for revenge-porn cases. Read with BNS §77 (voyeurism)."},
    {"id":"lg-x-134","domain":"Legal","lang":"en","topic":"IT Act §69 — government interception",
     "source":"IT Act 2000 §69","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Central/state government can intercept/monitor/decrypt info for sovereignty, security, public order, etc. Procedure: IT (Procedure for Monitoring) Rules 2009. PUCL v UoI safeguards apply. Recent Pegasus-spyware allegations led to SC committee."},
    {"id":"lg-x-135","domain":"Legal","lang":"en","topic":"IT Act §79 — intermediary safe harbour",
     "source":"IT Act 2000 §79","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Platforms not liable for third-party content if they observe due diligence. Shreya Singhal (2015): take-down only on court/government order. IT Rules 2021 added: significant social media intermediaries need grievance officer, compliance officer, monthly transparency reports."},
    {"id":"lg-x-136","domain":"Legal","lang":"en","topic":"DPDP Act 2023 — overview",
     "source":"Digital Personal Data Protection Act 2023","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"India's first comprehensive data protection law. Data Principal (user) rights: access, correction, erasure, grievance, nominate. Data Fiduciary (collector) obligations: notice, consent, purpose limitation, security, breach notification. Up to ₹250 crore penalty."},
    {"id":"lg-x-137","domain":"Legal","lang":"en","topic":"DPDP — consent and notice",
     "source":"DPDP Act 2023 §5-6","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Notice must be in clear plain language, in English + 22 scheduled languages. Consent must be free, specific, informed, unconditional, unambiguous, revocable. Consent for children (<18) requires verifiable parental consent."},
    {"id":"lg-x-138","domain":"Legal","lang":"en","topic":"DPDP — exemptions",
     "source":"DPDP Act 2023 §17","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"State use for prevention of offences, statistical research, performance of legal functions — exempt. Government can exempt agencies via notification (concern flagged as wide). Journalism not exempted — flagged by press bodies."},
    {"id":"lg-x-139","domain":"Legal","lang":"en","topic":"DPDP — Data Protection Board",
     "source":"DPDP Act 2023 §18-26","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Adjudicates breaches, levies penalties. Appeals to Telecom Disputes Settlement Appellate Tribunal (TDSAT). Members appointed by central government (independence concerns). Functional only after rules notified — drafts under consultation."},
    {"id":"lg-x-140","domain":"Legal","lang":"en","topic":"Cybercrime — reporting mechanisms",
     "source":"I4C · cybercrime.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"cybercrime.gov.in — central reporting portal. Financial fraud: 1930 helpline (golden hour for transaction reversal). State cyber-crime cells in major cities. Save: screenshots, transaction IDs, sender phone/email, URL of fraudulent site."},

    # ─── Consumer (5) ───
    {"id":"lg-x-141","domain":"Legal","lang":"en","topic":"Consumer Protection Act 2019 — defective product",
     "source":"CPA 2019 §2(10), §85","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Defect — fault, imperfection, shortcoming in quality, quantity, potency, purity, standard. Product liability action against manufacturer (§83), service provider, or seller (§86). Compensation includes physical injury, mental agony, harassment."},
    {"id":"lg-x-142","domain":"Legal","lang":"en","topic":"CPA 2019 — e-commerce and unfair trade practices",
     "source":"CPA 2019 + Consumer Protection (E-Commerce) Rules 2020","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"E-commerce entities must display: country of origin, seller details, return/refund/cancellation/warranty. No flash sales for fraudulent purpose. Marketplace and inventory models distinguished. CCPA can act against misleading ads, fake reviews."},
    {"id":"lg-x-143","domain":"Legal","lang":"en","topic":"E-Daakhil — online consumer complaint",
     "source":"edaakhil.nic.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Centralised online portal for consumer commission filings. Upload complaint, evidence, court fee. Hearings increasingly virtual. No advocate required (option). Filing fees: ₹100-5000 depending on claim value."},
    {"id":"lg-x-144","domain":"Legal","lang":"en","topic":"National Consumer Helpline (NCH) 1915",
     "source":"consumerhelpline.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Call/SMS 1915 or via app/WhatsApp 8800001915. Pre-litigation grievance redressal. Resolution rate ~70% without going to commission. Sectoral integrations with banking ombudsman, IRDAI ombudsman, etc."},
    {"id":"lg-x-145","domain":"Legal","lang":"en","topic":"Insurance ombudsman",
     "source":"Insurance Ombudsman Rules 2017","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"17 ombudsman offices across India for individual policyholder grievances up to ₹50 lakh. Free, fast (3 months target). Insurer's reply within 30 days required before approaching ombudsman. Online filing at cioins.co.in."},

    # ─── Senior citizens & disability (5) ───
    {"id":"lg-x-146","domain":"Legal","lang":"en","topic":"MWPSC Act 2007 — maintenance for parents",
     "source":"Maintenance and Welfare of Parents and Senior Citizens Act 2007","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Parents/grandparents can claim monthly maintenance up to ₹10,000 from children. Tribunal (SDM-level) decides in 90 days. Eviction of unmaintainable parents punishable. Senior citizens' helpline 14567 (Elderline)."},
    {"id":"lg-x-147","domain":"Legal","lang":"en","topic":"Rights of Persons with Disabilities Act 2016",
     "source":"RPwD Act 2016","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"21 disabilities covered. 4% reservation in government jobs (1% each: blind/low vision, deaf, locomotor including cerebral palsy, autism/intellectual/mental illness). 5% in higher education. Accessibility standards. State Commissioner adjudicates."},
    {"id":"lg-x-148","domain":"Legal","lang":"en","topic":"Mental Healthcare Act §115 — decriminalised suicide attempt",
     "source":"MHA 2017 §115","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Presumption of severe mental stress at time of attempt. State must provide care, treatment, rehabilitation. Effectively decriminalises despite IPC §309 still on books. Helped reduce barrier to emergency care after suicide attempts."},
    {"id":"lg-x-149","domain":"Legal","lang":"en","topic":"Equal Opportunity Cell — colleges",
     "source":"UGC guidelines","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"All universities must constitute EOC for SC/ST/OBC/disability issues — anti-discrimination, support, grievance. Many institutions have separate ICCs (POSH), Anti-Ragging Committees, EOCs. Students should know their nodal officers."},
    {"id":"lg-x-150","domain":"Legal","lang":"en","topic":"UGC anti-ragging regulations",
     "source":"UGC Regulations on Curbing the Menace of Ragging 2009","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Ragging is a cognisable offence. Anti-Ragging Squad on every campus. National Anti-Ragging Helpline 1800-180-5522 (24×7) and antiragging.in. Punishments: cancellation of admission, debarred from exams, expulsion, FIR, rustication."},

    # ─── Misc legal (50 more) ───
    {"id":"lg-x-151","domain":"Legal","lang":"en","topic":"Bharatiya Sakshya Adhiniyam (BSA) 2023 — overview",
     "source":"BSA 2023","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Replaces Indian Evidence Act 1872. Largely retains old structure. Electronic records and digital evidence treated on par with paper. Hearsay rules retained. Sections renumbered — major casebooks now use BSA references."},
    {"id":"lg-x-152","domain":"Legal","lang":"en","topic":"BSA — admissibility of electronic evidence",
     "source":"BSA 2023 §63 (replaces IEA §65B)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Electronic record admissible with §65B-style certificate from person in charge of device. Anvar P.V. v P.K. Basheer (2014 SC) made certificate mandatory. Recent rulings allowed contemporaneous certificate, not just at production."},
    {"id":"lg-x-153","domain":"Legal","lang":"en","topic":"FIR vs NCR (Non-Cognizable Report)",
     "source":"BNSS 2023 §173-175","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"FIR for cognizable offences (police can arrest without warrant — murder, rape, theft). NCR for non-cognizable (police needs court permission — defamation, simple hurt). NCR can be converted if facts reveal cognizable offence."},
    {"id":"lg-x-154","domain":"Legal","lang":"en","topic":"Zero FIR",
     "source":"Lalita Kumari v UP (2014 SC)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"FIR registered at any police station regardless of jurisdiction, then transferred to jurisdictional station. Particularly important for offences against women, accidents in transit. Useful when crime occurs while travelling, or jurisdictional station refuses."},
    {"id":"lg-x-155","domain":"Legal","lang":"en","topic":"Witness deposition — examination flow",
     "source":"BSA + BNSS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Examination-in-chief (party who called witness asks questions, usually via affidavit), cross-examination (opposite party — leading questions allowed), re-examination (clarify cross matters, no new topics). Court can recall any witness."},
    {"id":"lg-x-156","domain":"Legal","lang":"en","topic":"Hostile witness",
     "source":"BSA §164 (replaces IEA §154)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Party can with court's permission put leading/contradictory questions to its own witness. Doesn't automatically discredit testimony — court evaluates portion-by-portion. Common in criminal trials where witnesses turn under pressure."},
    {"id":"lg-x-157","domain":"Legal","lang":"en","topic":"Bail — conditions and cancellation",
     "source":"BNSS 2023 §480-487","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Common conditions: not to leave jurisdiction, surrender passport, weekly police reporting, not to contact witnesses, not to commit similar offence. Violation → bail cancellation (§487). Sureties required usually."},
    {"id":"lg-x-158","domain":"Legal","lang":"en","topic":"Trial — sessions vs magistrate court",
     "source":"BNSS 2023 First Schedule","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Offences punishable with death/life/>7 years tried by Sessions Court. <7 years by Magistrate. Summons cases (<2 years) — summary procedure. Warrant cases — formal procedure. Cheque bounce: summary trial possible."},
    {"id":"lg-x-159","domain":"Legal","lang":"en","topic":"Acquittal — government appeal",
     "source":"BNSS 2023 §417","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"State can appeal acquittal to High Court. Higher burden — High Court won't lightly interfere unless trial court's view 'palpably wrong'. Victim can appeal (BNSS provision new — earlier limited via §372 CrPC proviso)."},
    {"id":"lg-x-160","domain":"Legal","lang":"en","topic":"Right to silence & self-incrimination",
     "source":"Constitution Art 20(3)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Accused can't be compelled to be witness against self. Includes narco-analysis, polygraph (Selvi v Karnataka 2010 — only voluntary). Brain mapping similarly restricted. Doesn't bar fingerprint, voice sample, handwriting samples taking."},

    {"id":"lg-x-161","domain":"Legal","lang":"en","topic":"Trial in absentia under BNSS",
     "source":"BNSS 2023 §356","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"New provision: trial of proclaimed offender absconding 90+ days can proceed in absentia. Detailed safeguards: public notice, lawyer for defence, appeal rights. Controversial — concerns about fair trial; courts will test constitutionality."},
    {"id":"lg-x-162","domain":"Legal","lang":"en","topic":"Sentence in criminal case — types",
     "source":"BNS 2023 §4","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Death, imprisonment for life, rigorous/simple imprisonment, fine, forfeiture of property. BNS introduces community service for petty offences. Probation under Probation of Offenders Act for first-time offenders < certain category."},
    {"id":"lg-x-163","domain":"Legal","lang":"en","topic":"Probation under POA 1958",
     "source":"Probation of Offenders Act 1958","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Court may release first-time offenders (offence ≤7 years) on probation after admonition or on bond. Mandatory for offenders < 21 years (§6) — prison only if reasons recorded. Probation Officer supervises."},
    {"id":"lg-x-164","domain":"Legal","lang":"en","topic":"Compensation under §357 / §395 BNSS",
     "source":"BNSS 2023 §395-396","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Court can direct accused to pay compensation to victim (§395) in addition to fine. State victim compensation scheme (§396) supplements. NALSA Scheme for Women Victims of Sexual Assault specifies quantum."},
    {"id":"lg-x-165","domain":"Legal","lang":"en","topic":"Witness travel allowance and protection",
     "source":"State criminal rules + Witness Protection Scheme 2018","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"State rules provide TA/DA to witnesses summoned. Witness Protection Scheme 2018 covers Category A-C threats — identity concealment, security, residence change. Application via prosecutor or directly to Witness Protection Cell."},
    {"id":"lg-x-166","domain":"Legal","lang":"en","topic":"Indian Evidence — burden of proof",
     "source":"BSA 2023 §104-114","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Generally on party alleging. Criminal: prosecution beyond reasonable doubt. Civil: preponderance of probabilities. Specific presumptions shift burden (dowry death — BNS §80 + BSA §118). Statutory rebuttable presumptions in NI Act §139."},
    {"id":"lg-x-167","domain":"Legal","lang":"en","topic":"Privileged communications",
     "source":"BSA 2023 §132-139","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Marital communications (spouse can't testify, except divorce/cruelty cases). Advocate-client (§134, exception: in furtherance of crime). Without prejudice negotiations. Government records (§129). Source of journalist's information — no explicit protection."},
    {"id":"lg-x-168","domain":"Legal","lang":"en","topic":"Police custody vs judicial custody",
     "source":"BNSS 2023 §187","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Police custody (interrogation) — maximum 15 days now under BNSS. Judicial custody — magistrate's authority, held in jail. Total custody for investigation: 60 days (offence ≤10 yr) or 90 days (> 10 yr / death penalty)."},
    {"id":"lg-x-169","domain":"Legal","lang":"en","topic":"Police complaint — when station refuses",
     "source":"BNSS + Lalita Kumari","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"(1) Written complaint to Superintendent of Police. (2) Magistrate complaint u/s §175 BNSS. (3) Online via state cyber-cell or eFIR portal where available. (4) Writ petition for mandamus to register FIR (rare)."},
    {"id":"lg-x-170","domain":"Legal","lang":"en","topic":"Foreign judgment — recognition and enforcement",
     "source":"CPC 1908 §13, §44A","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"§13 lists exceptions to conclusiveness (not competent court, not on merits, founded on incorrect Indian law, etc.). §44A — direct execution as decree if from reciprocating territory (UK, Singapore, etc.). Otherwise file fresh suit on foreign judgment."},

    {"id":"lg-x-171","domain":"Legal","lang":"en","topic":"Trademark registration",
     "source":"Trade Marks Act 1999","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Application at ipindia.gov.in. Classes 1-45 (Nice Classification). Registration 10-year term, renewable. Examination + publication + opposition window (4 months) + registration. ® symbol only after registration; ™ for unregistered."},
    {"id":"lg-x-172","domain":"Legal","lang":"en","topic":"Copyright in India",
     "source":"Copyright Act 1957","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Automatic on creation of original work. Registration at copyright.gov.in optional but provides prima facie evidence. Term: author's life + 60 years. Moral rights (paternity, integrity). Fair dealing exceptions for criticism, reporting, education."},
    {"id":"lg-x-173","domain":"Legal","lang":"en","topic":"Patent process India",
     "source":"Patents Act 1970","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Application → 18-month publication → examination (request within 48 months) → grant or refusal. 20-year term from filing. Software per se not patentable; software with hardware effect may be. Compulsory licensing for public interest."},
    {"id":"lg-x-174","domain":"Legal","lang":"en","topic":"Design registration",
     "source":"Designs Act 2000","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"For aesthetic features of products. Registration 10 years extendable by 5. Must be new and not published. Different from trademark (source identifier) and patent (functional). Common for fashion, furniture, electronics."},
    {"id":"lg-x-175","domain":"Legal","lang":"en","topic":"Geographical Indications (GI)",
     "source":"GI Act 1999","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Recognises goods originating from specific area with reputation/qualities linked to origin. E.g., Darjeeling tea, Basmati rice, Banarasi sarees, Mysore silk. Registered with GI Registry Chennai. Protects producers and consumers."},
    {"id":"lg-x-176","domain":"Legal","lang":"en","topic":"Companies Act 2013 — incorporation",
     "source":"Companies Act 2013","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"SPICe+ form for company incorporation — DIN, name, MoA, AoA, PAN/TAN — all in one. Types: OPC, private, public. Minimum paid-up capital removed. Registered office, directors (min 1 for OPC, 2 for private, 3 for public, with one resident)."},
    {"id":"lg-x-177","domain":"Legal","lang":"en","topic":"Director duties — Companies Act §166",
     "source":"Companies Act 2013 §166","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Act in good faith, exercise duties with care/skill/diligence, avoid conflicts, not make undue gain. Personal liability for breach + criminal in some cases (fraud — §447). Independent directors have additional Schedule IV obligations."},
    {"id":"lg-x-178","domain":"Legal","lang":"en","topic":"NCLT — National Company Law Tribunal",
     "source":"Companies Act 2013 + IBC 2016","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Specialised tribunal for company law + insolvency. Benches in major cities. Powers: oppression-mismanagement (§241), winding up, mergers/amalgamations, compromise/arrangement, IBC proceedings. Appeals to NCLAT then SC."},
    {"id":"lg-x-179","domain":"Legal","lang":"en","topic":"IBC 2016 — corporate insolvency timeline",
     "source":"Insolvency and Bankruptcy Code 2016","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"180-day Corporate Insolvency Resolution Process (CIRP), extendable to 330 days. Committee of Creditors (financial creditors) decides resolution plan. If no plan → liquidation. Time-bound vs old SICA process which dragged decades."},
    {"id":"lg-x-180","domain":"Legal","lang":"en","topic":"IBC — personal insolvency",
     "source":"IBC 2016 Part III","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Insolvency for individuals + partnership firms. Two paths: fresh start (small debts), insolvency resolution + bankruptcy. Personal Guarantor provisions (for corporate debts) operational since Dec 2019. Not yet operational for general individuals."},

    {"id":"lg-x-181","domain":"Legal","lang":"en","topic":"SARFAESI Act — bank recovery",
     "source":"SARFAESI Act 2002","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Banks can enforce security without court — 60-day notice + take possession + auction. Borrower remedy: appeal to DRT within 45 days. Many tools used for SME defaults; OTS often negotiated. Sec 17 application is borrower's primary defence."},
    {"id":"lg-x-182","domain":"Legal","lang":"en","topic":"DRT — Debt Recovery Tribunal",
     "source":"RDDBFI Act 1993","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"For bank/FI claims ≥ ₹20 lakh. Specialised tribunal, summary procedure. Faster than civil court. Recovery Officer enforces decree by attachment, sale, arrest. Appeals: DRAT then High Court (Art 226)."},
    {"id":"lg-x-183","domain":"Legal","lang":"en","topic":"Banking ombudsman",
     "source":"RBI Integrated Ombudsman Scheme 2021","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free dispute resolution for bank service deficiency. Complaint after 30-day bank reply window. Online at cms.rbi.org.in. Award limit ₹20 lakh + ₹1 lakh compensation. Covers banks, NBFCs, prepaid instruments."},
    {"id":"lg-x-184","domain":"Legal","lang":"en","topic":"NSE/BSE listed company obligations",
     "source":"SEBI LODR Regulations 2015","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Quarterly financial results within 45 days. Material event disclosure within 30 minutes. Independent directors ≥ 1/3 board (1/2 for top 1000). Whistleblower mechanism, Audit Committee, Nomination & Remuneration Committee mandatory."},
    {"id":"lg-x-185","domain":"Legal","lang":"en","topic":"Securities fraud — SEBI powers",
     "source":"SEBI Act 1992 + PFUTP Regulations","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"SEBI investigates insider trading, market manipulation, fraudulent IPO. Penalties: disgorgement of gains, ban from market, ₹25 lakh - ₹25 crore. Settlement scheme available. Appeals to SAT then Supreme Court."},
    {"id":"lg-x-186","domain":"Legal","lang":"en","topic":"Money Laundering — PMLA 2002",
     "source":"Prevention of Money Laundering Act 2002","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Predicate offence required (Scheduled offences). ED investigates. ECIR (Enforcement Case Information Report) not equivalent to FIR — SC clarified accused has limited rights at investigation stage. Bail under §45 reverse burden — twin tests."},
    {"id":"lg-x-187","domain":"Legal","lang":"en","topic":"FEMA — foreign exchange",
     "source":"Foreign Exchange Management Act 1999","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Civil law (unlike erstwhile FERA — criminal). Liberalised Remittance Scheme: $250,000/year for resident individuals (education, travel, investment). FCNR/NRE/NRO accounts for NRIs. Violation → compounding or penalty up to 3x amount."},
    {"id":"lg-x-188","domain":"Legal","lang":"en","topic":"Black Money Act 2015",
     "source":"Black Money (Undisclosed Foreign Income and Assets) Act 2015","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Undisclosed foreign income/assets → 30% tax + 90% penalty (total 120%). Prosecution up to 10 years rigorous imprisonment. Disclosure schemes have closed; voluntary correction in regular ITR is limited."},
    {"id":"lg-x-189","domain":"Legal","lang":"en","topic":"NDPS Act — drug offences",
     "source":"Narcotic Drugs and Psychotropic Substances Act 1985","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Strict liability for commercial quantity (rigorous imprisonment 10-20 years + ₹1-2 lakh fine). Small quantity — up to 1 year. Section 50 search procedure (option of magistrate/gazetted officer) mandatory — strict compliance."},
    {"id":"lg-x-190","domain":"Legal","lang":"en","topic":"Environment Protection — common claims",
     "source":"Environment Protection Act 1986 + NGT Act 2010","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pollution complaints to State Pollution Control Board. Persistent issues to NGT (National Green Tribunal). Air, water, noise, hazardous waste regulations under EPA 1986 rules. PIL also a route — NGT often more effective for specific cases."},

    # ─── More family/personal (10) ───
    {"id":"lg-x-191","domain":"Legal","lang":"en","topic":"Inter-faith marriage challenges",
     "source":"Special Marriage Act 1954 + State Anti-Conversion Laws","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"SMA 1954 — 30-day notice + public objection process. Anti-conversion laws in UP/UK/MP/HP/Gujarat/Karnataka etc. require declaration to DM 60 days before conversion-for-marriage. Constitutional validity under SC challenge."},
    {"id":"lg-x-192","domain":"Legal","lang":"en","topic":"Marriage registration — mandatory?",
     "source":"Seema v Ashwani Kumar (2006 SC)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Marriage registration made compulsory across India. State rules vary on process. Non-registration doesn't invalidate marriage but causes issues with visa, passport, joint property, succession. Online registration in most states."},
    {"id":"lg-x-193","domain":"Legal","lang":"en","topic":"Live-in relationship — legal status",
     "source":"Indra Sarma v VKV Sarma (2013 SC)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Live-in not illegal between consenting adults. PWDVA 2005 covers women in 'relationship in nature of marriage' — maintenance, residence rights. Child born to live-in considered legitimate (Bharatha Matha 2010). Some states' registration push contested."},
    {"id":"lg-x-194","domain":"Legal","lang":"en","topic":"Surrogacy in India",
     "source":"Surrogacy (Regulation) Act 2021","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Only altruistic surrogacy (no commercial). Intending couple: Indian, married 5+ years, infertility certificate. Single women now permitted via amendment 2023 (widowed/divorced 35-45 yr). Surrogate: close relative, married, has own child."},
    {"id":"lg-x-195","domain":"Legal","lang":"en","topic":"ART Act 2021 — assisted reproduction",
     "source":"Assisted Reproductive Technology (Regulation) Act 2021","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Regulates ART clinics + sperm/egg banks. Mandatory registration with National Registry. Donor consent + child's rights protected. Single women + cohabiting couples now permitted access (different from earlier). Sex-selective ART banned."},
    {"id":"lg-x-196","domain":"Legal","lang":"en","topic":"MTP Act — abortion",
     "source":"Medical Termination of Pregnancy Act 1971 (amended 2021)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Up to 20 weeks — opinion of one RMP. 20-24 weeks — opinion of two RMPs (only for specific categories: rape survivors, minors, disabled women etc.). Beyond 24 weeks — medical board for fetal abnormality. Confidentiality (§5A) added 2021."},
    {"id":"lg-x-197","domain":"Legal","lang":"en","topic":"PCPNDT — sex selection ban",
     "source":"Pre-Conception and Pre-Natal Diagnostic Techniques Act 1994","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Prenatal sex determination is criminal. Ultrasound centres must register, no sex disclosure. Penalty: 3 yr first offence, 5 yr repeat + ₹50K/100K. Despite the law, sex ratio at birth continues to worry (ANC ratio reports)."},
    {"id":"lg-x-198","domain":"Legal","lang":"en","topic":"Foreign marriage — registration",
     "source":"Foreign Marriage Act 1969","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Indian citizen marrying foreigner abroad — can register with Indian mission. Marriage Officer issues certificate. For Indian recognition of foreign-solemnised marriage, file under FMA 1969 within 6 months."},
    {"id":"lg-x-199","domain":"Legal","lang":"en","topic":"OCI — Overseas Citizen of India",
     "source":"Citizenship Act 1955","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Foreign citizens of Indian origin — multi-entry, multi-purpose lifelong visa. Not citizenship — no vote, no public office. PIO card merged with OCI 2015. Recent restrictions: research, journalism, religious activity need permission."},
    {"id":"lg-x-200","domain":"Legal","lang":"en","topic":"Passport — issuance and seizure",
     "source":"Passports Act 1967","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Right to travel a fundamental right (Maneka Gandhi 1978). Passport authority may refuse/impound on specified grounds — court can review. Police clearance required for fresh adult passport in most cases. Tatkal scheme for urgent need."},

    # ─── Hindi versions of common queries (15) ───
    {"id":"lg-x-201","domain":"Legal","lang":"hi","topic":"FIR दर्ज न हो तो क्या करें (Hindi)",
     "source":"BNSS 2023 + Lalita Kumari","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"पुलिस FIR दर्ज न करे तो: (1) Superintendent of Police को लिखित शिकायत (BNSS §173(4))। (2) Magistrate के पास §175(3) BNSS के तहत complaint। (3) State Cyber-Cell या ऑनलाइन eFIR portal। (4) NHRC/SHRC में शिकायत।"},
    {"id":"lg-x-202","domain":"Legal","lang":"hi","topic":"उपभोक्ता शिकायत कैसे करें (Hindi)",
     "source":"Consumer Protection Act 2019 · E-Daakhil","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"पहले विक्रेता को लिखित शिकायत भेजें। समाधान न मिले तो: National Consumer Helpline 1915 पर कॉल या edaakhil.nic.in पर ऑनलाइन शिकायत दर्ज करें। ₹50 लाख तक — District Commission। 2 साल की limitation है।"},
    {"id":"lg-x-203","domain":"Legal","lang":"hi","topic":"तलाक के तरीके (Hindi)",
     "source":"Hindu Marriage Act 1955","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"पारस्परिक सहमति (§13B HMA) — दोनों राज़ी, 1 साल अलग रहे। 6 महीने cooling period। समय: 6-18 महीने। विवादित: क्रूरता, परित्याग 2+ साल, धर्मांतरण आदि (§13(1))। मध्यस्थता पहले होती है।"},
    {"id":"lg-x-204","domain":"Legal","lang":"hi","topic":"घरेलू हिंसा — कानूनी सुरक्षा (Hindi)",
     "source":"PWDVA 2005","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"PWDVA 2005 के तहत: सुरक्षा आदेश, निवास आदेश (घर में रहने का अधिकार), monetary relief, बच्चों की custody, मुआवज़ा। Magistrate के सामने Protection Officer के माध्यम से application। NCW 7827170170, सखी One Stop Centre 181।"},
    {"id":"lg-x-205","domain":"Legal","lang":"hi","topic":"मकान मालिक बिना नोटिस बेदखल कर रहा है (Hindi)",
     "source":"TPA §106 + state Rent Control Acts","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"मासिक किराए पर 15 दिन का लिखित नोटिस (TPA §106) कानूनी ज़रूरत। ताला बदलना, बिजली-पानी काटना — IPC §441 के तहत अपराध। पुलिस में शिकायत + civil court में injunction। DLSA से मुफ़्त वकील मदद।"},
    {"id":"lg-x-206","domain":"Legal","lang":"hi","topic":"मुफ़्त कानूनी सहायता (Hindi)",
     "source":"Legal Services Authorities Act 1987","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"महिलाएँ, SC/ST, बच्चे, विकलांग, ₹3-9 लाख से कम आय वाले — मुफ़्त कानूनी सहायता के लिए पात्र। आवेदन: DLSA (ज़िला), SLSA (राज्य), NALSA (केंद्रीय)। मुफ़्त वकील, court fee, मध्यस्थता।"},
    {"id":"lg-x-207","domain":"Legal","lang":"hi","topic":"साइबर अपराध की शिकायत (Hindi)",
     "source":"cybercrime.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"वित्तीय धोखाधड़ी: 1930 हेल्पलाइन पर तुरंत कॉल (golden hour में पैसा वापस होने की संभावना)। अन्य साइबर अपराध: cybercrime.gov.in पर ऑनलाइन शिकायत। Screenshots, transaction IDs, suspect का नंबर/ईमेल सहेज लें।"},
    {"id":"lg-x-208","domain":"Legal","lang":"hi","topic":"दहेज विरोध कानून (Hindi)",
     "source":"Dowry Prohibition Act 1961 + BNS §80, §85-86","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"दहेज लेना/देना/माँगना — 5 साल जेल + जुर्माना। दहेज से मौत (BNS §80) — 7 साल से उम्रकैद। पति-ससुराल वालों की क्रूरता (BNS §85-86) — 3 साल। महिला हेल्पलाइन 181, NCW 7827170170।"},
    {"id":"lg-x-209","domain":"Legal","lang":"hi","topic":"बेटी का संपत्ति में हिस्सा (Hindi)",
     "source":"Hindu Succession Act 2005 amendment","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"2005 संशोधन के बाद बेटियाँ भी coparcener हैं — पुत्रों के बराबर पैतृक संपत्ति में हिस्सा। Vineeta Sharma (2020 SC): यह अधिकार जन्म से है, पिता के 9 सितंबर 2005 को जीवित होने की शर्त नहीं।"},
    {"id":"lg-x-210","domain":"Legal","lang":"hi","topic":"नौकरी से अचानक निकाला गया (Hindi)",
     "source":"IDA 1947 + Code on Industrial Relations","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"कारखाने/संस्थान में retrenchment के लिए: 1 महीने का नोटिस + 15 दिनों की वेतन × पूरे वर्ष retrenchment compensation। 100+ कर्मचारियों वाले संस्थान में सरकार की अनुमति ज़रूरी (IDA §25N)। श्रम न्यायालय में अपील।"},
    {"id":"lg-x-211","domain":"Legal","lang":"hi","topic":"बुज़ुर्ग माता-पिता को maintenance (Hindi)",
     "source":"MWPSC Act 2007","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"माता-पिता बच्चों से ₹10,000/माह तक maintenance माँग सकते हैं। SDM के सामने Tribunal में आवेदन — 90 दिनों में फैसला। बेदखली पर सज़ा। Elderline 14567 पर मदद उपलब्ध।"},
    {"id":"lg-x-212","domain":"Legal","lang":"hi","topic":"बच्चे के साथ POCSO अपराध की शिकायत (Hindi)",
     "source":"POCSO Act 2012","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"बच्चे (<18) के साथ यौन शोषण: तुरंत 1098 (Childline) या स्थानीय पुलिस। POCSO अनिवार्य रूप से दर्ज करनी होगी। NCPCR की e-Box (pocsoebox.nic.in) पर भी शिकायत। Special POCSO court — 1 साल में सुनवाई पूरी होनी चाहिए।"},
    {"id":"lg-x-213","domain":"Legal","lang":"hi","topic":"सरकारी अधिकारी रिश्वत माँग रहा (Hindi)",
     "source":"Prevention of Corruption Act 1988","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Central Vigilance Commission (cvc.gov.in) में online complaint। State Lokayukta (राज्य) में भी। CBI Anti-Corruption Branch trap लगाती है — रिश्वत देने से पहले शिकायत करें। निडर रहें — POCA §17 informer protection देता है।"},
    {"id":"lg-x-214","domain":"Legal","lang":"hi","topic":"मानहानि का केस (Hindi)",
     "source":"BNS §356 + civil defamation","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"BNS §356 के तहत criminal complaint — 2 साल तक की जेल + जुर्माना। साथ ही civil court में हानि के लिए case कर सकते हैं। सच्चाई (अगर public interest में) और निष्पक्ष टिप्पणी मुख्य बचाव। Online defamation में IT Act भी लागू।"},
    {"id":"lg-x-215","domain":"Legal","lang":"hi","topic":"वसीयत कैसे बनाएँ (Hindi)",
     "source":"Indian Succession Act 1925","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"बालिग (18+) सही दिमाग का व्यक्ति। 2 गवाहों के सामने हस्ताक्षर। Stamp duty नहीं लगती; registration optional लेकिन सुझावित। मुंबई/कोलकाता/चेन्नई में probate ज़रूरी। कभी भी बदली/रद्द की जा सकती है।"},

    # ─── German legal (10) ───
    {"id":"lg-x-216","domain":"Legal","lang":"de","topic":"Mietrecht — Kündigung durch Vermieter (German)",
     "source":"BGB §573","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Vermieter braucht berechtigtes Interesse: Eigenbedarf, schuldhafte Vertragsverletzung (z. B. Mietrückstand), wirtschaftliche Verwertung. Kündigungsfristen: 3 Monate (Mietdauer <5 J), 6 Monate (5-8 J), 9 Monate (>8 J). Schriftform mit Begründung Pflicht."},
    {"id":"lg-x-217","domain":"Legal","lang":"de","topic":"Mietkaution Höhe und Rückgabe (German)",
     "source":"BGB §551","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Maximal 3 Nettokaltmieten. Vermieter muss Kaution verzinslich anlegen. Rückzahlung in angemessener Frist (3-6 Monate) nach Auszug, abzüglich berechtigter Forderungen (Mietrückstände, Schäden über normale Abnutzung)."},
    {"id":"lg-x-218","domain":"Legal","lang":"de","topic":"Arbeitsvertrag — Kündigung durch Arbeitgeber (German)",
     "source":"KSchG","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"In Betrieben >10 Vollzeit-AN gilt Kündigungsschutzgesetz nach 6 Monaten. Sozial gerechtfertigt nötig (personenbedingt, verhaltensbedingt, betriebsbedingt). Schriftform Pflicht (§623 BGB). Kündigungsschutzklage binnen 3 Wochen beim Arbeitsgericht."},
    {"id":"lg-x-219","domain":"Legal","lang":"de","topic":"Elternzeit und Elterngeld (German)",
     "source":"BEEG","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Bis zu 3 Jahre Elternzeit pro Elternteil (24 Monate übertragbar bis zum 8. Geburtstag). Elterngeld 12+2 Monate, Elterngeld Plus bis 24 Monate. Antrag bei Elterngeldstelle. Kündigungsschutz während Elternzeit + 8 Wochen vor Antritt."},
    {"id":"lg-x-220","domain":"Legal","lang":"de","topic":"Bürgergeld — Beantragung (German)",
     "source":"SGB II","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Erwerbsfähige zwischen 15 und Renteneintritt mit Wohnsitz Deutschland und Hilfebedürftigkeit. Antrag beim Jobcenter. Regelbedarf 2024: 563 € (alleinstehend). Miete + Heizung extra wenn angemessen. Pauschalen für Kinder."},
    {"id":"lg-x-221","domain":"Legal","lang":"de","topic":"Verbraucherrecht — Widerruf Online-Kauf (German)",
     "source":"BGB §355","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"14 Tage Widerrufsrecht bei Fernabsatzverträgen (Online, Telefon, Post). Frist beginnt mit Erhalt der Ware. Keine Begründung nötig. Verkäufer muss Geld binnen 14 Tagen zurückzahlen. Rücksendekosten meist beim Käufer."},
    {"id":"lg-x-222","domain":"Legal","lang":"de","topic":"Beratungshilfe und Prozesskostenhilfe (German)",
     "source":"BerHG + ZPO §114","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Beratungshilfe: für außergerichtliche Rechtsberatung bei geringem Einkommen — beim Amtsgericht beantragen (Wohnsitz). 15 € Eigenanteil. Prozesskostenhilfe (PKH): für Gerichtsverfahren, je nach Einkommen ratenlos oder mit Raten."},
    {"id":"lg-x-223","domain":"Legal","lang":"de","topic":"Strafanzeige erstatten (German)",
     "source":"StPO §158","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Bei jeder Polizeidienststelle, Staatsanwaltschaft, online über Internetwache der Landespolizei. Mündlich oder schriftlich. Personalausweis mitbringen. Bei Antragsdelikten zusätzlich Strafantrag binnen 3 Monaten."},
    {"id":"lg-x-224","domain":"Legal","lang":"de","topic":"DSGVO — Betroffenenrechte (German)",
     "source":"DSGVO","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Auskunft (Art 15), Berichtigung (Art 16), Löschung (Art 17), Einschränkung (Art 18), Datenübertragbarkeit (Art 20), Widerspruch (Art 21). Antrag formfrei beim Verantwortlichen, Beantwortung binnen 1 Monat. Beschwerde bei Landesdatenschutzbeauftragten."},
    {"id":"lg-x-225","domain":"Legal","lang":"de","topic":"Häusliche Gewalt — Gewaltschutzgesetz (German)",
     "source":"GewSchG","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Gericht kann Täter Wohnungsbetretungsverbot, Kontaktverbot, Annäherungsverbot erteilen — auch ohne mündliche Verhandlung im Eilverfahren. Hilfetelefon 08000 116 016 (24/7, mehrsprachig). Polizei 110."},

    # ─── More legal misc (25) ───
    {"id":"lg-x-226","domain":"Legal","lang":"en","topic":"Anti-conversion laws — state by state",
     "source":"State-level Acts","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"UP (UP Prohibition of Unlawful Conversion of Religion Ordinance 2020), MP, HP, Uttarakhand, Gujarat, Karnataka, Haryana, Jharkhand. Require declaration 30-60 days before conversion. Burden of proof on accused. Constitutional validity under SC challenge."},
    {"id":"lg-x-227","domain":"Legal","lang":"en","topic":"Foreigners Act 1946 — visa overstay",
     "source":"Foreigners Act 1946","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Overstay beyond visa: penalty up to ₹500/day + possible imprisonment. Exit permit from FRRO required to leave. Voluntary reporting before being caught reduces penalty. Online visa extension via Bureau of Immigration for some categories."},
    {"id":"lg-x-228","domain":"Legal","lang":"en","topic":"Citizenship Act — naturalisation",
     "source":"Citizenship Act 1955","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"By birth (limited post-1987), descent, registration (specified categories incl spouse of citizen 7 yr), naturalisation (12 yr residence + good conduct). CAA 2019 added expedited route for specified communities from Pakistan/Bangladesh/Afghanistan — controversial."},
    {"id":"lg-x-229","domain":"Legal","lang":"en","topic":"Aadhaar Act 2016 — limits",
     "source":"Aadhaar Act 2016 + Puttaswamy II (2018)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"SC limited Aadhaar to LPG/PDS/subsidies + IT purposes. Cannot insist for school admission, bank account, mobile SIM (struck down). Private use only with voluntary consent under DPDP Act 2023 framework."},
    {"id":"lg-x-230","domain":"Legal","lang":"en","topic":"Right to Privacy (Puttaswamy)",
     "source":"K.S. Puttaswamy v UoI (2017)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"9-judge SC bench: privacy a FR under Art 21. Three-fold test: legality, legitimate state interest, proportionality. Foundational for DPDP, Aadhaar limits, decriminalisation of consensual relations, LGBT rights."},
    {"id":"lg-x-231","domain":"Legal","lang":"en","topic":"Sec 377 — current status",
     "source":"Navtej Singh Johar v UoI (2018)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Consensual same-sex sexual acts between adults decriminalised. Non-consensual acts and acts with minors remain punishable (now under POCSO + BNS). Marriage equality + adoption rights still pending Parliament/court."},
    {"id":"lg-x-232","domain":"Legal","lang":"en","topic":"Transgender Persons Act 2019",
     "source":"Transgender Persons (Protection of Rights) Act 2019","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Self-identification through application to DM. National Council for Transgender Persons. Reservation in education, employment debated — Act doesn't explicitly mandate. Aftermath of NALSA (2014) judgment — some provisions criticised by community as dilution."},
    {"id":"lg-x-233","domain":"Legal","lang":"en","topic":"Speed of court process — common delays",
     "source":"Indian Judicial Statistics","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Average case pendency at subordinate court: 3-5 yr. High Court: 5-10 yr. SC: 1-3 yr. Reasons: vacancies, frequent adjournments, complex written procedure, appeals. Reforms: case management, virtual hearings (Covid catalysed), e-filing."},
    {"id":"lg-x-234","domain":"Legal","lang":"en","topic":"Mandatory court mediation",
     "source":"Commercial Courts Act 2015 §12A","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pre-institution mediation mandatory in commercial disputes (except urgent injunction). SC in Patil Automation (2022) held this jurisdictional. Mediation through DLSA/SLSA. Mediated agreement enforceable as decree."},
    {"id":"lg-x-235","domain":"Legal","lang":"en","topic":"Class action — securities",
     "source":"Companies Act 2013 §245","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Members/depositors can file class action before NCLT. Threshold: 100 members or 10% of total. Cause: oppression, mismanagement, fraud. Awards bind all similarly-situated. Limited use so far compared to US class action."},

    {"id":"lg-x-236","domain":"Legal","lang":"en","topic":"Public servants — Section 197 BNSS",
     "source":"BNSS 2023 §218","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Prior sanction required to prosecute public servants for acts done in discharge of official duty. Government decides sanction within 4 months (deemed grant if no decision). Often used to shield police misconduct — sanction refusal can be challenged in High Court."},
    {"id":"lg-x-237","domain":"Legal","lang":"en","topic":"AFSPA — Armed Forces Special Powers Act",
     "source":"AFSPA 1958","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"In 'disturbed areas' (NE, J&K historically), armed forces have powers to use force (including lethal), arrest without warrant, search without warrant. Prior sanction needed for prosecution. Reduced areas of applicability in recent years; long-standing repeal demand."},
    {"id":"lg-x-238","domain":"Legal","lang":"en","topic":"Sedition replacement (BNS §152)",
     "source":"BNS 2023 §152","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Replaces IPC §124A (sedition). Criminalises acts endangering sovereignty, unity, integrity of India. Punishment up to life imprisonment. Critics flag broad language could continue suppression of dissent like erstwhile sedition law."},
    {"id":"lg-x-239","domain":"Legal","lang":"en","topic":"UAPA — terror/national security cases",
     "source":"Unlawful Activities (Prevention) Act 1967","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Wide net — terrorism, secession, individual terrorist designation. 180-day judicial custody possible. Bail under §43D(5) — court must record satisfaction accused not guilty (reverse burden). Constitutional challenge to §43D(5) pending."},
    {"id":"lg-x-240","domain":"Legal","lang":"en","topic":"Forest Rights Act 2006",
     "source":"FRA 2006","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Recognises rights of Scheduled Tribes + Other Traditional Forest Dwellers (3+ generations residence) over forest land cultivated/used pre-Dec 2005. Individual + community rights. Gram Sabha primary authority for verification. Implementation uneven across states."},
    {"id":"lg-x-241","domain":"Legal","lang":"en","topic":"Land tenure types — agricultural",
     "source":"State Land Reforms Acts","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Bhumiswami / Pattadar (full owner), Bhumidhar / Sirdar (heritable tenants in UP), Adhiwasi (occupant), Tenant-at-will (low security). Each state has distinct categories. Land records modernisation (DILRMP) digitising titles."},
    {"id":"lg-x-242","domain":"Legal","lang":"en","topic":"Stamp duty exemption — women buyers",
     "source":"State Stamp Acts","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Maharashtra, Punjab, Delhi, Haryana, Karnataka, UP among states giving 1-2% reduced stamp duty when property registered in woman's name. Limits vary (urban/rural, residential, value cap). Major incentive to register property in spouse/daughter's name."},
    {"id":"lg-x-243","domain":"Legal","lang":"en","topic":"NRI property transactions",
     "source":"FEMA + RBI Master Direction","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"NRIs/PIOs can acquire residential/commercial property (not agricultural/farmhouse/plantation). Funds via NRE/NRO/FCNR. Sale proceeds repatriable up to $1 million/year. Capital gains taxed. Power of Attorney commonly used."},
    {"id":"lg-x-244","domain":"Legal","lang":"en","topic":"GST registration — when mandatory",
     "source":"CGST Act §22","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Turnover > ₹40 lakh (goods) / ₹20 lakh (services). Inter-state supply, e-commerce sellers, casual taxable persons — registration regardless of threshold. NIL turnover registration possible. Composition scheme up to ₹1.5 cr (goods)."},
    {"id":"lg-x-245","domain":"Legal","lang":"en","topic":"Public Distribution System (PDS) entitlements",
     "source":"NFSA 2013","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"AAY (Antyodaya): 35 kg per family/month. PHH (Priority Household): 5 kg per person/month. Prices: ₹3 (rice), ₹2 (wheat), ₹1 (coarse grains). Ration card application via fcs portal of state. Grievance redressal in District Grievance Redressal Officer."},

    {"id":"lg-x-246","domain":"Legal","lang":"en","topic":"FCRA — foreign donations to NGOs",
     "source":"Foreign Contribution (Regulation) Act 2010","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"NGOs receiving foreign donation need FCRA registration (5 yr term) or prior permission. SBI New Delhi branch designated account. 2020 amendment restricted re-granting and capped admin costs at 20%. Several NGOs lost registration in recent years."},
    {"id":"lg-x-247","domain":"Legal","lang":"en","topic":"Section 138 NI Act — limitation",
     "source":"NI Act 1881 §142","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Complaint must be filed within 30 days from expiry of 15-day notice period. Magistrate can take cognizance only of complaint, not police FIR. Summary trial under §143. Recent: presumption of issuance for consideration affirmed SC Rangappa 2010."},
    {"id":"lg-x-248","domain":"Legal","lang":"en","topic":"E-stamping — modern stamp duty payment",
     "source":"Indian Stamp (Collection of Stamp-duty through e-Stamping) Rules","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Replaced physical stamp paper. Pay online via SHCIL (Stock Holding Corp). Receive e-stamp certificate with UIN — verifiable on portal. Available across most states for varied document types."},
    {"id":"lg-x-249","domain":"Legal","lang":"en","topic":"Online court (eCourts)",
     "source":"eCommittee · Supreme Court of India","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"ecourts.gov.in for case status, judgments, court fee payment. Virtual hearings continued post-Covid. e-Filing portal for new cases. Service of summons via SMS/email permitted in many courts. Faceless income-tax appeals fully online."},
    {"id":"lg-x-250","domain":"Legal","lang":"en","topic":"Legal Aid Clinic — universities",
     "source":"NALSA Legal Aid Clinic Scheme","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Most National Law Universities + many private/state law schools have legal aid clinics. Free assistance for eligible persons. Supervised by faculty + practising lawyers. Useful for routine matters like FIR drafting, RTI applications, consumer complaints."},

    # ═════════════════════════════════════════════════════════════════════
    # GOVERNMENT SCHEMES — ~200 chunks
    # ═════════════════════════════════════════════════════════════════════

    # ─── Health-sector schemes (15) ───
    {"id":"gs-x-01","domain":"Government Schemes","lang":"en","topic":"PM-JAY — empanelled hospital network",
     "source":"NHA · pmjay.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"30,000+ empanelled hospitals (public + private) across India. Cashless treatment via Ayushman card. Check empanelled list on pmjay.gov.in / Ayushman Bharat PMJAY app. ABHA (health account ID) recommended for portable records."},
    {"id":"gs-x-02","domain":"Government Schemes","lang":"en","topic":"PMJAY — listed treatment packages",
     "source":"NHA Health Benefit Package 2022","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"1,950+ procedure packages across 27 specialities. Covers ICU, surgery, cancer, dialysis, cardiac, neonatal, mental health. Daycare procedures included. Pre-existing conditions covered from Day 1. ₹5 lakh family floater/year."},
    {"id":"gs-x-03","domain":"Government Schemes","lang":"en","topic":"Mission Indradhanush — immunisation",
     "source":"Ministry of Health and Family Welfare","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Targets children up to 2 years + pregnant women for full immunisation. 12 diseases covered. IMI 5.0 launched 2023. Free at all government health facilities. Find centres via U-WIN portal or ASHA worker."},
    {"id":"gs-x-04","domain":"Government Schemes","lang":"en","topic":"JSY — Janani Suraksha Yojana",
     "source":"MoHFW","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Cash assistance for institutional delivery — ₹1,400 rural / ₹1,000 urban (LPS), ₹700 rural / ₹600 urban (HPS). Eligibility: BPL, SC/ST in LPS; <19yr or 2+ live births similar in HPS. Apply via ASHA / ANM. Linked with JSSK (cashless free delivery)."},
    {"id":"gs-x-05","domain":"Government Schemes","lang":"en","topic":"JSSK — Janani Shishu Suraksha Karyakram",
     "source":"MoHFW","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free delivery (including C-section), drugs, diagnostics, blood, diet, transport at public health facilities. Free treatment for sick newborns up to 30 days, extended to 1 year. Universal — no eligibility criteria."},
    {"id":"gs-x-06","domain":"Government Schemes","lang":"en","topic":"PMMVY — Pradhan Mantri Matru Vandana Yojana",
     "source":"WCD Ministry","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹5,000 cash benefit for first living child in 3 instalments to pregnant/lactating women (excluding government employees). Second child benefit ₹6,000 if girl child. Apply at Anganwadi Centre. Aadhaar + bank account required."},
    {"id":"gs-x-07","domain":"Government Schemes","lang":"en","topic":"RBSK — Rashtriya Bal Swasthya Karyakram",
     "source":"MoHFW","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free health screening for children 0-18 years in Anganwadis and schools. Covers 4Ds: Defects at birth, Diseases, Deficiencies, Developmental delays. Referral and treatment up to tertiary care free."},
    {"id":"gs-x-08","domain":"Government Schemes","lang":"en","topic":"PMBJP — Pradhan Mantri Bhartiya Janaushadhi Pariyojana",
     "source":"BPPI","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Generic medicines at 50-90% cheaper than branded. 12,000+ Janaushadhi Kendras across India. 1,800+ medicines + 285 surgicals. Find nearest centre on Janaushadhi app or janaushadhi.gov.in."},
    {"id":"gs-x-09","domain":"Government Schemes","lang":"en","topic":"NHM — National Health Mission",
     "source":"MoHFW","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Flagship programme covering NRHM (rural) and NUHM (urban). Strengthens primary/secondary public health system. ASHA workers, Health & Wellness Centres, free essential medicines, telemedicine via eSanjeevani."},
    {"id":"gs-x-10","domain":"Government Schemes","lang":"en","topic":"eSanjeevani — national telemedicine",
     "source":"MoHFW · esanjeevani.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free OPD consultation by government doctors via app/web. Also enables doctor-to-doctor consultation from Health & Wellness Centre to specialist. Useful for rural and remote populations. ABHA integration available."},
    {"id":"gs-x-11","domain":"Government Schemes","lang":"en","topic":"NPCB — National Programme for Control of Blindness",
     "source":"MoHFW","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free cataract surgery, school eye screening, treatment of refractive errors, donation of spectacles. District blindness control units coordinate with NGOs and hospitals. Major in elderly cataract burden."},
    {"id":"gs-x-12","domain":"Government Schemes","lang":"en","topic":"Hridyam — free heart surgery for children Kerala",
     "source":"Kerala Health Department","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free cardiac surgery for children under 18 with congenital heart disease in Kerala. Empanelled hospitals across state. Hridyam helpline 0471-2552324. Similar state-led programmes: Tamil Nadu CMCHIS, Karnataka Vajpayee Arogyashree."},
    {"id":"gs-x-13","domain":"Government Schemes","lang":"en","topic":"NPCDCS — non-communicable diseases programme",
     "source":"MoHFW","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Population-based screening and management of diabetes, hypertension, common cancers (oral, breast, cervical) for 30+ adults at Health & Wellness Centres. Free diagnostics and first-line medicines."},
    {"id":"gs-x-14","domain":"Government Schemes","lang":"en","topic":"NTEP — TB elimination programme",
     "source":"Central TB Division · MoHFW","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free TB diagnosis, treatment, drugs at all government and many empanelled private facilities. Nikshay Poshan Yojana: ₹500/month nutritional support to TB patients. Goal: eliminate by 2025 (set ambitious, lagging)."},
    {"id":"gs-x-15","domain":"Government Schemes","lang":"en","topic":"Pradhan Mantri Surakshit Matritva Abhiyan",
     "source":"MoHFW","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free antenatal check-ups by gynaecologist on 9th of every month at all public health facilities. Identifies high-risk pregnancies. Volunteer private practitioners encouraged. Reduces maternal/infant mortality."},

    # ─── Agriculture/farmer schemes (15) ───
    {"id":"gs-x-16","domain":"Government Schemes","lang":"en","topic":"PM Fasal Bima Yojana",
     "source":"Ministry of Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Crop insurance: farmer pays 2% (kharif), 1.5% (rabi), 5% (commercial/horticulture). Rest by government. Covers pre-sowing to post-harvest losses. Voluntary for non-loanee farmers from 2020. Apply via CSC, bank, online."},
    {"id":"gs-x-17","domain":"Government Schemes","lang":"en","topic":"Kisan Credit Card (KCC)",
     "source":"NABARD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Short-term credit for crop production at 7% interest (3% subvention for timely repayment = 4% effective). Up to ₹3 lakh. Now extended to fisheries, animal husbandry. Apply via bank with land records. PM-KISAN beneficiaries get streamlined process."},
    {"id":"gs-x-18","domain":"Government Schemes","lang":"en","topic":"Soil Health Card scheme",
     "source":"Department of Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free soil testing every 3 years; report includes 12 parameters (N, P, K, pH, EC, OC, S, Zn, B, Fe, Mn, Cu) and crop-wise fertiliser recommendations. Application via Krishi Vigyan Kendra or block agriculture office."},
    {"id":"gs-x-19","domain":"Government Schemes","lang":"en","topic":"PMKSY — Pradhan Mantri Krishi Sinchayee Yojana",
     "source":"Ministry of Jal Shakti","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"'Per Drop More Crop'. Subsidy for drip and sprinkler irrigation: 55% small/marginal, 45% other (varies state). Up to 5 hectares. Apply via state horticulture mission portal. Major water-saving scheme."},
    {"id":"gs-x-20","domain":"Government Schemes","lang":"en","topic":"PMFME — Food Processing Enterprises",
     "source":"Ministry of Food Processing Industries","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Credit-linked subsidy 35% (max ₹10 lakh) to micro-enterprises in food processing. Branding and marketing support for FPOs/SHGs. 'One District One Product' approach. Apply via pmfme.mofpi.gov.in."},
    {"id":"gs-x-21","domain":"Government Schemes","lang":"en","topic":"NMOOP — National Mission on Oilseeds and Oil Palm",
     "source":"Ministry of Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Subsidies for oilseed cultivation, oil palm plantation, technology adoption. Higher subsidy for NE states + tribal areas. Reduce edible oil import dependence. State agriculture departments implement."},
    {"id":"gs-x-22","domain":"Government Schemes","lang":"en","topic":"AIF — Agriculture Infrastructure Fund",
     "source":"Department of Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1 lakh crore corpus for post-harvest infrastructure — warehouses, cold storage, processing units. 3% interest subvention + credit guarantee. Apply through participating banks (PSBs, RRBs, NBFCs)."},
    {"id":"gs-x-23","domain":"Government Schemes","lang":"en","topic":"NRLM — National Rural Livelihoods Mission",
     "source":"Ministry of Rural Development","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Self-Help Group (SHG) formation for rural women. ₹10,000-15,000 revolving fund + ₹50,000-200,000 community investment fund. Bank linkages at 7% interest. 90 lakh+ SHGs covering 10 crore households."},
    {"id":"gs-x-24","domain":"Government Schemes","lang":"en","topic":"DAY-NULM — National Urban Livelihoods Mission",
     "source":"MoHUA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Urban poor: self-employment + skill training + shelter for homeless + support to street vendors + SHG formation. Components: SEP-I (individual loans ₹2 lakh), SEP-G (group ₹10 lakh), EST&P (training)."},
    {"id":"gs-x-25","domain":"Government Schemes","lang":"en","topic":"PMKVY — Pradhan Mantri Kaushal Vikas Yojana 4.0",
     "source":"Ministry of Skill Development","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free skill training at NSDC partner centres. Recognition of Prior Learning (RPL) for existing skilled workers. Placement assistance. Apply at pmkvyofficial.org. 1.4 crore+ trained till 2023."},
    {"id":"gs-x-26","domain":"Government Schemes","lang":"en","topic":"ASEEM — Skills and employment matching portal",
     "source":"NSDC","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"asfa.gov.in — AI-based platform matching skilled workers with employer needs. Particularly for blue-collar and skilled trades. Free registration. Integrated with PMKVY trained candidates."},
    {"id":"gs-x-27","domain":"Government Schemes","lang":"en","topic":"PM-AASHA — agriculture price support",
     "source":"Ministry of Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Three sub-schemes: Price Support (PSS) for pulses/oilseeds/copra, Price Deficiency Payment for oilseeds, Private Procurement & Stockist (pilot). Ensures MSP via direct procurement or shortfall compensation."},
    {"id":"gs-x-28","domain":"Government Schemes","lang":"en","topic":"Kisan Drone Promotion",
     "source":"Ministry of Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"50% / ₹5 lakh subsidy to FPOs for agriculture drones. Up to 75% for SC/ST, NE states, women. Custom Hiring Centres (CHC) can also purchase. Use cases: spraying pesticides, crop monitoring, soil analysis."},
    {"id":"gs-x-29","domain":"Government Schemes","lang":"en","topic":"PMFBY — claim filing process",
     "source":"PMFBY portal","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Loss intimation within 72 hours of crop damage via crop insurance app, CSC, bank, agriculture department, helpline 14447. Survey by joint team (agri-dept + insurance + revenue). Payment to bank account in stipulated time."},
    {"id":"gs-x-30","domain":"Government Schemes","lang":"en","topic":"MSP — Minimum Support Price",
     "source":"CACP · Department of Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Announced for 23 crops (Kharif + Rabi seasons). Procurement primarily through FCI (rice, wheat) and NAFED/state agencies (pulses, oilseeds). Sell at mandi or e-NAM. Price + bonus + freight assistance vary by state."},

    # ─── Education schemes (15) ───
    {"id":"gs-x-31","domain":"Government Schemes","lang":"en","topic":"PM-USHA — undergraduate higher education",
     "source":"Ministry of Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Centrally-sponsored scheme for state higher education institutions. Funding for infrastructure, faculty, equity initiatives. Replaces RUSA 2.0. State-level higher education councils coordinate."},
    {"id":"gs-x-32","domain":"Government Schemes","lang":"en","topic":"NSP — Pre-Matric Scholarships",
     "source":"Ministry of Social Justice","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Class 9-10 students from SC/ST/OBC/Minority/EBC families. Annual income limits: ₹2.5 lakh (SC/ST), ₹1 lakh (OBC), ₹1 lakh (Minority). Hostel + day-scholar rates differ. Apply via NSP portal."},
    {"id":"gs-x-33","domain":"Government Schemes","lang":"en","topic":"NSP — Post-Matric Scholarships",
     "source":"NSP","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Class 11+ studies including professional courses. SC/ST income limit ₹2.5 lakh; OBC ₹1.5 lakh; minorities ₹2 lakh. Covers tuition fees + maintenance allowance. Renewal annually with continuing pass marks."},
    {"id":"gs-x-34","domain":"Government Schemes","lang":"en","topic":"Inspire Scholarship — science",
     "source":"DST · online-inspire.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹80,000/year (₹60,000 scholarship + ₹20,000 mentorship) for top-1% of class 12 board students pursuing natural sciences. Continued through BSc/MSc with merit. Applications post-class 12 results."},
    {"id":"gs-x-35","domain":"Government Schemes","lang":"en","topic":"KVPY — Kishore Vaigyanik Protsahan Yojana",
     "source":"IISc Bangalore","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Note: KVPY merged into Inspire Scholarship from 2022. Earlier: fellowship for science research aspirants from class 11 to PhD. Selection via aptitude test + interview."},
    {"id":"gs-x-36","domain":"Government Schemes","lang":"en","topic":"National Means-cum-Merit Scholarship (NMMS)",
     "source":"Department of School Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹12,000/year for class 9-12 students from low-income families. Selection: state-level NMMS exam (MAT + SAT). Family income ≤ ₹3.5 lakh/year. Renewal subject to performance."},
    {"id":"gs-x-37","domain":"Government Schemes","lang":"en","topic":"Maulana Azad Education Foundation scholarships",
     "source":"MAEF · maef.nic.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Begum Hazrat Mahal Scholarship for minority girls (Class 9-12) — ₹5,000-6,000/year. Maulana Azad National Fellowship for MPhil/PhD discontinued from 2022 (controversial). Educational loan subsidy for higher studies abroad."},
    {"id":"gs-x-38","domain":"Government Schemes","lang":"en","topic":"AICTE Pragati & Saksham scholarships",
     "source":"AICTE","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pragati: girl students in AICTE-approved technical institutions — ₹50,000/year tuition + contingency. Saksham: differently-abled students — same benefits. Family income ≤ ₹8 lakh. 5,000 Pragati + 1,000 Saksham annually."},
    {"id":"gs-x-39","domain":"Government Schemes","lang":"en","topic":"Vidya Lakshmi Portal — education loans",
     "source":"vidyalakshmi.co.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Single portal for application to 38 banks for education loans. Up to ₹4 lakh — no collateral. ₹4-7.5 lakh — third-party guarantee. Above ₹7.5 lakh — collateral. Moratorium during course + 1 year."},
    {"id":"gs-x-40","domain":"Government Schemes","lang":"en","topic":"CSIS — Central Sector Interest Subsidy",
     "source":"Department of Higher Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Full interest subsidy during moratorium for education loans up to ₹10 lakh, for students from families with income < ₹4.5 lakh. Applies to loans for professional/technical courses in India. Apply via bank during loan processing."},
    {"id":"gs-x-41","domain":"Government Schemes","lang":"en","topic":"PM Vidyalaxmi (2024)",
     "source":"Ministry of Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Education loan scheme launched 2024. ₹10 lakh loan for students in 860 top quality higher education institutions. 3% interest subsidy during moratorium for income < ₹8 lakh families. Replaces / complements CSIS."},
    {"id":"gs-x-42","domain":"Government Schemes","lang":"en","topic":"PMRF — Prime Minister's Research Fellowship",
     "source":"pmrf.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Direct PhD fellowships at IITs, IISc, IISER, NIT for top BTech students. ₹70,000-80,000/month + research grant ₹2 lakh/year for 5 years. Lateral entry route also for MTech/MSc students."},
    {"id":"gs-x-43","domain":"Government Schemes","lang":"en","topic":"NCS — National Career Service portal",
     "source":"ncs.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free job-seeker registration + career counselling + apprenticeship listings. Online + 200+ Model Career Centres. Used by employment exchanges. Aadhaar-linked profile."},
    {"id":"gs-x-44","domain":"Government Schemes","lang":"en","topic":"Swayam — MOOCs platform",
     "source":"swayam.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free online courses by IITs, IIMs, IGNOU, NPTEL. Credit transfer to universities. Certification on completion + optional exam fee. Major topics: engineering, management, humanities, languages, school content."},
    {"id":"gs-x-45","domain":"Government Schemes","lang":"en","topic":"NIPUN Bharat — foundational literacy",
     "source":"Ministry of Education · NCERT","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Foundational Literacy and Numeracy for classes 1-3 by 2026-27 (NEP target). State-level FLN missions. Teacher training, learning material, parental engagement. Major school-system reform."},

    # ─── Housing & infrastructure (10) ───
    {"id":"gs-x-46","domain":"Government Schemes","lang":"en","topic":"PMAY-U — Pradhan Mantri Awas Yojana Urban",
     "source":"MoHUA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"4 verticals: In-Situ Slum Redevelopment, Credit Linked Subsidy Scheme (CLSS), Affordable Housing in Partnership, Beneficiary-Led Construction. EWS up to ₹3 lakh income; LIG ₹3-6 lakh; MIG-I ₹6-12 lakh; MIG-II ₹12-18 lakh."},
    {"id":"gs-x-47","domain":"Government Schemes","lang":"en","topic":"PMAY Rural Permanent List 2024",
     "source":"PMAY-G portal","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Beneficiary identification via 2018 SECC + Awaas+ survey. Rural BPL/houseless. ₹1.20 lakh plain area / ₹1.30 lakh hilly. Linked with NREGA (95 days unskilled labour) + SBM (toilet). Bank account credit in tranches."},
    {"id":"gs-x-48","domain":"Government Schemes","lang":"en","topic":"PM AwAS Plus 2.0",
     "source":"MoRD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Survey app for left-out households eligible for PMAY-G. Self-survey or surveyor-assisted. Income-criterion relaxed (raised from earlier ₹10,000/month to ₹15,000). Direct upload of evidence."},
    {"id":"gs-x-49","domain":"Government Schemes","lang":"en","topic":"PM Suryodaya / Surya Ghar — rooftop solar",
     "source":"Ministry of New & Renewable Energy","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Up to 300 units/month free via rooftop solar. Subsidy: ₹30,000 for 1 kW, ₹60,000 for 2 kW, ₹78,000 for 3 kW+. Apply on pmsuryaghar.gov.in. Net-metering with state DISCOM. Loan facility 6.75-8%."},
    {"id":"gs-x-50","domain":"Government Schemes","lang":"en","topic":"Saubhagya — household electrification",
     "source":"Ministry of Power","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Pradhan Mantri Sahaj Bijli Har Ghar Yojana — last-mile electricity connection. Free for SECC-listed poor; ₹500 EMI for others. India achieved 99.9% household coverage by 2019 (formal saturation declared)."},
    {"id":"gs-x-51","domain":"Government Schemes","lang":"en","topic":"Swachh Bharat — Individual Household Toilets",
     "source":"MoDWS · MoHUA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"SBM-Gramin: ₹12,000 per household (₹15,000 in hilly/desert) for IHHL toilet. SBM-Urban: ₹15,000 ULB share + ₹4,000 state share. Apply via Gram Panchayat / ULB. Geo-tagged photo before/after."},
    {"id":"gs-x-52","domain":"Government Schemes","lang":"en","topic":"Jal Jeevan Mission — Har Ghar Jal",
     "source":"Ministry of Jal Shakti","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Functional Household Tap Connection for every rural household by 2024 (target). Apply via Gram Panchayat. State-level water supply schemes. ~70% coverage achieved (2024); Northeast and tribal areas lagging."},
    {"id":"gs-x-53","domain":"Government Schemes","lang":"en","topic":"AMRUT 2.0 — urban infrastructure",
     "source":"MoHUA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Atal Mission for Rejuvenation and Urban Transformation. Universal water supply + sewerage to 4,800+ ULBs. Citizen-centric digital governance. AMRUT 2.0 (2021-26) emphasises water-positive cities and circular economy."},
    {"id":"gs-x-54","domain":"Government Schemes","lang":"en","topic":"Smart Cities Mission",
     "source":"MoHUA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"100 selected cities. Area-based development + Pan-city solutions. Integrated Command and Control Centres operational in many cities. Mixed implementation results; mission ended formally 2024."},
    {"id":"gs-x-55","domain":"Government Schemes","lang":"en","topic":"Affordable Rental Housing Complexes (ARHC)",
     "source":"MoHUA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Sub-scheme of PMAY-U. Repurposed government-funded vacant houses + concession to private/public entities to build new. Rents 30-50% below market. For urban migrants and EWS — particularly post-Covid relevance."},

    # ─── Women & child schemes (15) ───
    {"id":"gs-x-56","domain":"Government Schemes","lang":"en","topic":"Beti Bachao Beti Padhao (BBBP)",
     "source":"MWCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Multi-sectoral approach addressing declining child sex ratio + girl education. PCPNDT enforcement, awareness, school enrolment drives. Funds disbursed to districts. Awareness > direct cash transfer."},
    {"id":"gs-x-57","domain":"Government Schemes","lang":"en","topic":"Sukanya Samriddhi Yojana",
     "source":"Department of Posts","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Long-term saving for girl child < 10 years. Min ₹250 / year, max ₹1.5 lakh. Interest currently 8.2% (Q3 FY24-25), revised quarterly. Maturity at 21 years OR after age 18 (50% withdrawal allowed for higher education/marriage). EEE tax status."},
    {"id":"gs-x-58","domain":"Government Schemes","lang":"en","topic":"Mahila Samman Savings Certificate",
     "source":"Department of Posts (Budget 2023 launch)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"For women/girls — 2-year deposit at 7.5% interest. Maximum ₹2 lakh. Available till March 2025 (originally). Single, joint, or by guardian for minor girl. TDS applicable; PMJDY-linked easy KYC."},
    {"id":"gs-x-59","domain":"Government Schemes","lang":"en","topic":"Mukhyamantri Mahila Utkarsh Yojana — Gujarat",
     "source":"Gujarat WCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1 lakh interest-free loan to women's self-help groups for income-generating activities. Repay in 2 years. Aim to support 10 lakh women in 5 years. Apply through district WCD office."},
    {"id":"gs-x-60","domain":"Government Schemes","lang":"en","topic":"One Stop Centre (OSC) — Sakhi",
     "source":"MWCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"At least one OSC per district. Integrated support to women affected by violence — medical, legal, psychological, police, shelter (up to 5 days). 24×7. Reach via 181 women helpline."},
    {"id":"gs-x-61","domain":"Government Schemes","lang":"en","topic":"Mission Shakti — umbrella programme",
     "source":"MWCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Two sub-schemes: Sambal (safety + security — OSC, Mahila Police Volunteer, Beti Bachao) and Samarthya (empowerment — BBBP, Hub for Empowerment of Women, working women hostel). Active 2021-26."},
    {"id":"gs-x-62","domain":"Government Schemes","lang":"en","topic":"Working Women Hostel scheme",
     "source":"MWCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Subsidised hostels for working women + daycare for their children. NGO-operated with government grant. Income < ₹50,000 (metros) / ₹35,000 (other). Locate via Mission Shakti portal."},
    {"id":"gs-x-63","domain":"Government Schemes","lang":"en","topic":"PM CARES for Children",
     "source":"PMO","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Children who lost both parents to Covid or sole earner. Corpus of ₹10 lakh at age 18 (monthly stipend for higher ed first). Free schooling at KV/Navodaya/private (PMAY-list). PM-JAY health cover up to age 18. Apply via DM."},
    {"id":"gs-x-64","domain":"Government Schemes","lang":"en","topic":"ICDS — Integrated Child Development Services",
     "source":"MWCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Anganwadi-centric. Supplementary nutrition, pre-school education (3-6 yr), immunisation, health check, referral, health/nutrition education for mothers. 13 lakh+ centres. Backbone of ECCE in India."},
    {"id":"gs-x-65","domain":"Government Schemes","lang":"en","topic":"Saksham Anganwadi & Poshan 2.0",
     "source":"MWCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Anganwadi upgradation + integrated nutrition mission. Adolescent girls 14-18 added to coverage. Poshan Tracker app for real-time data. Includes Take-Home Ration, Hot Cooked Meal, Anaemia Mukt Bharat."},
    {"id":"gs-x-66","domain":"Government Schemes","lang":"en","topic":"Hub for Empowerment of Women",
     "source":"MWCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"State Hub + District Hub + Block Resource Centres + Village Hub. Information dissemination, training, convergence of women schemes. Help women access entitlements. Funded under Mission Shakti."},
    {"id":"gs-x-67","domain":"Government Schemes","lang":"en","topic":"Mahila E-Haat — online marketing",
     "source":"MWCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free online platform for women entrepreneurs/SHGs to sell products. Reduced offline transit costs. Direct customer connection. Currently being merged with mass-market e-commerce initiatives."},
    {"id":"gs-x-68","domain":"Government Schemes","lang":"en","topic":"Beti Bachao — UP scheme variants",
     "source":"UP Mukhyamantri Kanya Sumangala","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Up to ₹25,000 across 6 life stages: birth, 1-year vaccination, class 1, class 6, class 9, UG. Single girl in family with income < ₹3 LPA. Apply on mksy.up.gov.in."},
    {"id":"gs-x-69","domain":"Government Schemes","lang":"en","topic":"Pinjra Tod — collective grievance",
     "source":"DU students movement (informational)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Not a scheme but a women's collective fighting curfew, gender-discriminatory hostel rules in Delhi colleges. Spurred UGC SAKSHAM committee reform. UGC 2023 guidelines: gender-equal hostel rules."},
    {"id":"gs-x-70","domain":"Government Schemes","lang":"en","topic":"Anganwadi worker recruitment & rights",
     "source":"MWCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Honorarium-based (₹4,500-10,000/month, state-varying). Recent SC ruling: entitled to gratuity. Performance-based incentives. Often local women — selection by Gram Sabha. Major source of informal women employment in rural India."},

    # ─── State schemes — by state (50) ───
    {"id":"gs-x-71","domain":"Government Schemes","lang":"en","topic":"Karnataka Shakti — free women bus travel",
     "source":"Karnataka KSRTC","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free travel for women in non-premium KSRTC/BMTC buses across Karnataka. Shakti Smart Card or any Aadhaar/ID at conductor. ~₹4,000 crore annual outlay. Massive uptake — ~3 crore trips/day."},
    {"id":"gs-x-72","domain":"Government Schemes","lang":"en","topic":"Karnataka Anna Bhagya",
     "source":"Karnataka Food Department","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"10 kg rice/person/month free for BPL households (Anna Bhagya original was 5 kg add'l on top of NFSA). Direct Benefit Transfer in some districts due to rice procurement shortage."},
    {"id":"gs-x-73","domain":"Government Schemes","lang":"en","topic":"Karnataka Gruha Jyothi",
     "source":"Karnataka Energy Department","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Up to 200 free units/month for domestic consumers. Average of past year consumption + 10% as cap. Apply via Seva Sindhu portal. Major political-flagship scheme."},
    {"id":"gs-x-74","domain":"Government Schemes","lang":"en","topic":"Karnataka Yuva Nidhi",
     "source":"Karnataka Skill Development","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹3,000/month unemployment allowance to graduates, ₹1,500/month to diploma holders — for 2 years. Maximum age 25 (graduate)/22 (diploma) at time of registration. Online application on sevasindhu portal."},
    {"id":"gs-x-75","domain":"Government Schemes","lang":"en","topic":"Maharashtra Mukhyamantri Annapurna Yojana",
     "source":"Maharashtra Food, Civil Supplies","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"3 free LPG cylinders/year to ration card holders. Direct benefit transfer post-purchase. Particularly benefits women head-of-household. Linked with PMUY."},
    {"id":"gs-x-76","domain":"Government Schemes","lang":"en","topic":"Maharashtra Mukhyamantri Vayoshri Yojana",
     "source":"Maharashtra Social Justice","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹3,000/year aid for senior citizens (60+) for purchasing assistive devices (spectacles, walking sticks, hearing aids). Income < ₹2 lakh. Apply via Aaple Sarkar or district social welfare office."},
    {"id":"gs-x-77","domain":"Government Schemes","lang":"en","topic":"Maharashtra Atal Pension Yojana state add-on",
     "source":"Maharashtra Finance","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"State supplement to APY for low-income workers — partial contribution match in early years. Application via cooperative banks and post offices."},
    {"id":"gs-x-78","domain":"Government Schemes","lang":"en","topic":"Mukhyamantri Lakhpati Didi — Maharashtra/national",
     "source":"NRLM","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"NRLM-linked target: 3 crore SHG women earning ₹1 lakh/year. Skill training, credit, market linkages, technology — drone training under Drone Didi. Convergence with multiple schemes."},
    {"id":"gs-x-79","domain":"Government Schemes","lang":"en","topic":"Tamil Nadu Magalir Urimai Thittam",
     "source":"TN Social Welfare","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1,000/month to woman head of family (income < ₹2.5 lakh + landholding < 5 acres). 1.06 crore beneficiaries. Apply via Amma Mini Clinics or magalirurimai.tn.gov.in."},
    {"id":"gs-x-80","domain":"Government Schemes","lang":"en","topic":"Tamil Nadu Pudhumai Penn",
     "source":"TN Higher Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1,000/month to girls who completed Class 6-12 in government schools and pursue higher education (UG/diploma/ITI). Disbursed monthly during study. Apply on penkalvi.tn.gov.in."},
    {"id":"gs-x-81","domain":"Government Schemes","lang":"en","topic":"Tamil Nadu Naan Mudhalvan",
     "source":"TN Higher Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Skills-and-employment portal for college students — career counselling, internships, soft-skills training. Integration with industry partners. Login via Aadhaar."},
    {"id":"gs-x-82","domain":"Government Schemes","lang":"en","topic":"Tamil Nadu CMCHIS — health insurance",
     "source":"TN Health","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Chief Minister's Comprehensive Health Insurance Scheme. ₹5 lakh/family/year cashless treatment. Covers families with income < ₹1.2 lakh. Apply via taluk office or e-Sevai centre."},
    {"id":"gs-x-83","domain":"Government Schemes","lang":"en","topic":"Delhi Mukhyamantri Mahila Samman Yojana",
     "source":"Delhi Women & Child Development","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1,000/month to women 18+ holding Delhi voter ID. Income criteria + non-government employee status. Launched 2024. Online registration via Mahila Samman portal."},
    {"id":"gs-x-84","domain":"Government Schemes","lang":"en","topic":"Delhi Sanjeevani Mahila Samman",
     "source":"Delhi Health","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free OPD + treatment for senior citizens 60+ at empanelled hospitals + tests. Mohalla Clinic network for primary care free of cost. Recent expansions to specialised services."},
    {"id":"gs-x-85","domain":"Government Schemes","lang":"en","topic":"Delhi Doorstep Delivery of Services",
     "source":"Delhi e-Governance","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"100+ government services delivered at home — caste/income certificates, driving licence, marriage registration, vehicle papers. Call 1076 for appointment. ₹50 service charge."},

    {"id":"gs-x-86","domain":"Government Schemes","lang":"en","topic":"WB Kanyashree Prakalpa",
     "source":"WB Women, Child Development","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"K1: ₹1,000 annual scholarship for girls 13-18 in classes 8-12, unmarried, family income < ₹1.2 lakh. K2: ₹25,000 one-time at 18 if still unmarried. K3: PhD support. UNICEF-recognised model."},
    {"id":"gs-x-87","domain":"Government Schemes","lang":"en","topic":"WB Yuvashree",
     "source":"WB Labour Department","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1,500/month unemployment allowance to job seekers 18-45 registered with employment exchange. Maximum 1 year. Bank account credit. Replaced earlier Bekar Bhata."},
    {"id":"gs-x-88","domain":"Government Schemes","lang":"en","topic":"WB Krishak Bandhu",
     "source":"WB Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹10,000/year per cultivator family (₹5,000 each in 2 instalments). Death benefit ₹2 lakh for 18-60 year old cultivators. Universal — no income criteria. Direct bank transfer."},
    {"id":"gs-x-89","domain":"Government Schemes","lang":"en","topic":"WB Swasthya Sathi",
     "source":"WB Health","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Cashless treatment up to ₹5 lakh/family/year at empanelled hospitals. Universal coverage to all WB residents. Smart card to woman head of family. Apply via Duare Sarkar camps or online."},
    {"id":"gs-x-90","domain":"Government Schemes","lang":"en","topic":"WB Duare Sarkar",
     "source":"WB e-Governance","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Periodic camps in every gram panchayat / ward delivering 30+ services — scheme applications, certificates, ration card updates. No travel/agent needed. Major outreach mechanism."},

    {"id":"gs-x-91","domain":"Government Schemes","lang":"en","topic":"Andhra Pradesh YSR Cheyutha",
     "source":"AP Department of Women, Child, Disabled, Senior Citizens","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹18,750/year to BC/SC/ST/Minority women aged 45-60, for 4 years (₹75,000 total). Aimed at small enterprise support. Phase-wise selection. Apply via Volunteers / Grama Sachivalayam."},
    {"id":"gs-x-92","domain":"Government Schemes","lang":"en","topic":"AP YSR Sunna Vaddi (zero interest loan)",
     "source":"AP Rural Development","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Interest reimbursement to women SHGs on bank loans up to ₹3 lakh — effective 0% interest. Quarterly DBT. Major NRLM-converged scheme. Strong SHG ecosystem in AP."},
    {"id":"gs-x-93","domain":"Government Schemes","lang":"en","topic":"AP Amma Vodi",
     "source":"AP School Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹15,000/year to mothers/guardians sending children class 1-12 to school. Income < ₹10,000/month rural, ₹12,000 urban. Includes private schools. Direct credit to mother's account."},
    {"id":"gs-x-94","domain":"Government Schemes","lang":"en","topic":"AP YSR Aarogyasri 2.0",
     "source":"AP Aarogyasri Health Care Trust","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹25 lakh/family cashless treatment for 3,257 procedures. Universal coverage. Empanelled hospitals across AP, Telangana, Karnataka, Tamil Nadu. Aarogyasri card via Volunteers."},
    {"id":"gs-x-95","domain":"Government Schemes","lang":"en","topic":"AP Rythu Bharosa",
     "source":"AP Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹13,500/year per farmer family + tenant farmers (₹6,000 PM-KISAN + ₹7,500 state). Three instalments. Tenant farmers covered through Crop Cultivator Rights Cards."},

    {"id":"gs-x-96","domain":"Government Schemes","lang":"en","topic":"Telangana Rythu Bandhu",
     "source":"Telangana Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹10,000/acre/year to landowning farmers — ₹5,000 each in kharif and rabi. No ceiling on land. Cash-positive transfer for input costs. Some landless/tenant farmer concerns excluded."},
    {"id":"gs-x-97","domain":"Government Schemes","lang":"en","topic":"Telangana KCR Kit",
     "source":"Telangana Health","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"For pregnant women in government hospitals: kit with 16 items (baby clothes, oil, soap, mosquito net, etc.) + ₹13,000 (girl child) / ₹12,000 (boy) financial assistance in 3 instalments."},
    {"id":"gs-x-98","domain":"Government Schemes","lang":"en","topic":"Telangana Aasara Pension",
     "source":"Telangana Welfare","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹2,016/month: old age (57+), widows, single women (35+), disabled (40%+ disability), beedi workers, AIDS patients. ₹3,016/month for >80% disability. Apply via MeeSeva."},
    {"id":"gs-x-99","domain":"Government Schemes","lang":"en","topic":"Telangana Mission Bhagiratha",
     "source":"Telangana Rural Water Supply","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Piped drinking water to every household by 2018 (claimed achieved 100% — independently questioned). Source: Godavari + Krishna reservoirs. Universal coverage model studied nationally."},
    {"id":"gs-x-100","domain":"Government Schemes","lang":"en","topic":"Telangana 2BHK Housing Scheme",
     "source":"Telangana Housing","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free 2BHK house (560 sqft) to homeless poor — fully government-built. Backlog reduction ongoing. Different from PMAY in: free vs subsidised, completed construction vs cash transfer."},

    {"id":"gs-x-101","domain":"Government Schemes","lang":"en","topic":"Punjab Atta Dal scheme",
     "source":"Punjab Food, Civil Supplies","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Subsidised wheat (₹2/kg) + pulses (₹20/kg) for blue card holders (BPL). Monthly entitlement based on family size. Apply through e-PDS portal or panchayat secretary."},
    {"id":"gs-x-102","domain":"Government Schemes","lang":"en","topic":"Punjab Old Age Pension",
     "source":"Punjab Social Security","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1,500/month to 58+ men, 60+ women below income/landholding threshold. Apply via DC office or online. Recently expanded coverage."},
    {"id":"gs-x-103","domain":"Government Schemes","lang":"en","topic":"Punjab Ashirwad — daughter marriage assistance",
     "source":"Punjab Social Welfare","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹51,000 financial assistance to SC/Christian girls at marriage from low-income families. Application 6 months before marriage with eligibility documents to district welfare officer."},
    {"id":"gs-x-104","domain":"Government Schemes","lang":"en","topic":"Haryana Lado Lakshmi",
     "source":"Haryana WCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹2,100/month to women 18+ (announced 2024). Income criteria + state residence. Online application portal launched. Direct bank credit."},
    {"id":"gs-x-105","domain":"Government Schemes","lang":"en","topic":"Haryana Mukhyamantri Parivar Samman Nidhi",
     "source":"Haryana State","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹6,000/year to families with income < ₹1.8 lakh (3 monthly instalments). Restricted to specific categories: small farmers, agriculture labour, unorganised workers. Linked with PPP (Parivar Pehchan Patra)."},

    {"id":"gs-x-106","domain":"Government Schemes","lang":"en","topic":"Rajasthan Indira Gandhi Smartphone Yojana",
     "source":"Rajasthan IT","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free smartphone + internet connectivity to women head of family in BPL/Chiranjeevi families. Eligible: NFSA card holders. Distribution via camps. Aim: digital inclusion for women."},
    {"id":"gs-x-107","domain":"Government Schemes","lang":"en","topic":"Rajasthan Chiranjeevi Health Insurance",
     "source":"Rajasthan Health","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹25 lakh/family/year cashless treatment. Universal — free for NFSA / SECC beneficiaries; ₹850/year premium for others. Now restructured under current government — verify current status."},
    {"id":"gs-x-108","domain":"Government Schemes","lang":"en","topic":"Rajasthan Mukhyamantri Kanyadan Yojana",
     "source":"Rajasthan Social Welfare","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹31,000-51,000 marriage assistance to SC/ST/OBC/BPL girls. Education-linked top-ups: ₹21,000 (10th pass), ₹41,000 (12th pass), ₹51,000 (graduate). Apply 1 month before marriage."},
    {"id":"gs-x-109","domain":"Government Schemes","lang":"en","topic":"MP Mukhyamantri Ladli Behna Awas Yojana",
     "source":"MP Housing","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free/subsidised house to women beneficiaries of Ladli Behna scheme who are houseless. Linked with PMAY-G. Identification through Ladli Behna database. Direct payment to bank in tranches."},
    {"id":"gs-x-110","domain":"Government Schemes","lang":"en","topic":"MP Sambal Yojana 2.0",
     "source":"MP Labour","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"For unorganised workers — registration online or at gram panchayat. Benefits: ₹4,000 antenatal care + ₹12,000 maternity, ₹2 lakh accidental death, ₹4 lakh death (work-related), free education for children. Re-launched 2022."},

    {"id":"gs-x-111","domain":"Government Schemes","lang":"en","topic":"Bihar Mukhyamantri Kanya Utthan Yojana",
     "source":"Bihar WCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Total ₹54,100 across girl's life: birth ₹2,000, age 1 ₹1,000, age 2 ₹2,000, vaccination ₹2,000, uniform Class 1-2 ₹600, etc. Up to graduation. Apply at education portal."},
    {"id":"gs-x-112","domain":"Government Schemes","lang":"en","topic":"Bihar Mukhyamantri Cycle Yojana",
     "source":"Bihar Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹3,000 to girl students enrolled in class 9 (state government schools). Designed to reduce drop-out. Direct bank transfer to mother's account. One-time, conditional on enrolment continuation."},
    {"id":"gs-x-113","domain":"Government Schemes","lang":"en","topic":"Bihar Krishi Input Anudan",
     "source":"Bihar Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Per-acre subsidy for crop damage due to natural calamities. ₹6,800/hectare (rabi assistance), ₹8,500/hectare (kharif). Apply via DBT Agriculture Portal — needs land records + Aadhaar."},
    {"id":"gs-x-114","domain":"Government Schemes","lang":"en","topic":"Gujarat Mukhyamantri Yuva Swavalamban Yojana",
     "source":"Gujarat Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹2 lakh scholarship for students 12th pass + qualifying entrance for medical/engineering/diploma. Family income < ₹6 lakh. Includes ₹50,000 hostel + ₹10,000 books + ₹50,000 maintenance."},
    {"id":"gs-x-115","domain":"Government Schemes","lang":"en","topic":"Gujarat Vahli Dikri Yojana",
     "source":"Gujarat WCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹4,000 at class 1, ₹6,000 at class 9, ₹1 lakh at age 18 (for higher education or marriage). For first 2 girls in family with income < ₹2 lakh. Apply at Anganwadi or online."},

    {"id":"gs-x-116","domain":"Government Schemes","lang":"en","topic":"Odisha KALIA — farmer support",
     "source":"Odisha Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹4,000/season (₹8,000/year) cultivation support + ₹12,500 livelihood support to landless agricultural workers. Insurance + interest subsidy components. Apply via Common Service Centres."},
    {"id":"gs-x-117","domain":"Government Schemes","lang":"en","topic":"Odisha Mission Shakti Loans",
     "source":"Odisha Mission Shakti Department","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"WSHG credit at zero interest (state interest subvention on bank loans). Up to ₹5 lakh per group. India's largest exclusive department for WSHGs."},
    {"id":"gs-x-118","domain":"Government Schemes","lang":"en","topic":"Odisha Madhu Babu Pension Yojana",
     "source":"Odisha Social Welfare","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹500-700/month to elderly, widows, disabled. Income limit < ₹40,000/year. Apply at Block Office or online. Direct bank transfer monthly."},

    {"id":"gs-x-119","domain":"Government Schemes","lang":"en","topic":"Kerala Karunya Health Scheme",
     "source":"Kerala Health","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free treatment up to ₹3-5 lakh for major diseases (cancer, kidney, cardiac, brain) at empanelled hospitals. Income < ₹3 lakh. Apply at District Karunya Health Centres."},
    {"id":"gs-x-120","domain":"Government Schemes","lang":"en","topic":"Kerala Welfare Pensions (5 types)",
     "source":"Kerala Local Self-Government","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1,600/month: old age, widow, disability, agricultural worker, unmarried women 50+. Application via Akshaya Centres. Aadhaar + bank required."},
    {"id":"gs-x-121","domain":"Government Schemes","lang":"en","topic":"Kerala Aardram — primary care upgrade",
     "source":"Kerala Health","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Sub-Centres upgraded to Family Health Centres. Specialist OPD, NCD screening, evening OPD. Major primary-care reform. Distinct from Aam Aadmi Mohalla Clinics in approach."},

    {"id":"gs-x-122","domain":"Government Schemes","lang":"en","topic":"Assam Mukhya Mantri Mahila Udyamita Abhiyan",
     "source":"Assam Industries","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹35,000 seed funding to rural women entrepreneurs. Plus skill training, market linkages. Mission Mode. Selection through SHG federations + Block office."},
    {"id":"gs-x-123","domain":"Government Schemes","lang":"en","topic":"Assam Orunodoi 2.0",
     "source":"Assam Finance","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1,250/month to women heads of family in low-income households. ~20 lakh beneficiaries. Direct bank transfer. Eligibility: NFSA + income criteria."},
    {"id":"gs-x-124","domain":"Government Schemes","lang":"en","topic":"Assam Anundoram Borooah Award",
     "source":"Assam Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free laptop to all class 10 first division students from Assam SEBA Board. Distribution drive at district level. Aim: digital education access."},

    {"id":"gs-x-125","domain":"Government Schemes","lang":"en","topic":"Chhattisgarh Mahtari Vandan Yojana",
     "source":"Chhattisgarh WCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1,000/month (₹12,000/year) to married women 21+. Anganwadi-based registration. Aadhaar + bank account. Excludes income-tax payers + government employees."},
    {"id":"gs-x-126","domain":"Government Schemes","lang":"en","topic":"Chhattisgarh Krishak Unnati",
     "source":"Chhattisgarh Agriculture","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Direct top-up over MSP for paddy farmers — effectively ₹3,100/quintal vs ₹2,300 MSP. State-funded difference. Quintal cap per acre."},
    {"id":"gs-x-127","domain":"Government Schemes","lang":"en","topic":"Jharkhand Mukhyamantri Maiya Samman Yojana",
     "source":"Jharkhand WCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹1,000-2,500/month (announced ₹2,500 in 2024) to women 21-50 with family income < ₹8 lakh. Anganwadi registration. Aadhaar + bank required."},
    {"id":"gs-x-128","domain":"Government Schemes","lang":"en","topic":"Jharkhand Phulo-Jhano Ashirwad Abhiyan",
     "source":"Jharkhand JSLPS","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Rehabilitation of women involved in hadia (local liquor) selling — alternative livelihood support, training, credit. SHG-based mobilisation. Focus on tribal areas."},
    {"id":"gs-x-129","domain":"Government Schemes","lang":"en","topic":"Uttarakhand Mukhyamantri Vatsalya Yojana",
     "source":"Uttarakhand WCD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹3,000/month to children orphaned by Covid till age 21. Free education at government institutions. State-government implementation alongside PM CARES for Children."},
    {"id":"gs-x-130","domain":"Government Schemes","lang":"en","topic":"Himachal Pradesh Mukhya Mantri Sukh Ashray Yojana",
     "source":"HP Social Justice","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹4,000/month + free education up to PhD + ₹2 lakh marriage assistance for children in care institutions (orphans, abandoned, victims of trafficking). HP first state with such comprehensive package."},

    # ─── Insurance & social security (15) ───
    {"id":"gs-x-131","domain":"Government Schemes","lang":"en","topic":"PM-SYM — Shram Yogi Maandhan",
     "source":"MoLE · maandhan.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹3,000/month pension at 60 for unorganised workers (monthly income < ₹15,000). Contribution ₹55-200/month + matching government share. Apply via CSC. eShram card automatic enrolment in 2024."},
    {"id":"gs-x-132","domain":"Government Schemes","lang":"en","topic":"PM-KMY — Kisan Maan Dhan",
     "source":"MoA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹3,000/month pension at 60 for small/marginal farmers. Contribution ₹55-200/month + matching government. PM-KISAN beneficiaries can opt to deduct contribution from PM-KISAN credit."},
    {"id":"gs-x-133","domain":"Government Schemes","lang":"en","topic":"PM-LVM — Laghu Vyapari Maandhan",
     "source":"MoLE","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹3,000/month pension at 60 for small traders/shopkeepers with annual turnover < ₹1.5 cr. Similar contribution structure to PM-SYM. Apply via CSC. GSTIN-based eligibility verification."},
    {"id":"gs-x-134","domain":"Government Schemes","lang":"en","topic":"eShram Portal",
     "source":"MoLE · eshram.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Universal database of unorganised workers (UAN-issued). Eligible for accident insurance ₹2 lakh + scheme convergence. 30+ crore registrations. Registration via portal, CSC, or self via app — Aadhaar + bank required."},
    {"id":"gs-x-135","domain":"Government Schemes","lang":"en","topic":"PMJJBY — Pradhan Mantri Jeevan Jyoti Bima Yojana",
     "source":"DFS · jansuraksha.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Term life insurance ₹2 lakh at ₹436/year premium. Adults 18-50. Renewable till 55. Auto-debit from savings account. Covers death from any cause."},
    {"id":"gs-x-136","domain":"Government Schemes","lang":"en","topic":"PMSBY — Pradhan Mantri Suraksha Bima Yojana",
     "source":"DFS · jansuraksha.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Personal accident insurance ₹2 lakh (death or full disability), ₹1 lakh (partial) at ₹20/year premium. Adults 18-70. Auto-debit from bank account."},
    {"id":"gs-x-137","domain":"Government Schemes","lang":"en","topic":"APY — Atal Pension Yojana benefit chart",
     "source":"PFRDA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Guaranteed pension ₹1,000-5,000/month at 60. Contribution depends on entry age + chosen pension level. Joining at 18: ₹42-210/month for ₹1,000-5,000 pension. Income-tax payers excluded since Oct 2022."},
    {"id":"gs-x-138","domain":"Government Schemes","lang":"en","topic":"PM JAY — Aadhaar e-KYC requirement",
     "source":"NHA","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Aadhaar mandatory for PM-JAY card issuance. e-KYC at Common Service Centre, Empanelled hospital, or directly at pmjay.gov.in. Verifies identity at admission. Resolves earlier name-mismatch issues."},
    {"id":"gs-x-139","domain":"Government Schemes","lang":"en","topic":"Indira Gandhi National Old Age Pension Scheme",
     "source":"NSAP · MoRD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Central ₹200/month (60-79 yr) + ₹500 (80+); states top up to ₹1,000-2,500. BPL ration card eligibility. Apply via block office or online state portal. Direct bank credit."},
    {"id":"gs-x-140","domain":"Government Schemes","lang":"en","topic":"Indira Gandhi National Widow Pension Scheme",
     "source":"NSAP","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Central ₹300/month for widows 40-79 from BPL families. States usually add ₹700-2,000. Apply at block development office with widow certificate + bank + Aadhaar."},
    {"id":"gs-x-141","domain":"Government Schemes","lang":"en","topic":"IGNDPS — Disability Pension",
     "source":"NSAP","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Central ₹300/month for severely disabled (80%+) 18-79 from BPL. States top up. Disability certificate from Government Medical Board required. UDID (Unique Disability ID) eases process."},
    {"id":"gs-x-142","domain":"Government Schemes","lang":"en","topic":"PMVVY — Pradhan Mantri Vaya Vandana Yojana (closed)",
     "source":"LIC","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Closed to new subscribers from 2023. Earlier: guaranteed pension scheme for 60+. ₹1.5 lakh - ₹15 lakh investment for 10-year monthly pension. Existing subscribers continue."},
    {"id":"gs-x-143","domain":"Government Schemes","lang":"en","topic":"NPS — National Pension System",
     "source":"PFRDA · npscra.nsdl.co.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Market-linked retirement pension for any citizen 18-70. Tier-I (mandatory for tax benefits) + Tier-II (voluntary, withdrawable). 60% withdrawal lump-sum at 60 + 40% annuity. Tax: 80CCD(1B) ₹50,000 + 80C ₹1.5 lakh."},
    {"id":"gs-x-144","domain":"Government Schemes","lang":"en","topic":"NPS Vatsalya — child NPS account",
     "source":"PFRDA (launched 2024)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"NPS account for minor children operated by guardian. Converts to regular NPS at 18. Same investment options + tax benefits accrue. Long compounding period — significant retirement corpus potential."},
    {"id":"gs-x-145","domain":"Government Schemes","lang":"en","topic":"UPS — Unified Pension Scheme",
     "source":"Ministry of Finance (notified 2024)","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"For central government employees joining 1 April 2025 onward. Guaranteed 50% of last drawn salary as pension (after 25 years) + family pension + minimum ₹10,000. Hybrid between OPS and NPS."},

    # ─── Misc schemes (25) ───
    {"id":"gs-x-146","domain":"Government Schemes","lang":"en","topic":"DigiLocker",
     "source":"MeitY · digilocker.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Secure cloud storage for government-issued documents. Aadhaar-linked. Issued documents (driving licence, vehicle RC, certificates) digitally verifiable + legally equivalent. Integrated with multiple departments."},
    {"id":"gs-x-147","domain":"Government Schemes","lang":"en","topic":"UMANG App — multi-service",
     "source":"MeitY","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Single app for 2,000+ government services — PAN, EPF, IRCTC, gas booking, scholarship etc. 13 Indian languages. Aadhaar/mobile based login. Major e-governance access point."},
    {"id":"gs-x-148","domain":"Government Schemes","lang":"en","topic":"ABHA — Ayushman Bharat Health Account",
     "source":"NHA · abdm.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free 14-digit unique health ID. Records lab reports, prescriptions, hospital discharge summaries digitally — patient-controlled access. Generates via Aadhaar/mobile. Healthcare providers integrate progressively."},
    {"id":"gs-x-149","domain":"Government Schemes","lang":"en","topic":"PM Garib Kalyan Anna Yojana (PMGKAY)",
     "source":"MoCAFPD","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"5 kg free foodgrains per person/month to NFSA beneficiaries (over and above regular allocation). Extended for 5 years from January 2024. Distribution via fair price shops."},
    {"id":"gs-x-150","domain":"Government Schemes","lang":"en","topic":"NRDWP — National Rural Drinking Water",
     "source":"Department of Drinking Water","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Funds rural drinking water schemes via state agencies. Mostly subsumed in Jal Jeevan Mission. Pre-2019 schemes continue separately. Per-capita norms: 55 lpcd functional household tap."},
    {"id":"gs-x-151","domain":"Government Schemes","lang":"en","topic":"Smart India Hackathon",
     "source":"AICTE · MoE","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Annual nationwide hackathon for student problem-solving on ministry-floated problem statements. ₹1 lakh prize per winning team in software/hardware categories. Year-round 'Toycathon', 'AgriHackathon' variants."},
    {"id":"gs-x-152","domain":"Government Schemes","lang":"en","topic":"PM Daksh — skill training for vulnerable",
     "source":"Ministry of Social Justice","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free skill training for SC/OBC/EBC/Safai Karamcharis. Short-term + Upskilling + Long-term. Stipend during training. Placement support. Apply via pmdaksh.dosje.gov.in or NSFDC office."},
    {"id":"gs-x-153","domain":"Government Schemes","lang":"en","topic":"Stand-Up India",
     "source":"DFS · standupmitra.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹10 lakh - ₹1 crore composite loan to SC/ST/Woman entrepreneur for greenfield enterprise (manufacturing/services/trading). Margin 15% (max). Apply via any branch — every Scheduled Commercial Bank required to give at least 1 loan."},
    {"id":"gs-x-154","domain":"Government Schemes","lang":"en","topic":"Mudra Yojana — three categories",
     "source":"PMMY","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Shishu (up to ₹50,000), Kishore (₹50,000-5 lakh), Tarun (₹5-10 lakh). New Tarun Plus introduced 2024 (up to ₹20 lakh for Tarun graduates). Collateral-free; for non-corporate non-farm small enterprises."},
    {"id":"gs-x-155","domain":"Government Schemes","lang":"en","topic":"Startup India Seed Fund",
     "source":"DPIIT","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Up to ₹20 lakh grant (proof of concept) + ₹50 lakh debt for early-stage startups. Through 200+ incubators. Eligibility: DPIIT-recognised startup < 2 yr old. Apply via incubator."},

    {"id":"gs-x-156","domain":"Government Schemes","lang":"en","topic":"PMEGP — Prime Minister Employment Generation",
     "source":"KVIC","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Project up to ₹50 lakh (manufacturing) / ₹20 lakh (services). Margin money subsidy 15-35% (rural/urban + general/special category). Apply at KVIC, KVIB, DIC, banks via kviconline.gov.in."},
    {"id":"gs-x-157","domain":"Government Schemes","lang":"en","topic":"Coir Vikas Yojana",
     "source":"Coir Board","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Skill training + machinery subsidy for coir industry workers/units. Focus on Kerala, TN, Karnataka, AP, Odisha. Quality improvement + export promotion. Apply via Coir Board offices."},
    {"id":"gs-x-158","domain":"Government Schemes","lang":"en","topic":"FAME-II — Electric Vehicle Subsidy",
     "source":"Ministry of Heavy Industries","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Subsidy on electric 2W, 3W, 4W, e-buses. EV portal listings show on-road price after subsidy. PM E-Drive (successor 2024-) for next phase. State EV policies add further subsidies."},
    {"id":"gs-x-159","domain":"Government Schemes","lang":"en","topic":"GeM — Government e-Marketplace",
     "source":"DGS&D · gem.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Public procurement online portal. Sellers (especially MSMEs, women-owned, startups) get direct access to government orders. EMD waiver for startups + women. Major opportunity for small businesses."},
    {"id":"gs-x-160","domain":"Government Schemes","lang":"en","topic":"TReDS — Trade Receivables Discounting",
     "source":"RBI · RXIL, M1xchange, A.TReDS platforms","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Online platform for MSMEs to discount invoices owed by large corporates. Faster cash flow. Big corporates with turnover >₹500 cr mandated to onboard since 2018."},

    {"id":"gs-x-161","domain":"Government Schemes","lang":"en","topic":"AMIM — Asha + ANM Mobile App",
     "source":"MoHFW","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Mobile app for ASHA, ANM workers — beneficiary tracking, service delivery, indent management. Reduces paperwork. Performance-linked incentives processed digitally."},
    {"id":"gs-x-162","domain":"Government Schemes","lang":"en","topic":"PM Shri Schools",
     "source":"Ministry of Education","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"14,500+ schools upgraded as model NEP-aligned schools. Focus: experiential learning, art-integrated curriculum, modern infrastructure, multilingual instruction. State government schools selected via merit."},
    {"id":"gs-x-163","domain":"Government Schemes","lang":"en","topic":"Eklavya Model Residential Schools (EMRS)",
     "source":"Ministry of Tribal Affairs","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Free residential schools for ST students from class 6-12. CBSE curriculum, sports infrastructure, computer labs. Selection via class 5 entrance exam. Target: 740 schools by 2026."},
    {"id":"gs-x-164","domain":"Government Schemes","lang":"en","topic":"National Apprenticeship Promotion Scheme",
     "source":"DGT","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Stipend ₹5,000-8,000/month for apprenticeships. Establishments with 30+ workers required to engage apprentices (2.5-15%). Online via NAPS portal. Linked with PM Internship Scheme 2024."},
    {"id":"gs-x-165","domain":"Government Schemes","lang":"en","topic":"PM Internship Scheme 2024",
     "source":"Ministry of Corporate Affairs","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"1 crore internships over 5 years at top 500 companies. ₹5,000/month + ₹6,000 one-time grant. Eligibility: 21-24 yr, not in full-time job/education. Apply via pminternship.mca.gov.in."},

    {"id":"gs-x-166","domain":"Government Schemes","lang":"en","topic":"Pension portal — Bhavishya",
     "source":"DoPPW · bhavishya.nic.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"End-to-end pension processing for retired central government employees. Initiates 18 months before retirement. Online forms, status tracking. Reduced pension delay significantly."},
    {"id":"gs-x-167","domain":"Government Schemes","lang":"en","topic":"Jeevan Pramaan — digital life certificate",
     "source":"jeevanpramaan.gov.in","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Aadhaar biometric-based annual life certificate for pensioners. Submit via app, CSC, bank branch, post office. From Nov 2024, face authentication enabled — no biometric device needed."},
    {"id":"gs-x-168","domain":"Government Schemes","lang":"en","topic":"NIC eGovernance Services",
     "source":"National Informatics Centre","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Most state/central government portals built/hosted by NIC — vahan.parivahan.gov.in (vehicles), parivahan (DL), GST, e-District, e-Hospital. Common backend = consistent UX."},
    {"id":"gs-x-169","domain":"Government Schemes","lang":"en","topic":"e-District services",
     "source":"State e-Governance","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"Online application for: caste certificate, income certificate, domicile, birth/death certificate, EWS certificate. Required for many scheme applications. State-wise portals (e.g., UP — eDistrict, Karnataka — Seva Sindhu)."},
    {"id":"gs-x-170","domain":"Government Schemes","lang":"en","topic":"PM-DevINE — North-East Initiative",
     "source":"MDoNER","lastVerifiedOn":"2025-10-15","verifiedBy":"human",
     "text":"₹6,600 crore for North-East infrastructure, livelihood, social development 2022-26. State-specific projects. Application through state government. Complements North East Special Infrastructure Development Scheme."},

